	/* DNEW Style*/
    .tooltip-container::after {
        content: attr(data-tooltip);
        position: absolute;
        bottom: 150%;
        left: 50%;
        transform: translateX(-50%);
        background-color: #1a1a1a;
        color: #fff;
        padding: 5px 10px;
        border-radius: 4px;
        font-size: 0.9em;
        white-space: normal; width: max-content; /* nowrap -> normal */
        z-index: 10;
        visibility: hidden;
        opacity: 0;
        transition: opacity 0.2s ease-in-out, visibility 0.2s ease-in-out;
        pointer-events: none;
        max-width: 300px; /* 80vw -> 500px */
        left: auto;
        right: 0;
        transform: translateX(0);
    }
    @media (min-width: 480px) {
        .tooltip-container::after {
            left: 50%;
            right: auto;
            transform: translateX(-50%);
        }
    }
    .tooltip-container:hover::after {
        visibility: visible;
        opacity: 1;
    }
