}
#map-query-infobox ul {
    list-style: none;
    padding: 0;
    margin: 0 0 15px 0;
    font-size: 0.9em;
}
#map-query-infobox ul li {
    display: flex;
    justify-content: space-between;
    padding: 4px 0;
}
#map-query-infobox .label {
    color: #b0b0b0;
    margin-right: 10px;
}
#map-query-infobox .value {
    font-weight: bold;
}
#map-query-infobox .info-actions {
    display: flex;
    gap: 10px;
}
.map-query-marker {
    position: absolute;
    transform: translate(-50%, -50%) scale(var(--map-marker-scale, 1));
    z-index: 15;
    pointer-events: none;
    display: flex;
    justify-content: center;
    align-items: center;
    width: 40px;
    height: 40px;
}
.map-query-marker::before {
    content: '';
    display: block;
    width: 10px;
    height: 10px;
    background-color: #ffd700;
    border: 1px solid #fff;
    border-radius: 50%;
    box-shadow: 0 0 5px rgba(0,0,0,0.7);
}
.map-query-marker::after {
    content: '';
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
    border: 2px solid #ffd700;
    border-radius: 50%;
    animation: query-pulse-after 1.5s infinite;
}
.map-query-marker.high-z-marker {
    z-index: 1801;
}
#map-query-infobox.high-z-infobox {
    z-index: 1802;
}
@keyframes query-pulse-after {
    0% {
        width: 40%;
        height: 40%;
        opacity: 0.7;
    }
    100% {
        width: 100%;
        height: 100%;
        opacity: 0;
    }
}

</style>
