<style> /* Dành cho Túi Đồ */
#inventory-viewer-overlay { z-index: 900; }
#view-inventory-btn { font-size: 0.8em; padding: 2px 8px; background: none; border: 1px solid var(--primary-color); color: var(--text-primary); border-radius: 4px; cursor: pointer; transition: all 0.2s; }
#view-inventory-btn:hover { background-color: var(--hover-color); color: #1a1a1a; }

/* Header của modal: chứa thanh tìm kiếm và các nút hành động */
#inventory-viewer-header { display: flex; gap: 10px; margin-bottom: 15px; align-items: center; flex-shrink: 0; }
#inventory-search-input { flex-grow: 1; }
#inventory-initial-actions, #inventory-selection-controls { display: flex; gap: 10px; margin-right: 40px; }

#inventory-viewer-main-cats, #inventory-viewer-sub-cats { display: flex; flex-wrap: wrap; gap: 10px; margin-bottom: 15px; flex-shrink: 0; }
.inv-cat-btn { padding: 5px 15px; background: rgba(255,255,255,0.05); border: 1px solid var(--separator-color); border-radius: 15px; cursor: pointer; transition: all 0.2s; color: var(--text-primary); font-size: 0.8em; }
.inv-cat-btn:hover { border-color: var(--hover-color); }
.inv-cat-btn.active { background-color: var(--primary-color); color: #1a1a1a; font-weight: bold; }
#inventory-viewer-sub-cats .inv-cat-btn { font-size: 0.8em; padding: 4px 12px; }

#inventory-viewer-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(120px, 1fr)); gap: 15px; padding: 10px; grid-auto-rows: min-content; }

.inventory-viewer-slot { min-height: 120px; background: rgba(0,0,0,0.2); border: 1px solid var(--separator-color); border-radius: 4px; position: relative; display: flex; flex-direction: column; justify-content: center; align-items: center; padding: 8px; cursor: pointer; transition: all 0.2s; overflow: hidden; }
.inventory-viewer-slot:hover { border-color: var(--accent-color); background: rgba(130, 216, 247, 0.1); }

.inventory-viewer-slot .inventory-slot-icon { font-size: 2.2em; color: var(--primary-color); margin-bottom: 8px; }

.inventory-viewer-slot .inventory-slot-name { font-size: 0.65em; font-weight: bold; color: var(--text-primary); text-align: center; line-height: 1.3; display: -webkit-box; -webkit-line-clamp: 2; -webkit-box-orient: vertical; overflow: hidden; text-overflow: ellipsis; margin-top: 5px; }

.inventory-viewer-slot .item-value { font-size: 0.8em; color: #FFD700; margin-top: auto; padding-top: 4px; }
.inventory-viewer-slot .inventory-slot-quantity { position: absolute; bottom: 4px; right: 6px; font-size: 0.9em; color: var(--accent-color); background: rgba(0,0,0,0.6); padding: 1px 5px; border-radius: 4px; }

#inventory-viewer-overlay[class*="selection-mode-"] .inventory-viewer-slot { border-style: dashed; border-width: 2px; }
#inventory-viewer-overlay.selection-mode-copy .inventory-viewer-slot.selected { border-style: solid; border-color: #66bb6a; box-shadow: 0 0 10px rgba(102, 187, 106, 0.5); }
#inventory-viewer-overlay.selection-mode-delete .inventory-viewer-slot.selected { border-style: solid; border-color: #e57373; box-shadow: 0 0 10px rgba(229, 115, 115, 0.5); }

.delete-quantity-input-container { display: none; position: absolute; top: 2px; left: 2px; background: rgba(0,0,0,0.8); padding: 2px; border-radius: 4px; border: 1px solid #ffcc80; }
.delete-quantity-input { width: 50px; background-color: transparent; border: none; color: #ffd700; text-align: center; font-size: 0.9em; font-weight: bold; }
/* Ẩn nút tăng giảm mặc định */
.delete-quantity-input::-webkit-outer-spin-button, .delete-quantity-input::-webkit-inner-spin-button { -webkit-appearance: none; margin: 0; }
.delete-quantity-input[type=number] { -moz-appearance: textfield; }

#inventory-viewer-overlay.selection-mode-delete .inventory-viewer-slot.selected .delete-quantity-input-container { display: block; }
</style>
<style> /* Style cho khung avatar */
#online-avatar-picker-overlay { z-index: 1700; }
#avatar-picker-grid {
    display: grid;
    grid-template-columns: repeat(auto-fill, minmax(130px, 1fr));
    gap: 10px;
    grid-auto-rows: min-content;
    flex-grow: 1;
    overflow-y: auto;
    max-height: unset;
    padding: 15px;
    background: rgba(0,0,0,0.2);
    border-radius: 5px;
}

.avatar-thumbnail {
    position: relative;
    aspect-ratio: 2/3;
    border: 2px solid var(--separator-color);
    border-radius: 5px;
    cursor: pointer;
    overflow: hidden;
    transition: all 0.2s ease-in-out;
}

.avatar-thumbnail img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    transition: transform 0.2s ease;
}

.avatar-thumbnail:hover img {
    transform: scale(1.1);
}

.avatar-thumbnail.selected {
    border-color: var(--accent-color);
    box-shadow: 0 0 15px rgba(130, 216, 247, 0.6);
}

.avatar-actions {
    position: absolute;
    bottom: 8px;
    left: 50%;
    transform: translateX(-50%);
    display: flex;
    gap: 10px;
}

.avatar-actions button {
    background: rgba(0, 0, 0, 0.7);
    color: white;
    border: none;
    border-radius: 50%;
    width: 40px;
    height: 40px;
    font-size: 1em;
    cursor: pointer;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.2s ease;
}

.avatar-actions button:hover {
    background: var(--hover-color);
}

.avatar-in-use-tag {
    position: absolute;
    top: 5px;
    left: 5px;
    background-color: rgba(0, 0, 0, 0.7);
    color: white;
    font-size: 0.75em;
    padding: 3px 7px;
    border-radius: 4px
    text-shadow: 1px 1px 2px rgba(0, 0, 0, 0.8);
    pointer-events: none;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    max-width: calc(100% - 10px);
}

@media (max-width: 768px) {
    #avatar-picker-grid {
        /* Giảm kích thước tối thiểu của ảnh xuống 100px */
        grid-template-columns: repeat(auto-fill, minmax(100px, 1fr));

        /* Giảm khoảng cách giữa các ảnh để tiết kiệm không gian */
        gap: 10px;
        padding: 10px;
    }

    .avatar-actions button {
        /* Làm cho các nút "Xem/Chọn" nhỏ hơn một chút trên di động */
        width: 32px;
        height: 32px;
        font-size: 0.9em;
    }
}

/* Tối ưu hóa thêm cho màn hình điện thoại rất nhỏ (dưới 480px) */
@media (max-width: 480px) {
     #avatar-picker-grid {
        /* Giảm kích thước tối thiểu xuống nữa */
        grid-template-columns: repeat(auto-fill, minmax(90px, 1fr));
    }
}
</style>
</head>
