<div id="avatar-preview-overlay" class="overlay" style="z-index: 1700; background-color: rgba(0,0,0,0.85); backdrop-filter: blur(5px);">
    <button class="modal-close-btn" style="position: fixed; top: 20px; right: 20px;">&times;</button>
    <img id="avatar-preview-img" style="max-width: 90%; max-height: 90%; object-fit: contain; box-shadow: 0 0 30px rgba(255,255,255,0.3);">
</div>
<script>
    document.addEventListener('DOMContentLoaded', () => {
        window.crypto = window.crypto || {};
        window.crypto.randomUUID = () => {
            return Math.random().toString(36).substring(2, 7);
        };
        const playerName = "Người Chơi";
        const GAME_VERSION = "4.16";
        async function migrateSaveData(archiveData) {
            let data = archiveData.data;
            let changesMade = false;
            let originalVersion = parseFloat(data.version || "1.0");

            if (originalVersion < 3.0) {
                const migrateV3State = (stateObject) => {
                    let stateChanged = false;
                    if (stateObject && stateObject['0']) {
                        Object.values(stateObject['0']).forEach(charRow => {
                            if (charRow['14']) {
                                try {
                                    let staticData = JSON.parse(charRow['14']);
                                    if (staticData.race && !staticData.race.desc && staticData.race.name) {
                                        const raceConfig = CREATION_CONFIG.RACES[staticData.race.name];
                                        staticData.race.desc = raceConfig ? raceConfig.desc : 'Một Chủng Tộc Độc Đáo.';
                                        charRow['14'] = JSON.stringify(staticData);
                                        stateChanged = true;
                                    }
                                } catch(e) {}
                            }

                            if (charRow['16'] && charRow['16'].split('|').length === 5) {
                                const parts = charRow['16'].split('|');
                                const [action, attire, position, figure, appearance] = parts.map(p => p.trim());

                                charRow['16'] = `${action} | ${position}`;

                                charRow['26'] = `${appearance}, ${figure}`;

                                charRow['27'] = JSON.stringify([
                                    [attire || "Trang Phục Mặc Định", attire || "Một Bộ Trang Phục Phù Hợp Với Thân Phận", 1, "Bộ Đồ"]
                                ]);

                                stateChanged = true;
                            }
                        });
                    }

                    if (stateObject && stateObject['8']) {
                        Object.values(stateObject['8']).forEach(skill => {
                            if (skill['9'] && typeof skill['9'] === 'string') {
                                try {
                                    const effects = JSON.parse(skill['9']);
                                    if (Array.isArray(effects) && effects.length > 0 && effects[0] && (effects[0].type || effects[0]['0'])) {
                                        const isAlreadyNewFormat = effects[0].type && effects[0].desc;
                                        if (isAlreadyNewFormat) return;

