        async function cacheAndSetVideoBackground(videoElement, videoUrl) {
            const cacheKey = `video_cache_${videoUrl}`;
            try {
                const cachedVideo = await db.asset_cache.get(cacheKey);
                if (cachedVideo && cachedVideo.data instanceof Blob) {
                    const localUrl = URL.createObjectURL(cachedVideo.data);
                    videoElement.src = localUrl;
                    console.log('Nền trang khởi động đã được tải từ bộ nhớ đệm cục bộ.');
                    return;
                }
                console.log('Đang tải xuống và lưu vào bộ nhớ đệm nền trang khởi động từ mạng...');
                const response = await fetch(videoUrl);
                if (!response.ok) {
                    throw new Error(`Yêu cầu mạng thất bại: ${response.statusText}`);
                }
                const videoBlob = await response.blob();
                await db.asset_cache.put({ key: cacheKey, data: videoBlob });
                console.log('Nền trang khởi động đã được lưu thành công vào cơ sở dữ liệu cục bộ.');
                const localUrl = URL.createObjectURL(videoBlob);
                videoElement.src = localUrl;

            } catch (error) {
                console.error('Tải hoặc lưu vào bộ nhớ đệm nền trang khởi động thất bại:', error);
                videoElement.src = videoUrl;
            }
        }
