        function recordMapHistory() {
            if (typeof currentState === 'undefined' || !currentState) return;

            const latestHistoryState = mapHistoryIndex > -1 ? mapEditHistory[mapHistoryIndex] : null;
            if (latestHistoryState && JSON.stringify(currentLocationsData) === JSON.stringify(latestHistoryState)) {
                return;
            }

            currentState.locations = JSON.parse(JSON.stringify(currentLocationsData));

            if (mapHistoryIndex < mapEditHistory.length - 1) {
                mapEditHistory = mapEditHistory.slice(0, mapHistoryIndex + 1);
            }
            mapEditHistory.push(JSON.parse(JSON.stringify(currentLocationsData)));
            mapHistoryIndex = mapEditHistory.length - 1;
            updateUndoRedoButtons();
        }

