        function sanitizeHTML(htmlString) {
            const allowedTags = ['details', 'summary', 'div', 'p', 'span', 'strong', 'em', 'i', 'b', 'u', 's', 'br', 'hr', 'h4', 'ul', 'ol', 'li', 'pre', 'code', 'blockquote'];
            const tagRegex = new RegExp(`</?(?!(${allowedTags.join('|')}))\\w+\\b[^>]*>`, 'gi');

            let sanitized = String(htmlString).replace(tagRegex, '');
            sanitized = sanitized.replace(/<script\b[^>]*>([\s\S]*?)<\/script>/gi, '');
            sanitized = sanitized.replace(/\s(on\w+)=["'][^"']*["']/gi, '');
            sanitized = sanitized.replace(/\s(on\w+)=["'][^"']*["']/gi, '');
            return sanitized;
        }

        function enforceRenderLimit() {
            const limit = regexConfig.renderLimit || 20;
            const topLevelMessages = Array.from(mainContentArea.children).filter(el =>
                el.classList.contains('log-entry') ||
                el.classList.contains('summary-logs-container') ||
                el.classList.contains('hidden-logs-container')
            );

            if (topLevelMessages.length > limit) {
                const toRemoveCount = topLevelMessages.length - limit;
                for (let i = 0; i < toRemoveCount; i++) {
                    if (topLevelMessages[i]) {
                        topLevelMessages[i].remove();
                    }
                }
            }
        }

        function getCleanTextFromLogContent(rawContent) {
            if (!rawContent) return '';

            const yTextMatch = rawContent.match(/<y_text>([\s\S]*?)<\/y_text>/);
            let contentToProcess;

            if (yTextMatch && yTextMatch[1]) {
                contentToProcess = yTextMatch[1].trim();
            } else {
                contentToProcess = rawContent;
                contentToProcess = contentToProcess.replace(/<y_actions>[\s\S]*?<\/y_actions>/gi, '');
                contentToProcess = contentToProcess.replace(/<branches>[\s\S]*?<\/branches>/gi, '');
                contentToProcess = contentToProcess.replace(/<(?:think|thinking|tablethink)>[\s\S]*?<\/(?:think|thinking|tablethink)>/gi, '');
                contentToProcess = contentToProcess.replace(/```(?:html)?\s*\n?([\s\S]*?)```/g, '$1');
            }

            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = contentToProcess;

            tempDiv.querySelectorAll('details').forEach(details => {
                const summary = details.querySelector('summary');
                if (summary) {
                    summary.textContent = `[${summary.textContent}] `;
                }
            });

            return (tempDiv.textContent || tempDiv.innerText || '').trim();
        }

        function createLogEntryElement(logData, type) {
            let originalContent = (typeof logData === 'string') ? logData : (logData.content || '');

            let displayContent = originalContent;

            const tableEditRegex = /<y_actions>[\s\S]*?<\/y_actions>/g;

            displayContent = displayContent.replace(/<(?:think|thinking|Think|Thinking|tableThink)>[\s\S]*?<\/(?:think|thinking|Think|Thinking|tableThink)>/gi, (match) => {
                if (regexConfig.showThinkingProcess) {
                    const cleanThinkingContent = match.replace(/<(.*)>/g, '$1');
                    const innerContent = cleanThinkingContent.replace(/<\/?(?:think|thinking|Think|Thinking|tableThink)>/gi, '');
                    const escapedContent = innerContent.replace(/</g, '&lt;').replace(/>/g, '&gt;');
                    return `
                        <details>
                            <summary>Quá trình suy nghĩ của AI...</summary>
                            <pre style="white-space: pre-wrap; word-wrap: break-word; font-size: 0.85em; opacity: 0.7;">${escapedContent}</pre>
                        </details>
                    `;
                }
                return '';
            });

            displayContent = displayContent.replace(/<y_actions>[\s\S]*?<\/y_actions>/g, '');
            displayContent = displayContent.replace(/<branches>[\s\S]*?<\/branches>/g, '');

            displayContent = processTextWithRules(displayContent, PLACEMENT_MAP.AI_OUTPUT, 'regular');

            displayContent = displayContent.replace(/(\n\s*){3,}/g, '\n\n').trim();


            const isSummary = (typeof logData !== 'string' && (originalContent.startsWith('[Chương Quá Khứ:') || originalContent.includes('<h4>Vận Mệnh Khởi Đầu, Tinh Tú Vang Vọng</h4>')));
            const logEntry = document.createElement('div');
            logEntry.classList.add('log-entry', type);
            if (isSummary) {
                logEntry.classList.add('summary');
            }
            const id = (typeof logData === 'string') ? null : logData.id;
            if (id) {
                logEntry.dataset.logId = id;
            }

            const htmlBlockRegex = /```(?:html)?\s*\n?([\s\S]*?)```/g;
            if (htmlBlockRegex.test(displayContent)) {
                let lastIndex = 0;
                let match;
                htmlBlockRegex.lastIndex = 0;

                while ((match = htmlBlockRegex.exec(displayContent)) !== null) {
                    const textBefore = displayContent.substring(lastIndex, match.index);
                    if (textBefore.trim()) {
                        const textNode = document.createElement('div');
                        textNode.innerHTML = sanitizeHTML(textBefore);
                        logEntry.appendChild(textNode);
                    }

                    const htmlContent = match[1];

                    const iframe = document.createElement('iframe');
                    iframe.style.width = '100%';
                    iframe.style.border = '1px solid var(--separator-color, #444)';
                    iframe.style.borderRadius = '5px';
                    iframe.style.backgroundColor = 'rgba(0,0,0,0.2)';
                    iframe.style.margin = '1em 0';
                    iframe.setAttribute('frameborder', '0');
                    iframe.setAttribute('scrolling', 'no');
                    iframe.onload = () => {
                        try {
                            const doc = iframe.contentWindow.document;
                            const body = doc.body;
                            const updateHeight = () => {
                                const height = body.scrollHeight;
                                iframe.style.height = (height + 5) + 'px';
                            };
                            updateHeight();
                            const observer = new ResizeObserver(updateHeight);
                            observer.observe(body);

                        } catch (e) {
                            console.error('Error adjusting iframe height:', e);
                            setTimeout(() => {
                                try {
                                    const height = iframe.contentWindow.document.body.scrollHeight;
                                    iframe.style.height = (height + 15) + 'px';
                                } catch(err) {
                                     iframe.style.height = '150px';
                                }
                            }, 300);
                        }
                    };

                    iframe.srcdoc = `
                        <style>
                            body { margin: 1em; padding: 0; color: var(--ai-font-color, #FFFFFF); font-family: var(--chat-font-family, 'Lora', serif); }
                        </style>
                        ${htmlContent}
                    `;

                    logEntry.appendChild(iframe);

                    lastIndex = match.index + match[0].length;
                }

                const textAfter = displayContent.substring(lastIndex);
                if (textAfter.trim()) {
                    const textNode = document.createElement('div');
                    textNode.innerHTML = sanitizeHTML(textAfter);
                    logEntry.appendChild(textNode);
                }
            } else {
                logEntry.innerHTML = sanitizeHTML(displayContent);
            }

            return logEntry;
        }

        function addMessageToLog(logData, type) {
            const chatArea = mainContentArea;
            const logEntry = createLogEntryElement(logData, type);
            chatArea.appendChild(logEntry);

            logEntry.querySelectorAll('script.shadow-dom-data').forEach(scriptEl => {
                const hostId = scriptEl.dataset.hostId;
                const host = logEntry.querySelector(`#${hostId}`);
                const encodedHtml = scriptEl.textContent.trim();

                if (host && encodedHtml) {
                    try {
                        const htmlContent = decodeURIComponent(escape(atob(encodedHtml)));
                        const shadowRoot = host.attachShadow({ mode: 'open' });
                        shadowRoot.innerHTML = `
                            <style>
                                :host { display: block; border: 1px solid var(--separator-color, #444); padding: 1em; border-radius: 5px; background: rgba(0,0,0,0.2); margin: 1em 0; }
                            </style>
                        `;
                        const template = document.createElement('template');
                        template.innerHTML = htmlContent;
                        shadowRoot.appendChild(template.content.cloneNode(true));
                    } catch (e) {
                        console.error('Failed to create shadow DOM:', e);
                        host.innerText = 'Error rendering isolated HTML content.';
                    }
                }
                scriptEl.remove();
            });

            enforceRenderLimit();
            return logEntry;
        }

        function parseGameDate(dateString) {
            const dateRegex = /Năm(\d{4})\s.*?(Tháng(\d{1,2}))\s*Ngày(\d{1,2})\s*(\d{2}):(\d{2})/;
            const match = dateString.match(dateRegex);
            if (!match) return null;
            const [, year, month, day, hour, minute] = match.map(Number);
            const totalMinutes = ((year - 1) * 360 * 24 * 60) + ((month - 1) * 30 * 24 * 60) + ((day - 1) * 24 * 60) + (hour * 60) + minute;
            return { totalMinutes };
        }

        async function autoCleanupNPCs(state) {
            const timeRow = (state['4'] || [])[0];
            if (!timeRow || !timeRow['0']) return false;

            const currentTimeString = timeRow['0'].split('/')[0];
            const currentGameDate = parseGameDate(currentTimeString);
            if (!currentGameDate) return false;

            const npcs = state['0'] || {};
            const activeTaskNpcIds = new Set();
            Object.values(state['6'] || {}).forEach(task => {
                if (task['9'] === 'in-progress' && task.issuerId) {
                    activeTaskNpcIds.add(task.issuerId);
                }
            });

            let cleanedCount = 0;
            const minutesIn7Days = 7 * 24 * 60;

            for (const npcId in npcs) {
                if (!npcId.startsWith('C') && !npcId.startsWith('G')) continue;

                const npc = npcs[npcId];
                const booleans = parseRemarksString(npc['20']);
                const lastSeenTime = npc['21'];

                if (booleans.isEssential === 'true' || booleans.isBonded === 'true') {
                    continue;
                }

                if (activeTaskNpcIds.has(npcId)) {
                    continue;
                }

                if (npc['4'] === 'Tử Vong' && booleans.isPresent === 'false') {
                    delete state['0'][npcId];
                    cleanedCount++;
                    continue;
                }

                if (booleans.isPresent === 'false' && lastSeenTime) {
                    const lastSeenDate = parseGameDate(lastSeenTime);
                    if (lastSeenDate && (currentGameDate.totalMinutes - lastSeenDate.totalMinutes > minutesIn7Days)) {
                        delete state['0'][npcId];
                        cleanedCount++;
                    }
                }
            }

            if (cleanedCount > 0) {
                console.log(`Tự động dọn dẹp: ${cleanedCount} NPC không quan trọng đủ điều kiện đã bị xóa.`);
            }

            return cleanedCount > 0;
        }

        function parseRemarksString(str) {
            if (typeof str !== 'string') {
                return {};
            }
            return (str || '').split('|').reduce((acc, part) => {
                const firstColonIndex = part.indexOf(':');
                if (firstColonIndex > -1) {
                    const key = part.substring(0, firstColonIndex).trim();
                    const value = part.substring(firstColonIndex + 1).trim();
                    if (key) acc[key] = value;
                }
                return acc;
            }, {});
        }

        function serializeRemarksObject(remarksObj) {
            return Object.entries(remarksObj)
                .filter(([key, value]) => value !== undefined && value !== null)
                .map(([key, value]) => `${key}:${value}`)
                .join('|');
        }

        async function serializeAllCharacterData() {
            if (!currentArchiveName) return;
            const archive = await db.archives.get(currentArchiveName);
            if (!archive) return;

