        function getValidPointPool(level) {
            const lvl = parseInt(level) || 1;
            if (lvl <= 10) return { min: 50, max: 80 };
            if (lvl <= 20) return { min: 81, max: 95 };
            if (lvl <= 30) return { min: 96, max: 115 };
            if (lvl <= 40) return { min: 116, max: 135 };
            if (lvl <= 50) return { min: 136, max: 155 };
            else {
                // Sau level 50, mỗi level sẽ cho thêm 4 điểm vào tổng pool
                const basePoints = 155; // Mốc điểm tối đa của level 50
                const additionalPoints = (lvl - 50) * 4;
                const newMax = basePoints + additionalPoints;
                // Min pool cũng tăng theo để giữ khoảng cách hợp lý
                const newMin = newMax - 25; 
                return { min: newMin, max: newMax };
            }			
        }

        function calculateCustomTraitCost(bonusObject) {
            const totalBonus = Object.values(bonusObject || {}).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
            const costMap = {
                '-5': -25, '-4': -20, '-3': -15, '-2': -10, '-1': -5,
                '0': 0, '1': 20, '2': 30, '3': 40, '4': 60, '5': 70
            };
            return costMap[totalBonus] || 0;
        }

        function calculateLevelFromPoints(points) {
            for (let level = 1; level <= 50; level++) {
                const pool = getValidPointPool(level);
                if (points <= pool.max) {
                    return level;
                }
            }
            return 50;
        }

        function getLevelFromAttributePoints(totalPoints) {
            for (let level = 1; level <= 100; level++) {
                const pool = getValidPointPool(level);
                if (totalPoints <= pool.max) {
                    return level;
                }
            }
            return 100;
        }

        function clampAttributeValue(attributeName, value) {
            const parsedValue = parseInt(value) || 0;
            const isSpecialAttr = attributeName === 'Tín Ngưỡng' || attributeName === 'Thân Hòa Vực Sâu';
            const minValue = isSpecialAttr ? 0 : 1;
            const maxValue = 30;
            return Math.max(minValue, Math.min(parsedValue, maxValue));
        }

        function getPointCost(value, direction = 'increase', isCreation = false) {
            if (isCreation) {
                const targetValue = direction === 'increase' ? value : value - 1;
                if (targetValue < 12) return 1;
                if (targetValue < 15) return 2;
                if (targetValue < 18) return 3;
                return 4;
            } else {
                const targetValue = direction === 'increase' ? value : value + 1;
                if (targetValue <= 15) return 1;
                if (targetValue <= 20) return 2;
                if (targetValue <= 25) return 3;
                return 4;
            }
        }

        function getTableIndexFromId(id) {
            if (!id) return null;
            const prefix = id.substring(0, 2);
            if (prefix === 'IT') {
                return '2';
            }

            const singlePrefix = id.charAt(0);
            switch(singlePrefix) {
                case 'B':
                case 'C':
                case 'G':
                    return '0';
                case 'M':
                    return '10';
                case 'I':
                    return '1';
                case 'F':
                    return '3';
                case 'T':
                    return '6';
                case 'S':
                    return '8';
                case 'E':
                    return '5';
                case 'P':
                    return '7';
                default:
                    return null;
            }
        }

        function recalculateAndCorrectNpcStats(row, forceXpCheck = false, isNewlyInserted = false) {
            if (!row) return;

            const MAX_LEVEL = 99; // Cũ: 60
            const ATTRIBUTE_CAP = 99; // Cũ: 30

            const favorability = parseInt(row['15'] || '0');
            const clampedFavorability = Math.max(-100, Math.min(100, favorability));
            if (favorability !== clampedFavorability) {
                row['15'] = String(clampedFavorability);
            }

            let attributes = {};
            try {
                if (row['11'] && typeof row['11'] === 'string') {
                    const parsed = JSON.parse(row['11']);
                    if (typeof parsed === 'object' && parsed !== null) {
                        attributes = parsed;
                    }
                }
            } catch (e) {
                console.error(`Phân tích JSON thuộc tính của nhân vật ${row['0']} thất bại, sẽ sử dụng giá trị mặc định. Lỗi:`, e, "Dữ liệu gốc:", row['11']);
                attributes = {};
            }

            let wasCorrected = false;

            for (const attr in CREATION_CONFIG.ATTRIBUTES) {
                const minValue = (attr === 'Tín Ngưỡng' || attr === 'Thân Hòa Vực Sâu') ? 0 : 1;
                const currentValue = parseInt(attributes[attr]);
                if (isNaN(currentValue)) {
                    attributes[attr] = minValue;
                    wasCorrected = true;
                } else {
                    attributes[attr] = Math.max(minValue, Math.min(ATTRIBUTE_CAP, currentValue));
                    if(attributes[attr] !== currentValue) wasCorrected = true;
                }
            }

            let totalPoints = Object.values(attributes).reduce((sum, val) => sum + (val || 0), 0);
            let level = parseInt(row['9']) || 1;
            if (typeof row['9'] === 'string' && row['9'].includes(':')) {
                const remarks = parseRemarksString(row['9']);
                level = parseInt(remarks.level) || 1;
            }

            if (level > MAX_LEVEL) {
                level = MAX_LEVEL;
                row['9'] = level;
                wasCorrected = true;
            }

            const validPool = getValidPointPool(level);
            if (row['0'] !== 'B1' && totalPoints > validPool.max) {
                wasCorrected = true;
                let pointsToReduce = totalPoints - validPool.max;
                const sortedAttrs = Object.keys(attributes).sort((a, b) => attributes[b] - attributes[a]);
                while (pointsToReduce > 0 && sortedAttrs.length > 0) {
                    let changedInLoop = false;
                    for (const attr of sortedAttrs) {
                        const minValue = (attr === 'Tín Ngưỡng' || attr === 'Thân Hòa Vực Sâu') ? 0 : 1;
                        if (attributes[attr] > minValue) {
                            attributes[attr]--;
                            pointsToReduce--;
                            changedInLoop = true;
                            if (pointsToReduce === 0) break;
                        }
                    }
                    if (!changedInLoop) break;
                }
            }

            if (wasCorrected) {
                row['11'] = JSON.stringify(attributes);
            }

            const equipmentBonuses = (row['0'] === 'B1') ? calculateEquipmentBonuses() : calculateNpcEquipmentBonuses(row);
            const finalAttributes = { ...attributes };
            for(const attr in equipmentBonuses) {
                if(finalAttributes.hasOwnProperty(attr)) {
                    finalAttributes[attr] += equipmentBonuses[attr];
                }
            }

            const conModifier = Math.floor(((finalAttributes['Thể Chất'] || 8) - 10) / 2);
            const intModifier = Math.floor(((finalAttributes['Trí Lực'] || 8) - 10) / 2);
            const wisModifier = Math.floor(((finalAttributes['Tinh Thần'] || 8) - 10) / 2);

            let extraHP = 0;
            let extraMP = 0;
            const isMonster = row['0'].startsWith('M');

            if (!isMonster) {
                extraHP = parseInt(row['23'] || '0');
                extraMP = parseInt(row['24'] || '0');
            }
            extraHP += (equipmentBonuses.extraHP || 0);
            extraMP += (equipmentBonuses.extraMP || 0);

            const hpPerLevelBase = isMonster ? 3 : 5;
            const maxHP = 10 + (level * (hpPerLevelBase + conModifier)) + extraHP;
            const maxMP = 10 + (level * Math.max(1, 3 + intModifier + wisModifier)) + extraMP;

            const [currentHP_raw, oldMaxHP_raw] = (row['6'] || '0|0').split('|');
            const [currentMP_raw, oldMaxMP_raw] = (row['7'] || '0|0').split('|');

            const currentHP = parseInt(currentHP_raw) || 0;
            const oldMaxHP = parseInt(oldMaxHP_raw) || 0;
            const currentMP = parseInt(currentMP_raw) || 0;
            const oldMaxMP = parseInt(oldMaxMP_raw) || 0;

            if (isNewlyInserted || wasCorrected || !row['6'] || !row['7'] || isNaN(currentHP) || isNaN(currentMP)) {
                row['6'] = `${maxHP}|${maxHP}`;
                row['7'] = `${maxMP}|${maxMP}`;
            } else {
                const hpIncrease = maxHP - oldMaxHP;
                const newCurrentHP = Math.max(0, Math.min(maxHP, currentHP + hpIncrease));
                const mpIncrease = maxMP - oldMaxMP;
                const newCurrentMP = Math.max(0, Math.min(maxMP, currentMP + mpIncrease));
                row['6'] = `${newCurrentHP}|${maxHP}`;
                row['7'] = `${newCurrentMP}|${maxMP}`;
            }

            if (isNewlyInserted || wasCorrected || row['17'] === undefined) {
                const requiredXp = calculateXPForLevel(level);
                const minNewXp = Math.floor(requiredXp * 0.1);
                const maxNewXp = requiredXp > 0 ? requiredXp - 1 : 0;
                row['17'] = (Math.floor(Math.random() * (maxNewXp - minNewXp + 1)) + minNewXp).toString();
            }
        }

        function recalculatePetStats(petRow) {
            if (!petRow) return;

            const level = parseInt(petRow['9'] || '1');
            const attributes = petRow['11'] ? JSON.parse(petRow['11']) : {};
            let wasCorrected = false;

            const conModifier = Math.floor(((attributes['Thể Chất'] || 8) - 10) / 2);
            const intModifier = Math.floor(((attributes['Trí Lực'] || 8) - 10) / 2);

            const maxHP = 15 + (level * (6 + conModifier));
            const maxMP = 10 + (level * (4 + intModifier));

            const [currentHP, oldMaxHP] = (petRow['6'] || '0|0').split('|').map(Number);
            const [currentMP, oldMaxMP] = (petRow['7'] || '0|0').split('|').map(Number);

            const isNewPet = oldMaxHP === 0 && oldMaxMP === 0;

            if (isNewPet) {
                petRow['6'] = `${maxHP}|${maxHP}`;
                petRow['7'] = `${maxMP}|${maxMP}`;
                wasCorrected = true;
            } else if (maxHP !== oldMaxHP || maxMP !== oldMaxMP) {
                const hpIncrease = maxHP - oldMaxHP;
                const mpIncrease = maxMP - oldMaxMP;

                const newCurrentHP = Math.min(maxHP, currentHP + Math.max(1, hpIncrease));
                const newCurrentMP = Math.min(maxMP, currentMP + Math.max(1, mpIncrease));

                petRow['6'] = `${newCurrentHP}|${maxHP}`;
                petRow['7'] = `${newCurrentMP}|${maxMP}`;
                wasCorrected = true;
            }

            const requiredXp = calculatePetXPForLevel(level);
            if (petRow['17'] !== undefined && parseInt(petRow['17']) >= requiredXp) {
                petRow['17'] = (requiredXp - 1).toString();
                wasCorrected = true;
            }

            return wasCorrected;
        }

