        function generateChangelog(oldState, newState) {
            let updates = {};
            let additions = [];
            let deletions = [];

            const allTables = new Set([...Object.keys(oldState), ...Object.keys(newState)]);

            allTables.forEach(table => {
                const oldTable = oldState[table] || {};
                const newTable = newState[table] || {};
                const allIds = new Set([...Object.keys(oldTable), ...Object.keys(newTable)]);

                allIds.forEach(id => {
                    const oldRow = oldTable[id];
                    const newRow = newTable[id];

                    if (oldRow && !newRow) {
                        deletions.push(id);
                    } else if (!oldRow && newRow) {
                        additions.push(id);
                    } else if (oldRow && newRow) {
                        const changedFields = {};
                        const allFields = new Set([...Object.keys(oldRow), ...Object.keys(newRow)]);
                        allFields.forEach(field => {
                            if (JSON.stringify(oldRow[field]) !== JSON.stringify(newRow[field])) {
                                changedFields[field] = `"${oldRow[field]}" -> "${newRow[field]}"`;
                            }
                        });
                        if (Object.keys(changedFields).length > 0) {
                            if (!updates[id]) updates[id] = {};
                            Object.assign(updates[id], changedFields);
                        }
                    }
                });
            });

            let changelogString = '';
            if (Object.keys(updates).length > 0) {
                const updateStrings = Object.entries(updates).map(([id, fields]) =>
                    `${id}: {${Object.entries(fields).map(([key, val]) => `"${key}":${val}`).join(', ')}}`
                );
                changelogString += `Cập nhật: ${updateStrings.join('; ')}\n`;
            }
            if (additions.length > 0) {
                changelogString += `Thêm: ${additions.join(', ')}\n`;
            }
            if (deletions.length > 0) {
                changelogString += `Xóa: ${deletions.join(', ')}\n`;
            }

            return changelogString.trim();
        }

        function updateLocationNameFromPosition(charRow) {
            if (!charRow) return false;

            const booleans = parseRemarksString(charRow['20'] || '');
            const positionString = booleans.position;
            if (!positionString) return false;

            const [xStr, yStr] = positionString.split(',');
            const x = parseFloat(xStr);
            const y = parseFloat(yStr);

            if (isNaN(x) || isNaN(y)) return false;

            let newMainRegion = null;
            let newSubRegion = null;

            (currentLocationsData.mainRegions || []).forEach(region => {
                if(isPointInPolygon({x,y}, region.points)) {
                    newMainRegion = region;
                }
            });
            (currentLocationsData.subRegions || []).forEach(subRegion => {
                if(isPointInPolygon({x,y}, subRegion.points)) {
                    newSubRegion = subRegion;
                    if (!newMainRegion) {
                        newMainRegion = (currentLocationsData.mainRegions || []).find(r => r.name === subRegion.parentName);
                    }
