                try {
                    let effects = JSON.parse(char['25']);
                    if (!Array.isArray(effects)) continue;
                    const updatedEffects = effects.map(fx => {
                        fx.duration -= 1;
                        return fx;
                    }).filter(fx => fx.duration > 0);

                    if (updatedEffects.length !== effects.length) {
                        changesMade = true;
                        if (updatedEffects.length === 0) {
                            delete char['25'];
                        } else {
                            char['25'] = JSON.stringify(updatedEffects);
