            while (currentXp >= xpToNextLevel) {
                currentXp -= xpToNextLevel;
                currentLevel++;
                leveledUp = true;

                const pointsPerLevel = (level) => level > 30 ? 2 : 1;
                const pointsGained = pointsPerLevel(currentLevel);
                const currentAttribPoints = await dbGet(`ATTRIB_POINTS_${currentArchiveName}`) || 0;
                await dbSet(`ATTRIB_POINTS_${currentArchiveName}`, currentAttribPoints + pointsGained);

                showDanmaku(`Lên Cấp! -> Lv.${currentLevel}. Nhận được ${pointsGained} điểm thuộc tính！`, 'player');
                const fabAttributeBtn = document.querySelector('.fab-item[data-action="attributes"]');
                if (fabAttributeBtn && !fabAttributeBtn.querySelector('.red-dot')) {
                    const dot = document.createElement('span');
                    dot.className = 'red-dot red-dot-animation';
