                xpToNextLevel = calculateXPForLevel(currentLevel);
            }

            newPlayerRow['9'] = currentLevel.toString();
            newPlayerRow['17'] = currentXp.toString();

            if (leveledUp) {
                recalculateAndCorrectNpcStats(newPlayerRow);
                const [newMaxHP, newMaxMP] = [newPlayerRow['6'].split('|')[1], newPlayerRow['7'].split('|')[1]];
                newPlayerRow['6'] = `${newMaxHP}|${newMaxHP}`;
                newPlayerRow['7'] = `${newMaxMP}|${newMaxMP}`;
            }

            const oldPlayerXp = parseInt(oldPlayerRow['17'] || '0');
            const xpGainedThisTurn = currentXp - oldPlayerXp;

            const summonedPet = Object.values(finalState['7'] || {}).find(p => parseRemarksString(p['20']).isSummoned === 'true');
            if (summonedPet && xpGainedThisTurn > 0) {
                 const petXpGain = Math.floor(xpGainedThisTurn * 0.75);
                 let petLevel = parseInt(summonedPet['9'] || '1');
                 let petCurrentXp = (parseInt(summonedPet['17']) || 0) + petXpGain;
                 let petRequiredXp = calculatePetXPForLevel(petLevel);

                 let petLeveledUp = false;
                 while(petCurrentXp >= petRequiredXp) {
                     petCurrentXp -= petRequiredXp;
                     petLevel++;
                     petRequiredXp = calculatePetXPForLevel(petLevel);
                     showDanmaku(`${summonedPet['1'].split('|')[0]} Lên Cấp! -> Lv.${petLevel}`, 'achievement');
                     petLeveledUp = true;
                 }
                 summonedPet['9'] = petLevel.toString();
                 summonedPet['17'] = petCurrentXp.toString();

                 if (petLeveledUp) {
                     recalculatePetStats(summonedPet);
                 }
            }

            return finalState;
        }

        function extractCommands(text) {
            const commands = [];
            const commandRegex = /(y_update|y_insert|y_delete|y_event|y_summary_s|y_summary_l|y_growth|y_json_update)\s*\(/g;
            let match;

            while ((match = commandRegex.exec(text)) !== null) {
                const commandName = match[1];
                const startIndex = match.index + commandName.length;
                let openParens = 0;
                let endIndex = -1;

                for (let i = startIndex; i < text.length; i++) {
                    if (text[i] === '(') {
                        openParens++;
                    } else if (text[i] === ')') {
                        openParens--;
                        if (openParens === 0) {
                            endIndex = i;
                            break;
                        }
                    }
                }

                if (endIndex !== -1) {
                    const fullCommand = text.substring(match.index, endIndex + 1);
                    commands.push(fullCommand);
                    commandRegex.lastIndex = endIndex;
                }
            }
            return commands;
        }

