        function attemptToFixYInsert(argStr) {
            try {
                let str = argStr.trim();
                if (!str.startsWith('{') || !str.endsWith('}')) return null;
                str = str.substring(1, str.length - 1).trim();
                if (str === '') return '{}';

                const values = [];
                let startIndex = 0;
                let inString = false;
                let bracketDepth = 0;
                let braceDepth = 0;

                for (let i = 0; i < str.length; i++) {
                    const char = str[i];
                    if (char === '"' && (i === 0 || str[i-1] !== '\\')) {
                        inString = !inString;
                    } else if (!inString) {
                        if (char === '[') bracketDepth++;
                        else if (char === ']') bracketDepth--;
                        else if (char === '{') braceDepth++;
                        else if (char === '}') braceDepth--;
                        else if (char === ',' && bracketDepth === 0 && braceDepth === 0) {
                            values.push(str.substring(startIndex, i).trim());
                            startIndex = i + 1;
                        }
                    }
                }
                values.push(str.substring(startIndex).trim());

                const fixedParts = values.map((part, index) => {
                    let valuePart = part;
                    const colonIndex = part.indexOf(':');

                    if (colonIndex > -1) {
                        let tempBrace = 0;
                        let tempBracket = 0;
                        let tempInString = false;
                        let isTopLevelColon = true;
                        for(let k=0; k < colonIndex; k++){
                            if(part[k] === '"' && (k === 0 || part[k-1] !== '\\')) tempInString = !tempInString;
                            else if(!tempInString){
                                if(part[k] === '{') tempBrace++;
                                else if(part[k] === '}') tempBrace--;
                                else if(part[k] === '[') tempBracket++;
                                else if(part[k] === ']') tempBracket--;
                            }
                        }
                        if(tempBrace === 0 && tempBracket === 0 && !tempInString){
                           valuePart = part.substring(colonIndex + 1).trim();
                        }
                    }

                    if (valuePart === '') return `"${index}":""`;
                    return `"${index}":${valuePart}`;
                });

                return `{${fixedParts.join(',')}}`;
            } catch (e) {
                console.error("Sửa chữa thất bại, ta đâm chết ngươi ta đâm chết ngươi:", e);
                return null;
            }
        }

