        async function addAction(type, data, context = {}, isHidden = false) {
            let actionText = '';
            switch(type) {
                case 'use':
                    const existingAction = actionQueue.find(a => a.type === 'use' && a.item.name === data.name);
                    if (existingAction) {
                        existingAction.quantity++;
                        renderActionQueue();
                        closeItemDetail();
                        return;
                    }
                    actionText = `Sử dụng ${data.name}`;
                    break;
                case 'travel':
                    actionText = `Đến ${data.location}`;
                    break;
                case 'gift':
                    actionText = `Tặng [${data.name}] cho ${context.charName}`;
                    break;
                case 'alchemy':
                    actionText = `Luyện Kim`;
                    break;
                case 'submit_task':
                    const task = currentState['6'][data.id];
                    if (task && task['9'] === 'completed') {
                        showLoading('Đang Tổng Kết Phần Thưởng Nhiệm Vụ...');
                        let rewardDelta = [];

                        rewardDelta.push({ command: 'y_update', id: data.id, data: { '9': 'closed' } });

                        if (task['12']) {
                            try {
                                const rewards = JSON.parse(task['12']);
                                if (Array.isArray(rewards)) {
                                    rewards.forEach(reward => {
                                        const playerRow = currentState['0']['B1'];
                                        switch (reward.type) {
                                            case 'money':
                                                const newMoney = (parseInt(playerRow['18']) || 0) + reward.amount;
                                                rewardDelta.push({ command: 'y_update', id: 'B1', data: { '18': newMoney.toString() } });
                                                break;
                                            case 'item':
                                                const newItemId = reward.id || `I_REWARD_${crypto.randomUUID()}`;
                                                rewardDelta.push({ command: 'y_insert', data: { '0': newItemId, '1': reward.name || 'Vật Phẩm Không Rõ', '2': reward.itemType || 'Tạp Vật', '3': reward.desc || '', '4': reward.effect || '', '5': (reward.quantity || 1).toString(), '7': (reward.value || 0).toString(), '8': 'B1' } });
                                                break;
                                            case 'favor':
                                                const targetChar = currentState['0'][reward.target];
                                                if (targetChar) {
                                                    const newFavor = (parseInt(targetChar['15']) || 0) + reward.amount;
                                                    rewardDelta.push({ command: 'y_update', id: reward.target, data: { '15': newFavor.toString() } });
                                                }
                                                break;
                                            case 'xp':
                                                const newXp = (parseInt(playerRow['17']) || 0) + reward.amount;
                                                rewardDelta.push({ command: 'y_update', id: 'B1', data: { '17': newXp.toString() } });
                                                break;
                                        }
                                    });
                                }
                            } catch(e) { console.error("Error parsing task reward JSON:", e); }
                        }

                        const changes = await applyChanges(currentState, rewardDelta);
                        currentState = changes.state;

                        await saveCurrentState();
                        syncStateFromTables();
                        hideLoading();
                        showDanmaku(`Ủy Thác [${data.name}] Đã Được Nộp！`, 'achievement');
                        tasksOverlay.classList.remove('visible');
                        await showCustomAlert('Ủy Thác Đã Được Nộp, Phần Thưởng Đã Được Trao！');

                    } else {
                        await showCustomAlert('Nhiệm Vụ Này Chưa Hoàn Thành Hoặc Không Tồn Tại, Không Thể Nộp.');
                    }
                    return;
				<!-- Start: Dùng cho các lệnh ẩn tùy chỉnh -->	
				default:
					// Dùng cho các lệnh ẩn tùy chỉnh
					if (typeof data === 'string') {
						actionText = data;
					} else {
						actionText = `[Lỗi] Hành động không xác định: ${type}`;
					}	<!-- End -->
            }

            if(type === 'travel') {
                 actionQueue = actionQueue.filter(a => a.type !== 'travel');
            }

            actionQueue.push({ type, text: actionText, data: data, context: context, isHidden }); <!-- Thêm isHidden-->

            renderActionQueue();

            if(type === 'use') closeItemDetail();
            if(type === 'travel') {
                locationDetailOverlay.classList.remove('visible');
                locationRpgOverlay.classList.remove('visible');
            }
        }

