        async function saveToLog(archiveName, newEntry, stateBeforeTurn = null) {
            try {
                const archive = await db.archives.get(archiveName);
                if (!archive) return;

                const attributePoints = await dbGet(`ATTRIB_POINTS_${archiveName}`) || 0;

                if (newEntry.type === 'user' && stateBeforeTurn) {
                    const fullStateBeforeTurn = {
                        ...stateBeforeTurn,
                        attributePoints: attributePoints
                    };
                    newEntry.stateBeforeThisTurn = JSON.stringify(fullStateBeforeTurn);
                }

                if (newEntry.stateSnapshot) {
                    try {
                        const snapshotObject = JSON.parse(newEntry.stateSnapshot);
                        let npcAvatarsToSave = null;

                        if (snapshotObject.npcAvatars) {
                            npcAvatarsToSave = snapshotObject.npcAvatars;
                            delete snapshotObject.npcAvatars;
                        }
                        if (snapshotObject.currentState && snapshotObject.currentState.npcAvatars) {
