        async function writeLogToWorldBook(archiveName, logEntries) {
            if (!window.parent || !window.parent.TavernHelper) { console.warn("Không thể truy cập TavernHelper của cửa sổ cha, bỏ qua việc ghi vào Lorebook."); return false; }
            try {
