                if (!primaryLorebook) { console.warn("Không tìm thấy Lorebook chính của nhân vật hiện tại, không thể ghi nhật ký."); return false; }
                const fullLogContent = logEntries.map(log => `【${new Date(log.timestamp).toLocaleString()}】\n${log.content}`).join('\n---\n');
                const entries = await window.parent.TavernHelper.getLorebookEntries(primaryLorebook);
                const loreComment = `§Nhật Ký_${archiveName}`;
                const existingEntry = entries.find(e => e.comment === loreComment);
                if (existingEntry) {
                    const updatedEntry = { ...existingEntry, content: fullLogContent };
                    await window.parent.TavernHelper.setLorebookEntries(primaryLorebook, [updatedEntry]);
                } else {
                    const newEntry = { comment: loreComment, content: fullLogContent, enabled: true, keys: [] };
                    await window.parent.TavernHelper.createLorebookEntries(primaryLorebook, [newEntry]);
                }
                return true;
            } catch (e) { console.error("Xảy ra lỗi khi ghi vào Lorebook:", e); return false; }
        }

        function getLogsForContext(allLogs) {
            const openingLog = allLogs.find(log => log.content.includes('<h4>Vận Mệnh Khởi Đầu, Tinh Tú Vang Vọng</h4>')) || null;
            const chatLogs = allLogs.filter(log => !log.content.includes('<h4>Vận Mệnh Khởi Đầu, Tinh Tú Vang Vọng</h4>'));

            let logsForPrompt = [];
            let visibleChatLogs = [];
            let hiddenChatLogs = [];

            if (summaryConfig.segmentedMemoryEnabled) {
                const chatLayers = summaryConfig.segmentedChatLayers || 0;
                const largeSummaryStart = summaryConfig.segmentedLargeSummaryStart || Infinity;

                const reversedLogs = [...chatLogs].reverse();

                let recentChatObjects = [];
                let smallSummaryBlock = [];
                let largeSummaryBlock = [];
                let macroSummaryBlock = [];

                const processedMacroRanges = new Set();

                for (let i = 0; i < reversedLogs.length; i++) {
                    const log = reversedLogs[i];

                    let isCoveredByMacro = false;
                    for (const summary of chatLogs) {
                        if (summary.type === 'summary_macro') {
                            const [start, end] = summary.range;
                            const originalIndex = allLogs.indexOf(log);
                            if (originalIndex >= start && originalIndex <= end) {
                                isCoveredByMacro = true;
                                const rangeKey = `${start}-${end}`;
                                if (!processedMacroRanges.has(rangeKey)) {
                                    macroSummaryBlock.unshift(summary.content);
                                    processedMacroRanges.add(rangeKey);
                                }
                                break;
                            }
                        }
                    }
                    if (isCoveredByMacro) continue;
                    if (i < chatLayers) {
                        recentChatObjects.unshift(log);
                    } else if (i >= largeSummaryStart) {
                        if (log.largeSummary) {
                            largeSummaryBlock.unshift(log.largeSummary);
                        }
                    } else {
                        if (log.smallSummary) {
                            smallSummaryBlock.unshift(log.smallSummary);
                        }
                    }
                }
                const summaryText = [
                    largeSummaryBlock.join('\n'),
                    macroSummaryBlock.join('\n\n'),
                    smallSummaryBlock.join('\n')
                ].filter(Boolean).join('\n\n');

                if (summaryText) {
                    logsForPrompt.push({ type: 'system', content: summaryText, isSummarized: true });
                }

                logsForPrompt.push(...recentChatObjects);
                visibleChatLogs = logsForPrompt;

                if (openingLog) {
                    logsForPrompt.unshift(openingLog);
                }

            } else {
                const macroSummaries = chatLogs.filter(log => log.type === 'summary_macro');
                const nonMacroLogs = chatLogs.filter(log => log.type !== 'summary_macro');

                const hiddenIds = new Set();
                if (regexConfig.fixedHideRange) {
                    const [start, end] = regexConfig.fixedHideRange.split('-').map(Number);
                    if (!isNaN(start) && !isNaN(end) && start > 0 && end >= start) {
                        for (let i = start - 1; i < end; i++) {
                            if (nonMacroLogs[i]) hiddenIds.add(nonMacroLogs[i].id);
                        }
                    }
                }
                visibleChatLogs = [...macroSummaries, ...nonMacroLogs.filter(log => !hiddenIds.has(log.id))];
                visibleChatLogs.sort((a,b) => allLogs.indexOf(a) - allLogs.indexOf(b));

                hiddenChatLogs = nonMacroLogs.filter(log => hiddenIds.has(log.id));
                logsForPrompt = [ ...(openingLog ? [openingLog] : []), ...visibleChatLogs ];
            }

            return { logsForPrompt, visibleChatLogs, hiddenChatLogs };
        }

        function calculateEquipmentBonuses() {
            const bonuses = { extraHP: 0, extraMP: 0 };
            Object.keys(CREATION_CONFIG.ATTRIBUTES).forEach(key => bonuses[key] = 0);

            const equipment = [
                ...(currentPlayerData.weapon || []),
                ...(currentPlayerData.armor || []),
                ...(currentPlayerData.accessory || []),
                ...(currentPlayerData.relic || []),
            ];

            equipment.forEach(item => {
                if (!item) return;
                const effects = parseItemEffect(item.effect);
                for (const attr in effects) {
                    if (bonuses.hasOwnProperty(attr)) {
                        bonuses[attr] += effects[attr];
                    }
                }
            });
            return bonuses;
        }

        function calculateNpcEquipmentBonuses(npcRow) {
            const bonuses = {};
            if (!npcRow || !currentState['1']) return bonuses;

            const npcId = npcRow['0'];
            const npcItems = Object.values(currentState['1']).filter(item => item['8'] === npcId && item['6']);

            npcItems.forEach(item => {
                if (item && item['4']) {
                    const effects = parseItemEffect(item['4']);
                    for (const attr in effects) {
                        bonuses[attr] = (bonuses[attr] || 0) + effects[attr];
                    }
                }
            });
            return bonuses;
        }

