        function generateTableStateStringForAI() {
            const stateForAI = {
                c: [],
                g: {}
            };

            const allItems = Object.values(currentState['1'] || {});
            const allSkills = Object.values(currentState['8'] || {});
            const allPets = Object.values(currentState['7'] || {});

            const toStableArray = (row, maxColumnIndex) => {
                const arr = [];
                for (let i = 0; i <= maxColumnIndex; i++) {
                    arr.push(row[String(i)] || "");
                }
                return arr;
            };

            Object.values(currentState['0'] || {}).forEach(char => {
                const charId = char['0'];
                const booleans = parseRemarksString(char['20'] || '');
                const isPresent = booleans.isPresent !== 'false';

                let coreData, inventoryData = [], skillsData = [];

                if (isPresent) {
                    let coreDataObject = { ...char };
                    delete coreDataObject['14'];

                    coreDataObject['11'] = char['11'] || '{}';

                    coreData = toStableArray(coreDataObject, 27);

                    inventoryData = allItems
                        .filter(item => item['8'] === charId && (charId !== 'B1' || item['2'] !== 'Vật Phẩm Quan Trọng'))
                        .map(item => toStableArray(item, 8));

                    skillsData = allSkills
                        .filter(skill => skill['11'] === charId)
                        .map(skill => toStableArray(skill, 11));

                } else {
                    const isImportant = booleans.isBonded === 'true' || Math.abs(parseInt(char['15'] || '0')) >= 50 || booleans.isEssential === 'true';
                    if (isImportant) {
                        coreData = { "0": charId, "1": char['1'], "8": char['8'], "10": char['10'], "13": char['13'], "15": char['15'], "16": char['16'], "20": char['20'], "21": char['21'] };
                    } else {
                        coreData = { "0": charId, "1": char['1'], "16": char['16'], "20": char['20'], "21": char['21'] };
                    }
                }
                stateForAI.c.push([coreData, inventoryData, skillsData]);
            });

            const summonedPets = allPets.filter(p => (parseRemarksString(p['20'] || '').isSummoned === 'true'));
            summonedPets.forEach(pet => {
                stateForAI.c.push([toStableArray(pet, 23), [], []]);
            });

            stateForAI.g['10'] = Object.values(currentState['10'] || {}).filter(m => (parseRemarksString(m['20'] || '').isPresent !== 'false')).map(m => toStableArray(m, 24));

            stateForAI.g['4'] = Object.values(currentState['4'] || {}).map(t => toStableArray(t, 0));
            stateForAI.g['6'] = Object.values(currentState['6'] || {}).filter(t => t['9'] !== 'closed').map(t => toStableArray(t, 14));

            return JSON.stringify(stateForAI);
        }

        function parseStaticDataString(newString, currentStaticData) {
            const newData = JSON.parse(JSON.stringify(currentStaticData));
            let changesMade = false;

            const parts = newString.split(';').map(p => p.trim());

            for (const part of parts) {
                const match = part.match(/^(Chủng Tộc|Chức Nghiệp|Xuất Thân|Thiên Phú|Dấu Ấn):(.*)/);
                if (!match) continue;

                const key = match[1];
                const value = match[2];

                switch (key) {
                    case 'Chủng Tộc':
                        const raceMatch = value.match(/([^()]+)(?:\(Hiệu Ứng:(.*)\))?/);
                        if (raceMatch) {
                            const raceName = raceMatch[1].trim();
                            const raceData = CREATION_CONFIG.RACES[raceName];
                            if (raceData) {
                                newData.race = { name: raceName, effect: raceData.traits[0]?.effects || 'Không' };
                                changesMade = true;
                            }
                        }
                        break;
                    case 'Xuất Thân':
                         const birthMatch = value.match(/([^()]+)(?:\(Hiệu Ứng:(.*)\))?/);
                         if (birthMatch) {
                            const birthName = birthMatch[1].trim();
                            const birthData = CREATION_CONFIG.BIRTHS[birthName];
                            if(birthData) {
                                const cleanBirthData = { ...birthData };
                                delete cleanBirthData.bonus;
                                newData.birth = cleanBirthData;
                                changesMade = true;
                            }
                         }
                        break;
                    case 'Dấu Ấn':
                        const imprintMatch = value.match(/([^()]+)(?:\(Hiệu Ứng:(.*)\))?/);
                        if (imprintMatch) {
                            const imprintName = imprintMatch[1].trim();
                            const imprintEffect = imprintMatch[2] ? imprintMatch[2].trim().replace(/\)$/, '') : '';
                            newData.imprint = { name: imprintName, effect: imprintEffect };
                            changesMade = true;
                        }
                        break;
                    case 'Thiên Phú':
                        const newTraits = value.split(',').map(t => {
                            const traitMatch = t.match(/([^()]+)(?:\(Hiệu Ứng:(.*)\))?/);
                            return traitMatch ? traitMatch[1].trim() : null;
                        }).filter(Boolean);

                        const currentTraitNames = new Set(newData.traits.map(t => t.name));
                        if (newTraits.some(tName => !currentTraitNames.has(tName)) || newTraits.length < currentTraitNames.size) {
                            const updatedTraits = [];
                            newTraits.forEach(traitName => {
                                let foundTrait = newData.traits.find(t => t.name === traitName);
                                if (!foundTrait) {
                                    for (const rarity in CREATION_CONFIG.TRAITS) {
                                        const foundInConfig = CREATION_CONFIG.TRAITS[rarity].find(t => t.name === traitName);
                                        if (foundInConfig) {
                                            foundTrait = { ...foundInConfig, rarity };
                                            delete foundTrait.bonus;
                                            break;
                                        }
                                    }
                                }
                                if (foundTrait) {
                                    updatedTraits.push(foundTrait);
                                }
                            });
                            newData.traits = updatedTraits;
                            changesMade = true;
                        }
                        break;
                }
            }
            return changesMade ? newData : null;
        }

