        async function handleRegenerate(targetLogId) {
            const archive = await db.archives.get(currentArchiveName);
            if (!archive) return;

            let logs = archive.data.logs;
            const targetLogIndex = logs.findIndex(log => log.id === targetLogId);

            if (targetLogIndex === -1) {
                await showCustomAlert('Không có mục tiêu để tạo lại.');
                return;
            }

            if (targetLogIndex === 1) {
                if (await showCustomConfirm('Bạn có chắc muốn tạo lại cốt truyện mở đầu không? Điều này sẽ đưa bạn trở lại thời điểm vừa tạo xong nhân vật.')) {
                    showLoading('Đang quay trở lại buổi đầu sáng thế...');
                    try {
                        const genesisLog = logs[0];
                        if (!genesisLog || !genesisLog.stateSnapshot) {
                            throw new Error('Không tìm thấy khoảnh khắc sáng thế, không thể tạo lại màn mở đầu.');
                        }

                        const initialSnapshotObject = JSON.parse(genesisLog.stateSnapshot);
                        const customOpeningStyle = genesisLog.customOpeningStyle || '';

                        const stateToLoad = initialSnapshotObject.currentState
                            ? { ...initialSnapshotObject.state, currentState: initialSnapshotObject.currentState }
                            : { currentState: initialSnapshotObject };

                        const openingPrompt = buildOpeningPrompt(stateToLoad.currentState, customOpeningStyle);

                        archive.data.logs = logs.slice(0, 1);
                        archive.data.state = stateToLoad;

                        if (initialSnapshotObject.isExtreme !== undefined) {
                            archive.data.state.isExtreme = initialSnapshotObject.isExtreme;
                        }

                        await db.archives.put(archive);
                        if (initialSnapshotObject.attributePoints !== undefined) {
                            await dbSet(`ATTRIB_POINTS_${currentArchiveName}`, initialSnapshotObject.attributePoints);
                        }

                        await loadState(archive.data.state, true);
                        loadChatHistory(archive.data.logs);
                        await sendMessage(openingPrompt, true, '[Lệnh Hệ Thống] Tạo lại cốt truyện mở đầu', true);

                    } catch (e) {
                        await showCustomAlert(`Tạo lại mở đầu thất bại: ${e.message}`);
                    } finally {
                        hideLoading();
                    }
                }
                return;
            }
            let lastUserLogIndex = -1;
            for (let i = targetLogIndex; i >= 0; i--) {
                if (logs[i].type === 'user') {
                    lastUserLogIndex = i;
                    break;
                }
            }

            if (lastUserLogIndex === -1) {
                await showCustomAlert('Không tìm thấy đầu vào người dùng tương ứng để tạo lại.');
                return;
            }

            const logsToKeep = logs.slice(0, lastUserLogIndex + 1);
            const logToRegenFrom = logsToKeep[lastUserLogIndex];
            let stateToLoad;

            if (logToRegenFrom.stateBeforeThisTurn) {
                console.log(`Tạo lại: Đã tải khoảnh khắc lượt trước từ nhật ký người dùng [${logToRegenFrom.id}].`);
                try {
                    const fullStateBefore = JSON.parse(logToRegenFrom.stateBeforeThisTurn);
                    stateToLoad = { currentState: fullStateBefore };
                    if (fullStateBefore.attributePoints !== undefined) {
                         await dbSet(`ATTRIB_POINTS_${currentArchiveName}`, fullStateBefore.attributePoints);
                    }
                } catch(e) {
                     await showCustomAlert('Quay lại trạng thái thất bại, dữ liệu khoảnh khắc lượt trước có thể đã bị hỏng.');
                     return;
                }
            } else {
                const lastAiLogBeforeUser = lastUserLogIndex > 0 ? logs.slice(0, lastUserLogIndex).reverse().find(log => log.type === 'ai' && log.stateSnapshot) : null;
                const lastLogWithState = lastAiLogBeforeUser || logs.find(log => log.stateSnapshot);

                if (!lastLogWithState || !lastLogWithState.stateSnapshot) {
                    await showCustomAlert('Lỗi nghiêm trọng: Không tìm thấy khoảnh khắc để quay lại.');
                    return;
                }
                try {
                    const snapshotObject = JSON.parse(lastLogWithState.stateSnapshot);
                    stateToLoad = snapshotObject.currentState ? snapshotObject : { currentState: snapshotObject };
                    if (snapshotObject.attributePoints !== undefined) {
                        await dbSet(`ATTRIB_POINTS_${currentArchiveName}`, snapshotObject.attributePoints);
                    }
                } catch(e) {
                    await showCustomAlert('Quay lại trạng thái thất bại, dữ liệu khoảnh khắc nhật ký có thể đã bị hỏng.');
                    return;
                }
            }

            await loadState(stateToLoad, true);

            archive.data.logs = logsToKeep;

            maintainMacroSummaries(archive);

            await db.archives.put(archive);

            let systemPromptForRegen = null;
            let userInputForRegen = null;
            let specialLogDataForRegen = null;

            if (logToRegenFrom.systemActionType) {
                console.log(`Đang sử dụng lệnh hành động hệ thống đặc biệt [${logToRegenFrom.systemActionType}] để tạo lại...`);

                const rawUserInput = (logToRegenFrom.fullContent || logToRegenFrom.content).replace(/^> /, '');

                specialLogDataForRegen = {
                    id: logToRegenFrom.id,
                    timestamp: logToRegenFrom.timestamp,
                    systemActionType: logToRegenFrom.systemActionType,
                    systemActionData: logToRegenFrom.systemActionData
                };

                switch(logToRegenFrom.systemActionType) {
                    case 'alchemy':
                        systemPromptForRegen = buildAlchemyPrompt(logToRegenFrom.systemActionData);
                        userInputForRegen = rawUserInput;
                        break;
                    default:
                        userInputForRegen = rawUserInput;
                        systemPromptForRegen = rawUserInput;
                        userInputForRegen = null;
                        break;
                }
            } else {
                const rawMessage = logToRegenFrom.fullContent || logToRegenFrom.content;
                userInputForRegen = rawMessage.startsWith('> ') ? rawMessage.substring(2) : rawMessage;
                systemPromptForRegen = null;
            }

            loadChatHistory(logsToKeep);
            const originalSendMessage = sendMessage;
            const tempSendMessage = async (...args) => {
                const originalClearMapHistory = window.clearMapHistory;
                window.clearMapHistory = () => { console.log("Regen in progress, map history clearing skipped."); };
                try {
                    await originalSendMessage(...args);
                } finally {
                    window.clearMapHistory = originalClearMapHistory;
                }
            };
            await tempSendMessage(systemPromptForRegen, true, userInputForRegen, false, specialLogDataForRegen);
        }

        function parseAIResponse(rawResponse) {
            let content = rawResponse;
            let tableEditCommandsString = '';

            const tableEditRegex = /<y_actions>([\s\S]*?)<\/y_actions>/g;

            const matches = [...content.matchAll(tableEditRegex)];
            if (matches.length > 0) {
                tableEditCommandsString = matches.map(match => match[1].trim()).join(' ');
            }

            content = content.replace(tableEditRegex, '');

            let branchContent = null;
            const branchRegex = /<branches>[\s\S]*?<\/branches>/g;
            const branchMatches = content.match(branchRegex);
            if (branchMatches) {
                branchContent = branchMatches.join('\n');
                content = content.replace(branchRegex, '');
            }

            const picGenRegex = /<pic[^>]*\sprompt="([^"]*)"[^>]*?>/g;
            content = content.replace(picGenRegex, (match, prompt) => {
                if (chatBackgroundSettings.autoImageGen && prompt) {
                    handleAIGenRequest(prompt, true);
                }
                return '';
            });
            content = processTextWithRules(content, PLACEMENT_MAP.AI_OUTPUT, 'chain');
            content = processTextWithRules(content, PLACEMENT_MAP.AI_OUTPUT, 'regular');

            return {
                tableEditCommands: tableEditCommandsString,
                branchOptions: [],
                contentBeforeProcessing: content.trim(),
                branchContent: branchContent
            };
        }

        function parseRegexString(regexString) {
            const lastSlash = regexString.lastIndexOf('/');
            if (regexString.startsWith('/') && lastSlash > 0) {
                const pattern = regexString.substring(1, lastSlash);
                const flags = regexString.substring(lastSlash + 1);
                return { pattern, flags };
            }
            return { pattern: regexString, flags: 'g' };
        }

        function processTextWithRules(text, scope, type) {
            let processedText = text;
            const rules = type === 'chain' ? (regexConfig.chainRules || []) : (regexConfig.rules || []);

            rules.forEach(rule => {
                if (!rule.disabled && rule.placement && rule.placement.includes(scope)) {
                    try {
                        const { pattern, flags } = parseRegexString(rule.findRegex);
                        const regex = new RegExp(pattern, flags);

                        if (type === 'chain') {
                            processedText = processedText.replace(regex, (match) => {
                                const escapedMatch = match.replace(/</g, '&lt;').replace(/>/g, '&gt;');
                                const summaryText = rule.replaceString.replace(/\$(\d)/g, (full, n) => {
                                    return `[Nhóm Bắt Giữ${n}]`;
                                });

                                return `
                                    <details>
                                        <summary>${rule.scriptName}: ${summaryText || 'Nhấp để mở rộng'}</summary>
                                        <pre style="white-space: pre-wrap; word-wrap: break-word; font-size: 0.85em; opacity: 0.7;">${escapedMatch}</pre>
                                    </details>
                                `;
                            });
                        } else {
                            processedText = processedText.replace(regex, rule.replaceString);
                        }

                    } catch (e) {
                        console.error(`Biểu thức chính quy ${type} không hợp lệ: ${rule.findRegex}`, e);
                    }
                }
            });

            return processedText;
        }

        async function updateUI(rawResponse, initialState, isOpeningSequence = false) {
            newTaskAdded = false;

            const { tableEditCommands, branchOptions, branchContent } = parseAIResponse(rawResponse);

            let { delta, smallSummary, largeSummary, parsingErrors, commandsString: fixedTableEditCommands } = parseTableEditCommands(tableEditCommands);

            if (fixedTableEditCommands !== tableEditCommands) {
                console.log("Phát hiện sửa chữa lệnh, đang cập nhật nội dung phản hồi gốc...");
                rawResponse = rawResponse.replace(tableEditCommands, fixedTableEditCommands);
            }

            if (parsingErrors && parsingErrors.length > 0) {
                const errorContent = parsingErrors.map(cmd => cmd.replace(/</g, '&lt;').replace(/>/g, '&gt;')).join('<br><br>');
                await showCustomDialog({
                    title: 'Thông Báo Chặn Lệnh',
                    message: `
                        <p>AI điên rồi！<br>Phát hiện AI xuất ra định dạng sai, các lệnh sau đây chưa được thực thi (vui lòng tự sửa/roll lại/đến kênh của tôi hoặc kênh tương tự để hỏi):</p>
<div style="max-height: 200px; overflow-y: auto; background: rgba(0,0,0,0.2); border: 1px solid var(--separator-color); padding: 10px; border-radius: 4px; text-align: left; white-space: pre-wrap; word-break: break-all; font-family: monospace;">
${errorContent}
</div>
`,
                    buttons: [{ text: 'Xác Nhận', value: () => true }]
                });
            }

            if (isOpeningSequence) {
                const originalDeltaCount = delta.length;
                delta = delta.filter(op => {
                    return op.id !== 'B1' && op.data?.['0'] !== 'B1';
                });
                const filteredCount = originalDeltaCount - delta.length;
                if (filteredCount > 0) {
                    console.warn(`[Bảo Vệ Mở Đầu] Đã chặn ${filteredCount} lệnh sửa đổi nhắm vào người chơi (B1).`);
                }
            }

            let { state: newState, log: changeLog, attributePointsGained, directAttributeGains } = await applyChanges(initialState, delta);
            if (attributePointsGained > 0) {
                const currentPoints = await dbGet(`ATTRIB_POINTS_${currentArchiveName}`) || 0;
                const newPoints = currentPoints + attributePointsGained;
                await dbSet(`ATTRIB_POINTS_${currentArchiveName}`, newPoints);

                showDanmaku(`Nhận được ${attributePointsGained} điểm thuộc tính có thể phân phối！`, 'player');

                const fabAttributeBtn = document.querySelector('.fab-item[data-action="attributes"]');
                if (fabAttributeBtn && !fabAttributeBtn.querySelector('.red-dot')) {
                    const dot = document.createElement('span');
                    dot.className = 'red-dot red-dot-animation';
                    fabAttributeBtn.appendChild(dot);
                    setTimeout(() => dot.classList.remove('red-dot-animation'), 2000);
                }
            }

            if (directAttributeGains && directAttributeGains.length > 0) {
                directAttributeGains.forEach(gain => {
                    if (gain.amount !== 0) {
                        const sign = gain.amount > 0 ? '+' : '';
                        showDanmaku(`${gain.attribute} vĩnh viễn ${sign}${gain.amount}！`, 'player');
                    }
                });
            }

            newState = await checkAndApplyPlayerLevelUp(initialState, newState);
            currentState = newState;

            syncStateFromTables(newState, null, (initialState.isExtreme || false));

            const achievementResult = await checkAchievements(rawResponse, newState);
            if (achievementResult.changed) {
                newState.achievements = achievementResult.achievementsState;
                if (achievementResult.rewardCommands.length > 0) {
                    const { delta: rewardDelta } = parseCleanCommands(achievementResult.rewardCommands);
                    const rewardChangesResult = await applyChanges(JSON.parse(JSON.stringify(newState)), rewardDelta);
                    newState = rewardChangesResult.state;
                    showDanmaku(`Phần Thưởng Thành Tựu Đã Được Trao！`, 'item');
                }
                currentState.achievements = newState.achievements;
                syncStateFromTables(newState);
                if (achievementOverlay.classList.contains('visible')) {
                    await openAchievementWall();
                }
            }

            await checkTaskCompletion();

            const attributePointsSnapshot = await dbGet(`ATTRIB_POINTS_${currentArchiveName}`) || 0;
            const stateToSnapshot = {
                ...((await db.archives.get(currentArchiveName))?.data.state || {}),
                currentState: newState,
                achievements: currentState.achievements,
                attributePoints: attributePointsSnapshot
            };

            const achievementsSnapshot = stateToSnapshot.achievements;

            const generateSimpleId = () => `${Date.now()}${Math.random().toString(36).substr(2, 5)}`;
            const newLogEntryId = generateSimpleId();
            let newLogEntry = null;

            if (rawResponse.trim() || branchContent) {
                newLogEntry = {
                    id: newLogEntryId,
                    timestamp: new Date().toISOString(),
                    content: rawResponse.trim(),
                    branchContent: branchContent || null,
                    stateSnapshot: JSON.stringify(stateToSnapshot),
                    achievementsSnapshot: achievementsSnapshot ? JSON.stringify(achievementsSnapshot) : null,
                    attributePointsSnapshot: attributePointsSnapshot,
                    type: 'ai',
                    smallSummary: smallSummary,
                    largeSummary: largeSummary
                };
            }

            if (summaryConfig.segmentedMemoryEnabled && newLogEntry && smallSummary === null && largeSummary === null && !rawResponse.includes('<div class="roll-result">')) {
                newLogEntry.smallSummary = "Tóm Tắt Nhỏ";
                newLogEntry.largeSummary = "Tóm Tắt Lớn";
                await saveToLog(currentArchiveName, newLogEntry);
                openManualSegmentedMemoryEditor(newLogEntryId);
            }
            const stateAfterEffects = await processTemporaryEffects(newState);
            if (stateAfterEffects) {
                currentState = stateAfterEffects;
            }

            return newLogEntry;
        }

