        async function repairAndLoadArchive(archiveName) {
            let archive = await db.archives.get(archiveName);
            if (!archive) {
                await showCustomAlert('Sửa chữa thất bại: Không tìm thấy lưu trữ.');
                return;
            }

            const logs = archive.data.logs;
            const lastGoodLogIndex = [...logs].reverse().findIndex(log => log.stateSnapshot);

            if (lastGoodLogIndex === -1) {
                await showCustomAlert('Không thể sửa chữa lưu trữ: Không tìm thấy khoảnh khắc trạng thái hợp lệ nào.');
                return;
            }

            const realIndex = logs.length - 1 - lastGoodLogIndex;
            const snapshotLog = logs[realIndex];

            try {
                const snapshotState = JSON.parse(snapshotLog.stateSnapshot);
                archive.data.state = snapshotState.currentState ? snapshotState : { ...archive.data.state, currentState: snapshotState };

                if (snapshotLog.achievementsSnapshot) {
                    archive.data.state.achievements = JSON.parse(snapshotLog.achievementsSnapshot);
                } else if (snapshotState.achievements) {
                    archive.data.state.achievements = snapshotState.achievements;
                }
                if (snapshotLog.attributePointsSnapshot !== undefined) {
                    await dbSet(`ATTRIB_POINTS_${archiveName}`, snapshotLog.attributePointsSnapshot);
                }

                archive.data.logs = logs.slice(0, realIndex + 1);
                await db.archives.put(archive);
                await showCustomAlert('Sửa chữa lưu trữ thành công！Đã quay lại trạng thái cuối cùng trước khi xảy ra lỗi.');

                currentArchiveName = archiveName;
                await dbSet(ACTIVE_ARCHIVE_KEY, archiveName);
                if (!archive.data.state.promptInjection) {
                    archive.data.state.promptInjection = {
                        enabled: regexConfig.enablePromptInjection || false,
                        prefix: regexConfig.promptPrefix || '',
                        suffix: regexConfig.promptSuffix || ''
                    };
                    await db.archives.put(archive);
                    console.log(`Cài đặt prompt vĩnh viễn của kho lưu trữ [${archiveName}] đã được di chuyển thành công.`);
                }

                await loadState(archive.data.state, true);
                loadChatHistory(archive.data.logs);
                await writeMapToWorldBook(archiveName, currentLocationsData);

                toggleCenterView('chat-view');
                gamePanel.classList.remove('hidden');
                splashScreen.classList.add('hidden');
                toggleExtremeModeUI(currentPlayerData.isExtreme);

            } catch(e) {
                await showCustomAlert(`Sửa chữa thất bại, lỗi phân tích dữ liệu khoảnh khắc: ${e.message}`);
            }
        }

        async function ensureArchiveIsSlim(archiveName) {
            showLoading('Đang kiểm tra và tối ưu hóa cấu trúc lưu trữ...');
            try {
                const archive = await db.archives.get(archiveName);
                if (!archive) return false;

                let wasModified = false;
                let combinedNpcAvatars = await dbGet(`${NPC_AVATARS_KEY}_${archiveName}`) || {};

                if (archive.data.state) {
                    if (archive.data.state.npcAvatars && Object.keys(archive.data.state.npcAvatars).length > 0) {
                        Object.assign(combinedNpcAvatars, archive.data.state.npcAvatars);
                        delete archive.data.state.npcAvatars;
                        wasModified = true;
                    }
                    if (archive.data.state.currentState && archive.data.state.currentState.npcAvatars && Object.keys(archive.data.state.currentState.npcAvatars).length > 0) {
                        Object.assign(combinedNpcAvatars, archive.data.state.currentState.npcAvatars);
                        delete archive.data.state.currentState.npcAvatars;
                        wasModified = true;
                    }
                }

                if (archive.data.logs && Array.isArray(archive.data.logs)) {
                    for (const log of archive.data.logs) {
                        if (log.stateSnapshot) {
                            try {
                                const snapshotObject = JSON.parse(log.stateSnapshot);
                                let snapshotModified = false;

                                if (snapshotObject.npcAvatars && typeof snapshotObject.npcAvatars === 'object' && Object.keys(snapshotObject.npcAvatars).length > 0) {
                                    Object.assign(combinedNpcAvatars, snapshotObject.npcAvatars);
                                    delete snapshotObject.npcAvatars;
                                    snapshotModified = true;
                                }
                                if (snapshotObject.currentState && snapshotObject.currentState.npcAvatars && typeof snapshotObject.currentState.npcAvatars === 'object' && Object.keys(snapshotObject.currentState.npcAvatars).length > 0) {
                                    Object.assign(combinedNpcAvatars, snapshotObject.currentState.npcAvatars);
                                    delete snapshotObject.currentState.npcAvatars;
                                    snapshotModified = true;
                                }
                                if (snapshotModified) {
                                    log.stateSnapshot = JSON.stringify(snapshotObject);
                                    wasModified = true;
                                }
                            } catch (e) {
                                console.warn(`Trong quá trình kiểm tra tinh giản, đã bỏ qua khoảnh khắc có định dạng sai (log ID: ${log.id})。`);
                            }
                        }
                    }
                }

                if (wasModified) {
                    console.log(`Lưu trữ [${archiveName}] đã được tinh giản, đã trích xuất dữ liệu avatar và/hoặc bản đồ.`);
                    if (Object.keys(combinedNpcAvatars).length > 0) {
                         await dbSet(`${NPC_AVATARS_KEY}_${archiveName}`, combinedNpcAvatars);
                    }
                    await db.archives.put(archive);
                    await showCustomAlert(`Lưu trữ [${archiveName}] đã được tối ưu hóa tự động, đã xóa dữ liệu avatar và bản đồ nhúng để cải thiện hiệu suất.`);
                }

                return true;
            } catch (error) {
                console.error("Xảy ra lỗi trong quá trình kiểm tra tinh giản lưu trữ:", error);
                await showCustomAlert('Kiểm tra tình trạng lưu trữ thất bại, vui lòng xem chi tiết trong console.');
                return false;
            } finally {
                hideLoading();
            }
        }

        async function selectAndLoadArchive(archiveName) {
            showLoading('Đang đọc lưu trữ...');
            try {
                const isHealthy = await ensureArchiveIsSlim(archiveName);
                if (!isHealthy) {
                    hideLoading();
                    return;
                }

                showLoading('Đang kiểm tra phiên bản...');
                let archive = await db.archives.get(archiveName);
                if (!archive) {
                    await showCustomAlert(`Lỗi: Không tìm thấy lưu trữ "${archiveName}"`);
                    hideLoading();
                    return;
                }

                const migrationNeeded = parseFloat(archive.data.version || "1.0") < parseFloat(GAME_VERSION);

                if (migrationNeeded) {
                    hideLoading();
                    const confirmed = await showCustomConfirm(
                        `Phát hiện lưu trữ phiên bản cũ (v${archive.data.version || "1.0"})。<br><br>Để đảm bảo trải nghiệm game tốt nhất và khắc phục các vấn đề tiềm ẩn, đề nghị nâng cấp lên cấu trúc dữ liệu của phiên bản hiện tại (v${GAME_VERSION})。<br><br><strong>Có nâng cấp ngay bây giờ không?</strong>`,
                        'Cập Nhật Phiên Bản Lưu Trữ'
                    );

                    if (confirmed) {
                        showLoading('Đang nâng cấp cấu trúc lưu trữ...');
                        const changesMade = await migrateSaveData(archive);
                        if (changesMade) {
                            await db.archives.put(archive);
                            await showCustomAlert('Lưu trữ đã nâng cấp thành công！Sẽ tải lại ngay bây giờ...');
                        } else {
                            archive.data.version = GAME_VERSION;
                            await db.archives.put(archive);
                            await showCustomAlert('Số phiên bản lưu trữ đã được cập nhật, không phát hiện cấu trúc dữ liệu cần sửa đổi. Sẽ tải lại ngay bây giờ...');
                        }
                        await selectAndLoadArchive(archiveName);
                        return;
                    } else {
                        if (!splashScreen.classList.contains('hidden')) {
                            splashScreen.classList.remove('hidden');
                            gamePanel.classList.add('hidden');
                        } else {
                            toggleCenterView('archive-selection-view');
                            await renderArchiveSelectionView();
                        }
                        hideLoading();
                        return;
                    }
                }

                showLoading('Đang tải trò chơi...');
                currentArchiveName = archiveName;
                await dbSet(ACTIVE_ARCHIVE_KEY, archiveName);

                await loadState(archive.data.state, true);

                const scaleInputEditor = document.getElementById('map-scale-input-editor');
                if (scaleInputEditor) {
                    scaleInputEditor.value = currentLocationsData?.mapScaleKm || 200;
                }

                loadChatHistory(archive.data.logs);

                const lastLog = archive.data.logs[archive.data.logs.length - 1];
                if (lastLog && lastLog.branchContent) {
                    const branchMatch = lastLog.branchContent.match(/<branches>([\s\S]*?)<\/branches>/);
                    if (branchMatch) {
                        const optionRegex = /\[(.*?)\]/g;
                        const allOptions = [];
                        let option;
                        while ((option = optionRegex.exec(branchMatch[1])) !== null) {
                            allOptions.push(option[1]);
                        }
                        updateBranchingOptions(allOptions);
                    } else {
                        updateBranchingOptions([]);
                    }
                } else {
                    updateBranchingOptions([]);
                }

                await writeMapToWorldBook(archiveName, currentLocationsData);

                showLoading('Đồng bộ Lorebook...');
                await syncLorebookStatus(archiveName);

                toggleCenterView('chat-view');
                gamePanel.classList.remove('hidden');
                splashScreen.classList.add('hidden');
                toggleExtremeModeUI(currentPlayerData.isExtreme);

                clearMapHistory();
