        function loadChatHistory(logs) {
            const existingEntries = mainContentArea.querySelectorAll('.log-entry, .summary-logs-container, .hidden-logs-container');
            existingEntries.forEach(entry => entry.remove());

            if (!logs || logs.length === 0) return;
            const limit = regexConfig.renderLimit || 20;
            const logsToRender = logs.slice(-limit);
            logsToRender.forEach(log => {
                const type = log.type || 'ai';
                mainContentArea.appendChild(createLogEntryElement(log, type));
            });

            setTimeout(() => {
                if (logs.length <= 1) {
                    mainContentArea.scrollTop = 0;
                } else {
                    mainContentArea.scrollTop = mainContentArea.scrollHeight;
                }
            }, 0);
        }

