        function parseItemEffect(effectString) {
            const effects = {};
            if (!effectString || effectString === 'Không') return effects;
            const parts = effectString.split(/[,，]/);
            const regex = /(.+?)([+-])(\d+)/;
            parts.forEach(part => {
                const match = part.trim().match(regex);
                if (match) {
                    const attr = match[1].trim();
                    const sign = match[2];
                    const value = parseInt(match[3]);
                    effects[attr] = (sign === '+') ? value : -value;
                }
            });
            return effects;
        }

        function renderPlayerAttributes(playerData) {
            attributesList.innerHTML = '';
            if (!playerData || !playerData.id) return;

            const playerRow = currentState['0'] ? currentState['0']['B1'] : {};
            const inherentExtraHP = parseInt(playerRow['23'] || '0');
            const inherentExtraMP = parseInt(playerRow['24'] || '0');

            const equipmentBonuses = calculateEquipmentBonuses();
            const equipmentExtraHP = equipmentBonuses.extraHP || 0;
            const equipmentExtraMP = equipmentBonuses.extraMP || 0;

            const totalExtraHP = inherentExtraHP + equipmentExtraHP;
            const totalExtraMP = inherentExtraMP + equipmentExtraMP;

            const conModifier = Math.floor(((playerData.detailedAttributes['Thể Chất'] || 10) - 10) / 2);
            const intModifier = Math.floor(((playerData.detailedAttributes['Trí Lực'] || 10) - 10) / 2);
            const wisModifier = Math.floor(((playerData.detailedAttributes['Tinh Thần'] || 10) - 10) / 2);
            const level = parseInt(playerData.level || 1);
            const correctMaxHP = 10 + (level * (5 + conModifier)) + totalExtraHP;
            const correctMaxMP = 10 + (level * (3 + intModifier + wisModifier)) + totalExtraMP;
            const baseMaxHP = correctMaxHP - totalExtraHP;
            const baseMaxMP = correctMaxMP - totalExtraMP;

            const currentHP = Math.min(playerData.currentHP !== undefined ? playerData.currentHP : correctMaxHP, correctMaxHP);
            let hpDisplay = `${currentHP}/${correctMaxHP}`;
            if (totalExtraHP !== 0) {
                let breakdown = [];
                if (inherentExtraHP > 0) {
                    breakdown.push(`<span class="attr-bonus">+${inherentExtraHP}</span>`);
                } else if (inherentExtraHP < 0) {
                     breakdown.push(`<span class="attr-penalty">${inherentExtraHP}</span>`);
                }
                if (equipmentExtraHP > 0) {
                    breakdown.push(`<span class="attr-bonus">+${equipmentExtraHP}</span>`);
                } else if (equipmentExtraHP < 0) {
                    breakdown.push(`<span class="attr-penalty">${equipmentExtraHP}</span>`);
                }
                hpDisplay += ` <small style="opacity: 0.8;">(${baseMaxHP} ${breakdown.join(' ')})</small>`;
            }

            const currentMP = Math.min(playerData.currentMP !== undefined ? playerData.currentMP : correctMaxMP, correctMaxMP);
            let mpDisplay = `${currentMP}/${correctMaxMP}`;
            if (totalExtraMP !== 0) {
                let breakdown = [];
                if (inherentExtraMP > 0) {
                    breakdown.push(`<span class="attr-bonus">+${inherentExtraMP}</span>`);
                } else if (inherentExtraMP < 0) {
                    breakdown.push(`<span class="attr-penalty">${inherentExtraMP}</span>`);
                }
                if (equipmentExtraMP > 0) {
                    breakdown.push(`<span class="attr-bonus">+${equipmentExtraMP}</span>`);
                } else if (equipmentExtraMP < 0) {
                    breakdown.push(`<span class="attr-penalty">${equipmentExtraMP}</span>`);
                }
                mpDisplay += ` <small style="opacity: 0.8;">(${baseMaxMP} ${breakdown.join(' ')})</small>`;
            }

            const displayOrder = [
                { label: 'Chủng Tộc', value: playerData.race || 'Không Rõ' },
                { label: 'Thân Phận', value: playerData.identity || 'Không' },
                { label: 'Tuổi', value: playerData.age || 'Không Rõ' },
                { label: 'Chức Nghiệp', value: playerData.career || 'Thất Nghiệp' },
                { label: 'Cấp', value: `Lv.${playerData.level || 1}` },
                { label: 'Hạng Mạo Hiểm', value: playerData.adventureRank || 'Chưa Xếp Hạng' },
                { label: 'Sinh Mệnh(HP)', value: hpDisplay },
                { label: 'Ma Lực(MP)', value: mpDisplay },
            ];

            if (playerData.lustValue !== undefined && playerData.lustValue !== null) {
                const [current, max] = String(playerData.lustValue).split('|').map(Number);
                if (!isNaN(current)) {
                    const maxLust = (!isNaN(max) && max > 0) ? max : 10 + (playerData.detailedAttributes['Mị Lực'] || 8) * 2 + (playerData.detailedAttributes['Tinh Thần'] || 8);
                    displayOrder.push({ label: 'Giá Trị Ham Muốn', value: `${current}/${maxLust}` });
                }
            }

            displayOrder.push({ label: 'Đồng Mithril', value: playerData.money || '0' });

            let locationValue = `${playerData.location || 'Không Rõ'}`;
            if (playerData.detailedLocation && playerData.detailedLocation !== playerData.location) {
                locationValue += ` / ${playerData.detailedLocation}`;
            }
            if (playerData.position && playerData.position.x !== undefined && playerData.position.y !== undefined) {
                locationValue += `<br><span style="font-size: 0.9em; opacity: 0.8;">(Tọa Độ: ${playerData.position.x.toFixed(2)}, ${playerData.position.y.toFixed(2)})</span>`;
            }
            displayOrder.push({ label: 'Nơi Ở', value: locationValue });

            for (const item of displayOrder) {
                const li = document.createElement('li');
                li.innerHTML = `<span class="attr-label">${item.label}:</span><span class="attr-value">${item.value}</span>`;
                attributesList.appendChild(li);
            }
        }

        function renderInventory(items) {
            inventoryGrid.innerHTML = '';

            const equipmentSlots = ['weapon', 'armor', 'accessory', 'relic'];
            const equippedItemIds = new Set();
            equipmentSlots.forEach(slotKey => {
                (currentPlayerData[slotKey] || []).forEach(item => {
                    if (item && item.id) {
                        equippedItemIds.add(item.id);
                    }
                });
            });

            const itemsToShow = items.filter(item => !equippedItemIds.has(item.id));

            if (itemsToShow.length === 0) {
                inventoryGrid.innerHTML = '<p style="grid-column: 1 / -1; text-align: center; opacity: 0.7;">Túi đồ trống không...</p>';
                return;
            }

            const typeOrder = ['Vật Phẩm Tiêu Hao', 'Vũ Khí', 'Giáp', 'Phụ Kiện', 'Thánh Vật', 'Vật Phẩm Quan Trọng', 'Nguyên Liệu', 'Cuộn Giấy', 'Tạp Vật'];
            itemsToShow.sort((a, b) => {
                const aIndex = typeOrder.indexOf(a.type) !== -1 ? typeOrder.indexOf(a.type) : typeOrder.length;
                const bIndex = typeOrder.indexOf(b.type) !== -1 ? typeOrder.indexOf(b.type) : typeOrder.length;
                return aIndex - bIndex;
            });

            itemsToShow.forEach(item => {
                const slot = document.createElement('div');
                slot.className = 'inventory-slot';

                slot.title = `${item.name}\nLoại: ${item.type}`;
                const iconClass = itemIconMap[item.type] || itemIconMap['Mặc Định'];
                slot.innerHTML = `<i class="fas ${iconClass} inventory-slot-icon"></i><span class="inventory-slot-name">${item.name}</span><span class="inventory-slot-quantity">${item.quantity}</span>`;

                slot.addEventListener('click', () => {
                    showItemDetail(item);
                });

                inventoryGrid.appendChild(slot);
            });
        }

        async function cleanupOrphanedData() {
            if (!currentState) return false;

            let changesMade = false;

            const livingEntityIds = new Set(['B1']);
            Object.keys(currentState['0'] || {}).forEach(id => livingEntityIds.add(id));
            Object.keys(currentState['7'] || {}).forEach(id => livingEntityIds.add(id));

            if (currentState['1']) {
                const itemIdsToDelete = [];
                Object.values(currentState['1']).forEach(item => {
                    const owner = item['8'];
                    if (owner && !livingEntityIds.has(owner)) {
                        itemIdsToDelete.push(item['0']);
                        changesMade = true;
                    }
                });
                if (itemIdsToDelete.length > 0) {
                    console.log(`Dọn dẹp: Đã xóa ${itemIdsToDelete.length} vật phẩm vô chủ.`);
                    itemIdsToDelete.forEach(id => delete currentState['1'][id]);
                }
            }

            if (currentState['8']) {
                const skillIdsToDelete = [];
                Object.values(currentState['8']).forEach(skill => {
                    const owner = skill['11'];
                    if (owner && !livingEntityIds.has(owner)) {
                        skillIdsToDelete.push(skill['0']);
                        changesMade = true;
                    }
                });
                if (skillIdsToDelete.length > 0) {
                    console.log(`Dọn dẹp: Đã xóa ${skillIdsToDelete.length} kỹ năng vô chủ.`);
                    skillIdsToDelete.forEach(id => delete currentState['8'][id]);
                }
            }

            if (currentState['0']) {
                Object.values(currentState['0']).forEach(char => {
                    if (char['13']) {
                        const originalRelations = char['13'];
                        const validRelations = originalRelations.split(';').filter(rel => {
                            const targetId = rel.split(':')[0];
                            return livingEntityIds.has(targetId);
                        }).join(';');

                        if (originalRelations !== validRelations) {
                            char['13'] = validRelations;
                            changesMade = true;
                            console.log(`Dọn dẹp: Đã cập nhật chuỗi quan hệ của nhân vật ${char['0']}.`);
                        }
                    }
                });
            }

            if (changesMade) {
                await saveCurrentState();
                syncStateFromTables();
                await showCustomAlert('Đã dọn dẹp dữ liệu vô chủ trong lưu trữ.');
            }
            return changesMade;
        }

        function maintainMacroSummaries(archive) {
            if (!archive.data.macro_summaries || archive.data.macro_summaries.length === 0) {
                return false;
            }

            const logs = archive.data.logs || [];
            const logIds = new Set(logs.map(l => l.id));
            const logCount = logs.length;

            const originalCount = archive.data.macro_summaries.length;

            const validSummaries = archive.data.macro_summaries.filter(summary => {
                const [start, end] = summary.range;
                if (end >= logCount) {
                    return false;
                }
                for (let i = start; i <= end; i++) {
                    if (!logs[i]) return false;
                }
                return true;
            });

            if (validSummaries.length < originalCount) {
                archive.data.macro_summaries = validSummaries;
                console.log(`Bảo trì Ký Ức Macro: Đã xóa ${originalCount - validSummaries.length} bản tóm tắt không còn hợp lệ do thay đổi lịch sử ghi chép.`);
                return true;
            }

            return false;
        }

