        async function validateAndSanitizeExistingData() {
            let dataWasChanged = false;
            try {
                let traits = await dbGet(CUSTOM_TRAITS_KEY) || [];
                if (traits.length > 0) {
                    const originalTraitsString = JSON.stringify(traits);

                    traits.forEach(trait => {
                        if (trait.bonus && typeof trait.bonus === 'object') {
                            let total = 0;
                            const sanitizedBonus = {};

                            for (const attr in trait.bonus) {
                                if (CREATION_CONFIG.ATTRIBUTES.hasOwnProperty(attr)) {
                                    const value = Math.max(-5, Math.min(5, parseInt(trait.bonus[attr]) || 0));
                                    sanitizedBonus[attr] = value;
                                    total += value;
                                }
                            }

                            if (total > 5) {
                                console.warn(`Hiệu chỉnh thiên phú tùy chỉnh [${trait.name}]: Tổng điều chỉnh thuộc tính (${total}) vượt quá giới hạn 5 điểm, đã đặt lại.`);
                                trait.bonus = {};
                            } else {
                                trait.bonus = sanitizedBonus;
                            }
                        }
                    });

                    if (JSON.stringify(traits) !== originalTraitsString) {
                        await dbSet(CUSTOM_TRAITS_KEY, traits);
                        dataWasChanged = true;
                    }
                }
            } catch (e) {
                console.error("Lỗi khi xác minh dữ liệu thiên phú tùy chỉnh:", e);
            }

            return dataWasChanged;
        }

