        async function reapplyYActions(targetLogId) {
            hideContextMenu();
            showLoading('Đang áp dụng lại lệnh...');

            try {
                const archive = await db.archives.get(currentArchiveName);
                if (!archive) throw new Error("Không tìm thấy lưu trữ hiện tại.");

                const logs = archive.data.logs;
                const targetLogIndex = logs.findIndex(log => log.id === targetLogId);

                if (targetLogIndex === -1 || logs[targetLogIndex].type !== 'ai') {
                    throw new Error("Nhật ký mục tiêu không phải là một phản hồi AI hợp lệ.");
                }

                let originalContent = logs[targetLogIndex].content;
                const branchMatch = originalContent.match(/<branches>([\s\S]*?)<\/branches>/);
                const branchContent = branchMatch ? branchMatch[0] : null;

                const allCommandsToParse = extractCommands(originalContent);
                if (allCommandsToParse.length === 0) {
                    await showCustomAlert('Tầng này không chứa bất kỳ lệnh nào có thể áp dụng.');
                    hideLoading();
                    return;
                }
                const allCommandsString = allCommandsToParse.join(' ');

                let stateObjectBeforeTurn = null;
                for (let i = targetLogIndex - 1; i >= 0; i--) {
                    if (logs[i].type === 'user' && logs[i].stateBeforeThisTurn) {
                        stateObjectBeforeTurn = JSON.parse(logs[i].stateBeforeThisTurn);
                        break;
                    }
                }
                if (!stateObjectBeforeTurn) {
                    throw new Error("Không tìm thấy khoảnh khắc trạng thái trước lượt này (stateBeforeThisTurn), không thể áp dụng lại một cách an toàn.");
                }

                const pureStateBeforeTurn = stateObjectBeforeTurn.currentState || stateObjectBeforeTurn;

                const { delta, smallSummary, largeSummary, parsingErrors, commandsString: fixedCommandsString } = parseTableEditCommands(allCommandsString);

                if (parsingErrors && parsingErrors.length > 0) {
                    const errorContent = parsingErrors.map(cmd => cmd.replace(/</g, '&lt;').replace(/>/g, '&gt;')).join('<br><br>');
                    await showCustomDialog({
                        title: 'Thông Báo Chặn Lệnh',
                        message: `
                            <p>Ngươi muốn làm gì!<br>Phát hiện định dạng lệnh sai, các lệnh sau đây chưa được thực thi:</p>
<div style="max-height: 200px; overflow-y: auto; background: rgba(0,0,0,0.2); border: 1px solid var(--separator-color); padding: 10px; border-radius: 4px; text-align: left; white-space: pre-wrap; word-break: break-all; font-family: monospace;">
${errorContent}
</div>
`,
                        buttons: [{ text: 'Xác Nhận', value: () => true }]
                    });
                }

                if (fixedCommandsString !== allCommandsString) {
                    console.log("Phát hiện sửa chữa khi áp dụng lại lệnh, đang cập nhật nội dung nhật ký...");
                    const actionsRegex = /<y_actions>[\s\S]*?<\/y_actions>/;
                    if (actionsRegex.test(originalContent)) {
                        originalContent = originalContent.replace(actionsRegex, `<y_actions>${fixedCommandsString}</y_actions>`);
                    } else {
                        console.warn("Không thể tìm thấy khối y_actions trong tin nhắn gốc để thay thế các lệnh đã được sửa chữa.");
                    }
                }

                const changesResult = await applyChanges(pureStateBeforeTurn, delta);
                let newState = await checkAndApplyPlayerLevelUp(pureStateBeforeTurn, changesResult.state);

                const attributePoints = stateObjectBeforeTurn.attributePoints || await dbGet(`ATTRIB_POINTS_${currentArchiveName}`) || 0;

                const stateToSnapshot = {
                    ...(archive.data.state || {}),
                    currentState: newState,
                    attributePoints: attributePoints
                };

                logs[targetLogIndex].content = originalContent;
                logs[targetLogIndex].stateSnapshot = JSON.stringify(stateToSnapshot);
                if (smallSummary !== null) {
                    logs[targetLogIndex].smallSummary = smallSummary;
                }
                if (largeSummary !== null) {
                    logs[targetLogIndex].largeSummary = largeSummary;
                }

                currentState = newState;
                archive.data.state.currentState = newState;
                if (archive.data.state) {
                    archive.data.state.attributePoints = attributePoints;
                }

                await db.archives.put(archive);

                const messageElement = mainContentArea.querySelector(`[data-log-id="${targetLogId}"]`);
                if (messageElement) {
                    const newLogElement = createLogEntryElement(logs[targetLogIndex], 'ai');
                    messageElement.replaceWith(newLogElement);
                }

                syncStateFromTables();
                updateAvatar(currentPlayerData);
                checkPlayerDeath();

                hideLoading();
                await showCustomAlert('Lệnh đã được áp dụng lại thành công, trạng thái trò chơi và các tóm tắt liên quan đã được cập nhật！');

                if (branchContent) {
                    const optionRegex = /\[(.*?)\]/g;
                    const allOptions = [];
                    let option;
                    while ((option = optionRegex.exec(branchContent)) !== null) {
                        allOptions.push(option[1]);
                    }
                    updateBranchingOptions(allOptions);
                } else {
                    updateBranchingOptions([]); 
                }

            } catch (error) {
                hideLoading();
                await showCustomAlert(`Thao tác thất bại: ${error.message}`);
            }
        }

        async function openCacheManager() {
            const calculateSize = (data) => data ? new Blob([JSON.stringify(data)]).size : 0;

            const updateCacheItem = async (elementId, data) => {
                const size = calculateSize(data);
                const el = document.getElementById(elementId);
                if (el) el.textContent = `${(size / 1024).toFixed(2)} KB`;
            };

            const archivesData = await db.archives.toArray();
            const archivesDataSize = archivesData.reduce((acc, archive) => acc + calculateSize(archive), 0);
            document.getElementById('archives-data-size').textContent = `${(archivesDataSize / 1024).toFixed(2)} KB`;

            await updateCacheItem('summary-settings-size', await dbGet(SUMMARY_CONFIG_KEY));
            await updateCacheItem('regex-settings-size', await dbGet(REGEX_CONFIG_KEY));
            await updateCacheItem('traits-size', await dbGet(CUSTOM_TRAITS_KEY));
            await updateCacheItem('bonded-chars-size', await dbGet(CUSTOM_BONDED_CHARS_KEY));
            await updateCacheItem('custom-births-size', await dbGet(CUSTOM_BIRTHS_KEY));
            await updateCacheItem('custom-races-size', await dbGet(CUSTOM_RACES_KEY));
            await updateCacheItem('custom-classes-size', await dbGet(CUSTOM_CLASSES_KEY));

            const allSettings = await db.settings.toArray();
            const playerAvatars = allSettings.filter(s => s.key.startsWith(CUSTOM_AVATAR_KEY));
            const npcAvatars = allSettings.filter(s => s.key.startsWith(NPC_AVATARS_KEY));
            const playerAvatarsSize = playerAvatars.reduce((acc, avatar) => acc + calculateSize(avatar.value), 0);
