        function showOverlaySafely(overlayElement, contentUpdateCallback) {
            const modalElement = overlayElement.querySelector('.modal');
            if (!modalElement) return;

            const isAlreadyVisible = overlayElement.classList.contains('visible');

            if (contentUpdateCallback) {
                contentUpdateCallback();
            }

            if (!isAlreadyVisible) {
                overlayElement.style.transition = 'none';
                modalElement.style.transition = 'none';

                requestAnimationFrame(() => {
                    requestAnimationFrame(() => {
                        overlayElement.style.transition = '';
                        modalElement.style.transition = '';
                        overlayElement.classList.add('visible');
                    });
                });
            }
        }

        function showCustomDialog(options) {
            return new Promise((resolve) => {
                const { title, message, inputs = [], buttons } = options;

                const modal = document.getElementById('custom-dialog-modal');

                let inputsHtml = '';
                if (inputs.length > 0) {
                    inputsHtml = inputs.map(input => {
                        const commonAttrs = `id="dialog-input-${input.id}" class="styled-input" placeholder="${input.placeholder || ''}"`;
                        if (input.type === 'textarea') {
                            return `
                                <div class="custom-input-group" style="background: none; padding: 0; margin-top: 10px; text-align: left;">
                                    <label for="dialog-input-${input.id}">${input.label}</label>
                                    <textarea ${commonAttrs} rows="3" style="width: 100%; resize: vertical;">${input.defaultValue || ''}</textarea>
                                </div>
                            `;
                        }
                        return `
                            <div class="custom-input-group" style="background: none; padding: 0; margin-top: 10px; text-align: left;">
                                <label for="dialog-input-${input.id}">${input.label}</label>
                                <input type="${input.type || 'text'}" ${commonAttrs} value="${input.defaultValue || ''}" style="width: 100%;">
                            </div>
                        `;
                    }).join('');
                }

                modal.innerHTML = `
                    <h4 id="custom-dialog-title">${title}</h4>
                    <div class="modal-content">
                        <p id="custom-dialog-message">${message}</p>
                        ${inputsHtml}
                    </div>
                    <div id="custom-dialog-buttons" class="modal-footer"></div>
                `;

                const buttonsEl = modal.querySelector('#custom-dialog-buttons');

                buttons.forEach(btnConfig => {
                    const button = document.createElement('button');
                    button.textContent = btnConfig.text;
                    button.className = 'major-action-button';
                    if (btnConfig.style === 'danger') {
                        button.style.borderColor = '#e57373';
                        button.style.color = '#e57373';
                    }
                    button.onclick = () => {
                        customDialogOverlay.classList.remove('visible', 'confirm-dialog-overlay');
                        let values = {};
                        if (inputs.length > 0) {
                            inputs.forEach(input => {
                                values[input.id] = modal.querySelector(`#dialog-input-${input.id}`).value;
                            });
                        }
                        resolve(btnConfig.value(values));
                    };
                    buttonsEl.appendChild(button);
                });

                customDialogOverlay.classList.add('visible', 'confirm-dialog-overlay');
                if (inputs.length > 0) {
                     modal.querySelector(`#dialog-input-${inputs[0].id}`).focus();
                }
            });
        }

