        function updateAllMapScales(container = document) {
            const globalScale = parseFloat(document.documentElement.style.getPropertyValue('--panel-scale') || '1.0');

            const pannables = container.querySelectorAll('.map-pannable');
            pannables.forEach(pannable => {
                const internalScale = parseFloat(pannable.dataset.scale) || 1;
                const finalVisualScale = internalScale * globalScale;
                const markerScale = 1 / finalVisualScale;
                pannable.querySelectorAll('.map-location-marker, .map-character-marker, .map-edit-vertex-html, .map-query-marker').forEach(marker => {
                    marker.style.setProperty('--map-marker-scale', markerScale);
                });

                const baseStrokeWidth = 1.0;
                const scaleDampener = Math.sqrt(finalVisualScale);

                pannable.querySelectorAll('.map-svg-layer path, .map-svg-layer polygon, .map-svg-layer polyline').forEach(el => {
                    const isMarchingAnts = el.classList.contains('highlight') || el.classList.contains('selectable-parent');
                    const multiplier = isMarchingAnts ? 1.8 : 1;
                    const finalStrokeWidth = (baseStrokeWidth * multiplier) / scaleDampener;
                    el.style.strokeWidth = `${finalStrokeWidth}px`;
                    if (isMarchingAnts) {
                        el.style.strokeDasharray = `${8 / scaleDampener}, ${4 / scaleDampener}`;
                    }
                });
            });
        }

        function updateMapLOD(pannable, scale) {
            if (!pannable) return;

            const applyLOD = (selector, config) => {
                pannable.querySelectorAll(selector).forEach(el => {
                    if (scale >= config.minScale && scale <= config.maxScale) {
                        el.classList.remove('hidden');
                    } else {
                        el.classList.add('hidden');
                    }
                });
            };

            const landmarks = pannable.querySelectorAll('.map-location-marker');
            landmarks.forEach(marker => {
                const dot = marker.querySelector('.dot');
                const label = marker.querySelector('.label');

                if (dot) {
                    if (scale >= MAP_LOD_CONFIG.landmarkDot.minScale && scale <= MAP_LOD_CONFIG.landmarkDot.maxScale) {
                        dot.classList.remove('hidden');
                    } else {
                        dot.classList.add('hidden');
                    }
                    if (label) {
                        if (scale >= MAP_LOD_CONFIG.landmarkLabel.minScale && scale <= MAP_LOD_CONFIG.landmarkLabel.maxScale) {
                            label.classList.remove('hidden');
                        } else {
                            label.classList.add('hidden');
                        }
                    }
                } else if (label) {
                    const isSubRegion = pannable.querySelector(`.sub-region-poly[data-id="${marker.dataset.id}"]`) !== null;
                    const config = isSubRegion ? MAP_LOD_CONFIG.subRegionLabel : MAP_LOD_CONFIG.mainRegionLabel;
                    if (scale >= config.minScale && scale <= config.maxScale) {
                        label.classList.remove('hidden');
                    } else {
                        label.classList.add('hidden');
                    }
                }
            });
        }

