			if (inventorySelectionMode !== 'none') {
				exitSelectionMode();
			}

			const CATEGORIES = {
				'Tất Cả': [],
				'Trang Bị': ['Vũ Khí', 'Giáp', 'Phụ Kiện', 'Thánh Vật'],
				'Vật Phẩm Tiêu Hao': ['Vật Phẩm Tiêu Hao'],
				'Cuộn Giấy': ['Cuộn Giấy'],
				'Nguyên Liệu': ['Nguyên Liệu'],
				'Vật Phẩm Quan Trọng': ['Vật Phẩm Quan Trọng'],
				'Vật Phẩm Khác': ['Tạp Vật']
			};

			let activeMainCat = 'Tất Cả';
			let activeSubCat = 'Tất Cả';

			const mainCatsContainer = document.getElementById('inventory-viewer-main-cats');
			const subCatsContainer = document.getElementById('inventory-viewer-sub-cats');
			const searchInput = document.getElementById('inventory-search-input');
			searchInput.value = ''; // Xóa nội dung tìm kiếm cũ

			function renderItems() {
				const grid = document.getElementById('inventory-viewer-grid');
				grid.innerHTML = '';
				const searchTerm = searchInput.value.toLowerCase();

				let itemsToDisplay = [...inventoryItems];

				// Lọc theo danh mục chính
				if (activeMainCat !== 'Tất Cả' && CATEGORIES[activeMainCat]) {
					const typesInMainCat = CATEGORIES[activeMainCat];
					// Nếu danh mục chính có danh mục con, lọc dựa trên danh mục con đang hoạt động
					if (typesInMainCat.length > 1 && activeSubCat !== 'Tất Cả') {
						 itemsToDisplay = itemsToDisplay.filter(item => item.type === activeSubCat);
					} else if (typesInMainCat.length > 0) {
						 itemsToDisplay = itemsToDisplay.filter(item => typesInMainCat.includes(item.type));
					}
				}

				// Lọc theo từ khóa tìm kiếm
				if (searchTerm) {
					itemsToDisplay = itemsToDisplay.filter(item => item.name.toLowerCase().includes(searchTerm));
				}

				itemsToDisplay.forEach(item => {
					const slot = document.createElement('div');
					slot.className = `inventory-viewer-slot ${itemsToDelete[item.id] ? 'selected' : ''}`;
					slot.dataset.itemId = item.id;
					// Lưu trữ toàn bộ dữ liệu vật phẩm để dễ dàng sao chép
					slot.dataset.itemData = JSON.stringify(item); 

					const iconClass = itemIconMap[item.type] || itemIconMap['Mặc Định'];
					slot.innerHTML = `
						<i class="fas ${iconClass} inventory-slot-icon"></i>
						<span class="inventory-slot-name">${item.name}</span>
						<span class="item-value">${item.value || 0} <i class="fas fa-coins"></i></span>
						<span class="inventory-slot-quantity">${item.quantity}</span>
						<div class="delete-quantity-input-container">
							<input type="number" min="1" max="${item.quantity}" value="${itemsToDelete[item.id] || 1}" class="delete-quantity-input">
						</div>
					`;

					const quantityInput = slot.querySelector('.delete-quantity-input');

					quantityInput.addEventListener('click', e => e.stopPropagation()); 

					quantityInput.addEventListener('input', () => {
						let val = parseInt(quantityInput.value);
						const max = parseInt(quantityInput.max);
						if (isNaN(val) || val < 1) val = 1;
						if (val > max) val = max;
						quantityInput.value = val;
						if (itemsToDelete[item.id]) {
							itemsToDelete[item.id] = val;
						}
					});

					slot.addEventListener('click', () => {
						if (inventorySelectionMode === 'copy' || inventorySelectionMode === 'delete') {
							slot.classList.toggle('selected');
							if (inventorySelectionMode === 'delete') {
								if (slot.classList.contains('selected')) {
									itemsToDelete[item.id] = parseInt(quantityInput.value);
								} else {
									delete itemsToDelete[item.id];
								}
							}
						} else {
							showItemDetail(item);
						}
					});
					grid.appendChild(slot);
				});
			}

