		function makeElementCopyable(element, textToCopy) {
			if (!element) return;

			element.style.cursor = 'pointer';
			element.title = 'Nhấp để sao chép';

			if (element.copyListener) {
				element.removeEventListener('click', element.copyListener);
			}

			element.copyListener = async (e) => {
				e.stopPropagation();
				try {
					await navigator.clipboard.writeText(textToCopy);

					const oldFeedback = element.querySelector('.copy-feedback');
					if (oldFeedback) oldFeedback.remove();

					const feedback = document.createElement('span');
					feedback.textContent = ' Đã copy!';
					feedback.className = 'copy-feedback';
					feedback.style.color = '#66bb6a'; // Màu xanh lá cây
					feedback.style.fontSize = '0.8em';
					feedback.style.fontStyle = 'italic';
					feedback.style.display = 'inline';
					element.appendChild(feedback);

					setTimeout(() => {
						feedback.remove();
					}, 1500); // Tự động xóa sau 1.5 giây

				} catch (err) {
					console.error('Sao chép thất bại:', err);
				}
			};

			element.addEventListener('click', element.copyListener);
		}	

