		function parseGameDate(dateString) {
			const match = dateString.match(/Năm (\d{4}) Mùa .* \(Tháng (\d{1,2})\) Ngày (\d{1,2})/);
			if (match) {
				const [, year, month, day] = match;
				return new Date(parseInt(year), parseInt(month) - 1, parseInt(day));
			}
			return null;
		}

		async function handleAutomaticAging() {
			const timeRow = (currentState['4'] || [])[0];
			if (!timeRow || !timeRow['0']) return false;

			const timeString = timeRow['0'];
			const yearMatch = timeString.match(/Năm (\d{4})/);
			if (!yearMatch) return false;

			const currentYear = parseInt(yearMatch[1]);

			if (lastProcessedYear === null) {
				lastProcessedYear = currentYear;
				return false;
			}

			if (currentYear > lastProcessedYear) {
				const ageIncrease = currentYear - lastProcessedYear;
				let charactersAged = [];

				Object.values(currentState['0'] || {}).forEach(charRow => {
					const currentAge = parseInt(charRow['5']);
					if (!isNaN(currentAge)) {
						charRow['5'] = (currentAge + ageIncrease).toString();
						charactersAged.push(`${(charRow['1'] || '|').split('|')[0]}`);
					}
				});

				lastProcessedYear = currentYear;
				if (charactersAged.length > 0) {
					showDanmaku(`Năm tháng thoi đưa, ${charactersAged.length} nhân vật đã thêm tuổi mới.`, 'world');
					await saveCurrentState();
					return true;
				}
			}
			return false;
		}

		async function checkAndTriggerNPCBackgroundActivity() {
			const timeRow = (currentState['4'] || [])[0];
			if (!timeRow || !timeRow['0']) return;
			if (!currentState['0'] || Object.keys(currentState['0']).length <= 1) return;

			const fullTimeString = timeRow['0'].split('/')[0].trim();
			const currentDate = parseGameDate(fullTimeString);
			if (!currentDate) return;

			if (!timeRow['1'] || !timeRow['2']) {
				const datePart = fullTimeString.match(/Năm \d{4} Mùa .* \(Tháng \d{1,2}\) Ngày \d{1,2}/)[0];
				timeRow['1'] = datePart;
				timeRow['2'] = fullTimeString;
				await saveCurrentState();
				return;
			}

			const prevTrainingDate = parseGameDate(timeRow['1']);
			const prevActivityTime = new Date(timeRow['2'].replace(/Năm (\d{4}) Mùa .* \(Tháng (\d{1,2})\) Ngày (\d{1,2})/, '$1-$2-$3'));
			const currentDateTime = new Date(fullTimeString.replace(/Năm (\d{4}) Mùa .* \(Tháng (\d{1,2})\) Ngày (\d{1,2})/, '$1-$2-$3'));

			const daysPassed = prevTrainingDate ? Math.floor((currentDate - prevTrainingDate) / (1000 * 60 * 60 * 24)) : 0;
			const minutesPassed = prevActivityTime ? (currentDateTime - prevActivityTime) / (1000 * 60) : 0;

			let hasAnyStateChange = false;
			const leveledUpNpcs = [];

			// 1. Xử lý tập luyện và thăng cấp (nếu qua ngày mới)
			if (daysPassed >= 1) {
				for (const npcId in currentState['0']) {
					if (npcId === 'B1') continue;
					const npcRow = currentState['0'][npcId];
					const levelUpInfo = handleNpcLeveling(npcRow, daysPassed);
					if (levelUpInfo) {
						leveledUpNpcs.push(levelUpInfo);
						hasAnyStateChange = true;
					}
				}
				if (leveledUpNpcs.length > 0) {
					const commandText = `${getForcefulCommandPrefix()} [Tự Động Rèn Luyện] Đã trôi qua ${daysPassed} ngày, các NPC sau đã thăng cấp:\n${leveledUpNpcs.map(info => `- ${info.name} (ID: ${info.id}) đã lên Lv.${info.newLevel}, nhận được ${info.pointsToDistribute} điểm thuộc tính.`).join('\n')}\n\nQuy tắc thăng cấp Yêu cầu AI: Phân phối điểm thuộc tính vào cột 11; nâng cấp kỹ năng hiện có (cột 4); có thể thêm kỹ năng mới (y_insert) hoặc vật phẩm/trang bị mới (y_insert) phù hợp với cấp độ mới.`;
					addAction('npc_level_up', commandText, {}, true);
				}
				timeRow['1'] = fullTimeString.match(/Năm \d{4} Mùa .* \(Tháng \d{1,2}\) Ngày \d{1,2}/)[0];
			}

			// 2. Xử lý hoạt động nền
			let npcsToUpdateForActivity = [];
			if (minutesPassed >= 60) { // Trên 1 tiếng, cập nhật tất cả
				npcsToUpdateForActivity = Object.values(currentState['0']).filter(npc => npc['0'] !== 'B1');
			} else if (minutesPassed > 5) { // Trên 5 phút, chỉ cập nhật NPC vắng mặt
				npcsToUpdateForActivity = Object.values(currentState['0']).filter(npc => {
					if (npc['0'] === 'B1') return false;
					const booleans = parseRemarksString(npc['20'] || '');
					return booleans.isPresent === 'false';
				});
			}

			if (npcsToUpdateForActivity.length > 0) {
				const timeString = `${Math.round(minutesPassed)} phút`;
				const npcList = npcsToUpdateForActivity.map(npc => `${(npc['1']||'|').split('|')[0]} (ID: ${npc['0']})`).join(', ');
				const command = `${getForcefulCommandPrefix()} [Hoạt Động Nền] Đã trôi qua ${timeString}. Yêu cầu AI mô phỏng hoạt động nền cho các NPC sau: ${npcList}. Cập nhật các cột: 4 (trạng thái), 12 (tâm tư), 13 (quan hệ), 15 (thiện cảm), 16 (hành động/vị trí), 20 (tọa độ), 25 (hiệu ứng), 27 (trang phục). NPC có thể nhận vật phẩm mới (y_insert) và trang bị chúng (y_update).`;
				addAction('npc_background_activity', command, {}, true);
				timeRow['2'] = fullTimeString;
				hasAnyStateChange = true;
			}

			if (hasAnyStateChange) {
				await saveCurrentState();
			}
		}		

		function handleNpcLeveling(npcRow, daysToProcess) {
			let currentLevel = parseInt(npcRow['9'] || '1');
			let currentXp = parseInt(npcRow['17'] || '0');
			const oldLevel = currentLevel;

			const booleans = parseRemarksString(npcRow['20'] || '');
			const aptitude = booleans.aptitude || 'D';
			const aptitudeModifier = APTITUDE_MODIFIERS[aptitude] || 1.0;

			for (let day = 0; day < daysToProcess; day++) {
				let xpNeededForNextLevel = calculateXPForLevel(currentLevel);
				const dailyXpGainPercent = (Math.random() * 4 + 1) / 100; // 1% to 5%
				const randomFactor = 0.8 + Math.random() * 0.4; // 0.8 to 1.2
				const dailyXpGain = Math.round(xpNeededForNextLevel * dailyXpGainPercent * aptitudeModifier * randomFactor);

				currentXp += dailyXpGain;

				while (currentXp >= xpNeededForNextLevel && currentLevel < 60) {
					currentXp -= xpNeededForNextLevel;
					currentLevel++;
					xpNeededForNextLevel = calculateXPForLevel(currentLevel);
				}
			}

			if (currentLevel > oldLevel) {
				const oldPool = getValidPointPool(oldLevel);
				const newPool = getValidPointPool(currentLevel);
				const pointsToDistribute = newPool.max - oldPool.max;

				npcRow['9'] = currentLevel.toString();
				npcRow['17'] = currentXp.toString();

				// Cập nhật lại HP/MP cho NPC
				recalculateAndCorrectNpcStats(npcRow, true); 

				return {
					id: npcRow['0'],
					name: (npcRow['1'] || '|').split('|')[0],
					oldLevel: oldLevel,
					newLevel: currentLevel,
					pointsToDistribute: pointsToDistribute
				};
			} else if (parseInt(npcRow['17']) !== currentXp) {
				npcRow['17'] = currentXp.toString();
			}

			return null;
		}		
