		async function applyLorebookSetting(choice, showAlert = false) {
			const lorebookComments = ['📌COT', '📌Nhấn Mạnh Định Dạng'];

			const shouldBeEnabled = choice === 'no';

			if (!window.parent || !window.parent.TavernHelper) {
				if (showAlert) await showCustomAlert('Không thể truy cập TavernHelper của cửa sổ cha. Không thể thay đổi Lorebook.');
				console.warn("Không thể truy cập TavernHelper của cửa sổ cha, bỏ qua việc thay đổi Lorebook.");
				return;
			}

			try {
				const primaryLorebook = await window.parent.TavernHelper.getCurrentCharPrimaryLorebook();
				if (!primaryLorebook) {
					if (showAlert) await showCustomAlert('Không tìm thấy Lorebook chính của nhân vật hiện tại.');
					return;
				}

				const entries = await window.parent.TavernHelper.getLorebookEntries(primaryLorebook);

				const targetEntries = entries.filter(e => lorebookComments.includes(e.comment));

				if (targetEntries.length === 0) {
					if (showAlert) await showCustomAlert(`Không tìm thấy bất kỳ lorebook nào có ghi chú: ${lorebookComments.join(', ')}.`);
					return;
				}

				const entriesToUpdate = [];
				targetEntries.forEach(entry => {
					if (entry.enabled !== shouldBeEnabled) {
						entry.enabled = shouldBeEnabled;
						entriesToUpdate.push(entry);
					}
				});

				if (entriesToUpdate.length > 0) {
					await window.parent.TavernHelper.setLorebookEntries(primaryLorebook, entriesToUpdate);
				}

				if (showAlert) {
					const status = shouldBeEnabled ? 'bật' : 'tắt';
					const loreNames = targetEntries.map(e => `'${e.comment}'`).join(' và ');
					await showCustomAlert(`Đã ${status} các lore: ${loreNames}. Chúc bạn chơi vui vẻ.`);
				}
			} catch (e) {
				if (showAlert) await showCustomAlert(`Lỗi khi cập nhật Lorebook: ${e.message}`);
				console.error("Lỗi khi cập nhật Lorebook:", e);
			}
		}

