			currentAvatarContext = context;

			const result = await showCustomDialog({
				title: "Thay Đổi Chân Dung",
				message: "Bạn muốn chọn ảnh từ đâu?",
				buttons: [
					{ text: 'Tải Ảnh Từ Máy', value: () => 'upload' },
					{ text: 'Chọn Ảnh Online', value: () => 'online' }
				]
			});

			if (result === 'upload') {
				const input = context.type === 'npc' ? document.getElementById('npc-avatar-upload-input') : document.getElementById('avatar-upload-input');
				input.click();
			} else if (result === 'online') {
				openOnlineAvatarPicker(context);
			}
		}	

		function openOnlineAvatarPicker(context) {
			const overlay = document.getElementById('online-avatar-picker-overlay');
			const tabs = document.getElementById('avatar-picker-tabs');
			const grid = document.getElementById('avatar-picker-grid');

			// Thiết lập sự kiện cho các tab
			tabs.querySelectorAll('.tab-button').forEach(tab => {
				tab.addEventListener('click', () => {
					tabs.querySelectorAll('.tab-button').forEach(t => t.classList.remove('active'));
					tab.classList.add('active');
					fetchAndDisplayAvatars(tab.dataset.tab, grid, context);
				});
			});

			// Mở tab mặc định
			fetchAndDisplayAvatars('nam', grid, context);
			overlay.classList.add('visible');
		}

		async function fetchAndDisplayAvatars(tabName, gridContainer, context) {
			gridContainer.innerHTML = '<p style="grid-column: 1 / -1; text-align: center;">Đang tải danh sách ảnh...</p>';

			const usageMap = await buildAvatarUsageMap();
			let imageFiles = avatarCache[tabName];

			if (imageFiles) {
				renderAvatarGrid(imageFiles, gridContainer, context, usageMap);
				return;
			}

			try {
				const response = await fetch(GITHUB_AVATAR_URLS[tabName]);
				if (!response.ok) throw new Error(`Lỗi API GitHub: ${response.statusText}`);
				const files = await response.json();

				imageFiles = files
					.filter(file => file.type === 'file' && /\.(jpg|jpeg|png|gif|webp)$/i.test(file.name));

				avatarCache[tabName] = imageFiles; // Lưu mảng các object file vào cache
				renderAvatarGrid(imageFiles, gridContainer, context, usageMap); // Truyền mảng object file đi

			} catch (error) {
				gridContainer.innerHTML = `<p style="grid-column: 1 / -1; text-align: center; color: #e57373;">Không thể tải danh sách ảnh: ${error.message}</p>`;
				console.error("Lỗi khi lấy ảnh từ GitHub:", error);
			}
		}

		function renderAvatarGrid(imageFiles, gridContainer, context, usageMap) {
			gridContainer.innerHTML = '';
			let selectedThumbnail = null;

			imageFiles.forEach(file => {
				const thumbContainer = document.createElement('div');
				thumbContainer.className = 'avatar-thumbnail';

				const img = document.createElement('img');
				img.src = file.download_url;
				img.loading = 'lazy';
				thumbContainer.appendChild(img);

				// KIỂM TRA VÀ THÊM THẺ TÊN NHÂN VẬT
				const users = usageMap[file.name]; // users bây giờ là một mảng
				if (users && users.length > 0) {
					// Chỉ hiển thị tên đầu tiên, nếu có nhiều hơn thì thêm "+X"
					const displayName = users.length > 1 ? `${users[0]} +${users.length - 1}` : users[0];
					const fullTitle = `Đang được dùng bởi: ${users.join(', ')}`;

					const tag = document.createElement('div');
					tag.className = 'avatar-in-use-tag';
					tag.textContent = displayName;
					tag.title = fullTitle;
					thumbContainer.appendChild(tag);
				}

				gridContainer.appendChild(thumbContainer);

				const clearActions = () => {
					gridContainer.querySelectorAll('.avatar-actions').forEach(el => el.remove());
					if (selectedThumbnail) {
						selectedThumbnail.classList.remove('selected');
					}
				};

				// Hàm xử lý chung cho cả click và dblclick
				const handleSelection = async () => {
					if (users && users.length > 0) {
						let message;
						const userList = users.join(', ');
						if (users.length === 1) {
							message = `Nhân vật [${userList}] đang sử dụng ảnh này, bạn vẫn muốn chọn?`;
						} else {
							message = `Các nhân vật [${userList}] đang sử dụng ảnh này, bạn vẫn muốn chọn?`;
						}

						const confirmed = await showCustomConfirm(message, "Xác Nhận Lựa Chọn");
						if (!confirmed) {
							return; // Người dùng hủy, không làm gì cả
						}
					}

					// Nếu ảnh không được sử dụng, hoặc người dùng đã xác nhận, thì áp dụng avatar
					applyAvatar(file, context);
				};

				// Nhấp một lần
				thumbContainer.addEventListener('click', () => {
					clearActions();
					selectedThumbnail = thumbContainer;
					thumbContainer.classList.add('selected');

					const actionsDiv = document.createElement('div');
					actionsDiv.className = 'avatar-actions';

					const viewBtn = document.createElement('button');
					viewBtn.innerHTML = '<i class="fas fa-eye"></i>';
					viewBtn.title = "Xem";
					viewBtn.onclick = (e) => {
						e.stopPropagation();
						showAvatarPreview(file.download_url);
					};

					const selectBtn = document.createElement('button');
					selectBtn.innerHTML = '<i class="fas fa-check"></i>';
					selectBtn.title = "Chọn";
					selectBtn.onclick = (e) => {
						e.stopPropagation();
						handleSelection(); // Gọi hàm xử lý chung
					};

					actionsDiv.appendChild(viewBtn);
					actionsDiv.appendChild(selectBtn);
					thumbContainer.appendChild(actionsDiv);
				});

				// Nhấp đúp
				thumbContainer.addEventListener('dblclick', async () => {
					clearActions();
					await handleSelection(); // Gọi hàm xử lý chung
				});
			});
		}

		function showAvatarPreview(imageUrl) {
			const overlay = document.getElementById('avatar-preview-overlay');
			const img = document.getElementById('avatar-preview-img');
			img.src = imageUrl;
			overlay.classList.add('visible');
		}

		async function applyAvatar(file, context) {
			try {
				const response = await fetch(file.download_url);
				const blob = await response.blob();
				const base64String = await new Promise((resolve, reject) => {
					const reader = new FileReader();
					reader.onloadend = () => resolve(reader.result);
					reader.onerror = reject;
					reader.readAsDataURL(blob);
				});

				const avatarDataToSave = {
					data: base64String,
					source: 'github',
					filename: file.name 
				};

				switch (context.type) {
					case 'creation':
						creationState.customAvatar = avatarDataToSave;
						await showCustomAlert("Chân Dung tùy chỉnh đã được cài đặt cho nhân vật mới!");
						break;
					case 'player':
						await dbSet(`${CUSTOM_AVATAR_KEY}_${currentArchiveName}`, avatarDataToSave);
						await updateAvatar(currentPlayerData);
						await showCustomAlert("Chân Dung người chơi đã được thay đổi!");
						break;
					case 'npc':
						let npcAvatars = await dbGet(`${NPC_AVATARS_KEY}_${currentArchiveName}`) || {};
						npcAvatars[context.id] = avatarDataToSave;
						await dbSet(`${NPC_AVATARS_KEY}_${currentArchiveName}`, npcAvatars);

						const char = characterDatabase[context.id];
						if (char) await updateNpcAvatar(char);
						await showCustomAlert("Chân Dung NPC đã được thay đổi!");
						break;
					case 'pet':
						let petAvatars = await dbGet(`${PET_AVATARS_KEY}_${currentArchiveName}`) || {};
						petAvatars[context.id] = avatarDataToSave;
						await dbSet(`${PET_AVATARS_KEY}_${currentArchiveName}`, petAvatars);

						const petData = currentState['7'][context.id];
						if (petData) await updatePetAvatar(petData);
						await showCustomAlert("Chân Dung đồng hành đã được thay đổi!");
						break;						
				}

				// Đóng tất cả các cửa sổ liên quan
				document.getElementById('online-avatar-picker-overlay').classList.remove('visible');
				document.getElementById('avatar-preview-overlay').classList.remove('visible');

			} catch (error) {
				console.error("Lỗi khi áp dụng avatar:", error);
				await showCustomAlert(`Lỗi khi áp dụng avatar: ${error.message}`);
			}
		}

		/**
		 * Ghi đè hàm xử lý tải lên cũ để tương thích với hệ thống context mới
		 */
		async function handleAvatarUpload(event) {
			const file = event.target.files[0];
			if (!file) {
				event.target.value = '';
				return;
			}
			const reader = new FileReader();
			reader.onload = async (e) => {
				try {
					// Sử dụng context đã được lưu khi người dùng chọn "Tải Ảnh Từ Máy"
					await applyAvatar(e.target.result, currentAvatarContext);
				} catch (err) {
					await showCustomAlert(`Xử lý avatar thất bại: ${err.message}`);
				} finally {
					event.target.value = '';
				}
			};
			reader.readAsDataURL(file);
		}		

