            document.getElementById('ctx-copy-btn').addEventListener('click', () => {
                if (!activeLogEntry) return;

                function copyTextToClipboard(text) {
                    if (navigator.clipboard && window.isSecureContext) {
                        return navigator.clipboard.writeText(text);
                    } else {
                        return new Promise((resolve, reject) => {
                            const textArea = document.createElement("textarea");
                            textArea.value = text;
                            textArea.style.position = "fixed";
                            textArea.style.top = "0";
                            textArea.style.left = "0";
                            textArea.style.opacity = "0";
                            document.body.appendChild(textArea);
                            textArea.focus();
                            textArea.select();
                            try {
                                const successful = document.execCommand('copy');
                                if (successful) {
                                    resolve();
                                } else {
                                    reject(new Error('Copy command was unsuccessful'));
                                }
                            } catch (err) {
                                reject(err);
                            }
                            document.body.removeChild(textArea);
                        });
                    }
                }

                let text = activeLogEntry.textContent;
                if (activeLogEntry.classList.contains('user')) { text = text.replace(/^> /, ''); }

                copyTextToClipboard(text)
                    .then(() => showCustomAlert('Tin nhắn đã được sao chép!'))
                    .catch(err => {
                        console.error('Sao chép thất bại:', err);
                        showCustomAlert('Sao chép thất bại');
                    });
                hideContextMenu();
            });
