            document.getElementById('save-prompt-injection-btn').addEventListener('click', savePromptInjectionSettings);

            const mapViewportContainer = document.getElementById('map-viewport-container');
            if (mapViewportContainer) {
                let dragStartX, dragStartY, isPotentialClick = false;
                let ignoreNextDrawClick = false;

                mapViewportContainer.addEventListener('mousedown', (e) => {
                    if ((currentMapEditMode === 'draw-subregion' && !isDrawing) || isDrawing) {
                        isPotentialClick = true;
                        dragStartX = e.clientX;
                        dragStartY = e.clientY;
                    }
                });

                mapViewportContainer.addEventListener('mousemove', (e) => {
                    if (isPotentialClick) {
                        const dx = e.clientX - dragStartX;
                        const dy = e.clientY - dragStartY;
                        if (Math.sqrt(dx * dx + dy * dy) > 10) {
                            isPotentialClick = false;
                        }
                    }
                });

                mapViewportContainer.addEventListener('mouseup', (e) => {
                    if (!isPotentialClick) return;
                    isPotentialClick = false;

                    const dx = e.clientX - dragStartX;
                    const dy = e.clientY - dragStartY;
                    if (Math.sqrt(dx * dx + dy * dy) > 10) {
                        return;
                    }

                    const pannable = document.getElementById('main-map-pannable');
                    const viewportRect = mapViewportContainer.getBoundingClientRect();
                    const scale = parseFloat(pannable.dataset.scale) || 1;
                    const panX = parseFloat(pannable.dataset.panX) || 0;
                    const panY = parseFloat(pannable.dataset.panY) || 0;
                    const clickInViewportX = e.clientX - viewportRect.left;
                    const clickInViewportY = e.clientY - viewportRect.top;
                    const worldX = (clickInViewportX - panX) / scale;
                    const worldY = (clickInViewportY - panY) / scale;
                    const x = (worldX / pannable.offsetWidth) * 100;
                    const y = (worldY / pannable.offsetHeight) * 100;
                    const clickedPoint = { x, y };

                    if (currentMapEditMode === 'draw-subregion' && !isDrawing) {
                        let selectedParent = null;
                        (currentLocationsData.mainRegions || []).forEach(region => {
                            if (isPointInPolygon(clickedPoint, region.points)) {
                                selectedParent = region;
                            }
                        });

                        if (selectedParent) {
                            document.body.classList.remove('selecting-parent-region-mode');
                            const polyEl = pannable.querySelector(`.main-region-poly[data-id="${selectedParent.id}"]`);
                            if (polyEl) polyEl.classList.add('highlight');

                            isDrawing = true;
                            currentDrawingPoints = [];
                            const editSvgLayer = document.getElementById('map-edit-svg-layer');
                            if (editSvgLayer) editSvgLayer.style.pointerEvents = 'auto';

                            const hue = Math.floor(Math.random() * 360);
                            window.currentDrawingContext = {
                                parent: selectedParent,
                                style: { fill: `hsla(${hue}, 70%, 50%, 0.3)`, stroke: `hsl(${hue}, 70%, 50%)` }
                            };

                            updateEditorUI();
                            drawOnEditLayer();
                        }
                        return;
                    }

                    if (isDrawing && (currentMapEditMode === 'draw-region' || currentMapEditMode === 'draw-subregion')) {
                        let finalX = x;
                        let finalY = y;
                        const snapPoint = findSnapPoint({ x: finalX, y: finalY });
                        if (snapPoint) {
                            finalX = snapPoint.x;
                            finalY = snapPoint.y;
                        }
                        currentDrawingPoints.push({ x: finalX, y: finalY });
                        drawOnEditLayer();
                    }
                });
            }
        }

        async function loadSummaryConfig() {
            const defaultConfig = {
                apiUrl: '', apiKey: '', apiModel: 'gpt-3.5-turbo',
                apiSource: 'parent',
                segmentedMemoryEnabled: true, segmentedChatLayers: 5, segmentedLargeSummaryStart: 25,
                macroSummaryPrompt: 'Yêu cầu tóm tắt lớn: <Request:Tạm dừng cốt truyện, lượt này không cần xuất ra nội dung cốt truyện. Vui lòng tóm tắt tất cả nội dung sau thành một đoạn văn mạch lạc, thống nhất, khách quan và súc tích theo dạng các ý chính. Tóm tắt phải tập trung vào các sự kiện cốt lõi, quyết định quan trọng và thay đổi trạng thái.>'
            };
            try {
                summaryConfig = await dbGet(SUMMARY_CONFIG_KEY) || defaultConfig;
                if (!summaryConfig.macroSummaryPrompt) {
                    summaryConfig.macroSummaryPrompt = defaultConfig.macroSummaryPrompt;
                }				
            } catch (e) {
                summaryConfig = defaultConfig;
            }
            document.getElementById('summary-api-url').value = summaryConfig.apiUrl || '';
            document.getElementById('summary-api-key').value = summaryConfig.apiKey || '';
            document.getElementById('summary-api-model').value = summaryConfig.apiModel || 'gpt-3.5-turbo';

			document.getElementById('macro-summary-prompt').value = summaryConfig.macroSummaryPrompt;

            const apiSource = summaryConfig.apiSource || 'custom';
            document.querySelector(`input[name="apiSource"][value="${apiSource}"]`).checked = true;
            document.getElementById('custom-api-settings').classList.toggle('hidden', apiSource !== 'custom');

            document.getElementById('segmented-memory-enabled-toggle').checked = summaryConfig.segmentedMemoryEnabled || false;
            document.getElementById('segmented-chat-layers').value = summaryConfig.segmentedChatLayers || 20;
            document.getElementById('segmented-large-summary-start').value = summaryConfig.segmentedLargeSummaryStart || 50;
        }

