        async function callParentApiForSummary(textToSummarize) {
            if (window.parent && window.parent.TavernHelper && typeof window.parent.TavernHelper.generate === 'function') {
                const tavernGenerateFunc = window.parent.TavernHelper.generate;
                const prompt = `${summaryConfig.prompt}\n\nSau đây là nội dung cần tóm tắt: \n${textToSummarize}`;
                const params = { user_input: prompt, should_stream: false, disable_extras: true };
                try {
                    const finalAiResponse = await tavernGenerateFunc(params);
                    return finalAiResponse.trim();
                } catch (e) {
                    console.error("TavernHelper.generate call for summary error:", e);
                    throw new Error('AI của cửa sổ cha tạo thất bại.');
                }
            } else {
                throw new Error('Không tìm thấy AI của cửa sổ cha (TavernHelper).');
            }
        }

        async function callSummaryApi(textToSummarize) {
            const thinkingMessage = addMessageToLog({ content: 'Đang yêu cầu trợ lý tóm tắt...' }, 'system');
            try {
                let summaryResult;
                if (summaryConfig.apiSource === 'parent') {
                    const prompt = `Yêu cầu tóm tắt lớn: <Request:Tạm dừng cốt truyện, lượt này không cần xuất ra nội dung cốt truyện. Vui lòng tóm tắt tất cả nội dung sau thành một đoạn văn mạch lạc, thống nhất, khách quan và súc tích theo dạng các ý chính. Tóm tắt phải tập trung vào các sự kiện cốt lõi, quyết định quan trọng và thay đổi trạng thái.>\n\n${textToSummarize}`;
                    summaryResult = await callParentApiForSummary(prompt);
                } else {
                    const { apiUrl, apiKey, apiModel } = summaryConfig;
                    if (!apiUrl || !apiModel) {
                        throw new Error('Cấu hình API tùy chỉnh không hoàn chỉnh, không thể tóm tắt.');
                    }
                    const finalPrompt = `Bạn là một trợ lý chịu trách nhiệm tạo ra các ghi chép về câu chuyện phiêu lưu. Vui lòng phân tích các ghi chép phiêu lưu sau đây và tóm tắt chúng dưới dạng các ý chính khách quan, súc tích tuyệt đối. Tóm tắt của bạn phải tập trung vào **sự kiện cốt lõi**. Vui lòng không thêm bất kỳ suy đoán hay ngôn ngữ mô tả nào.\n\n### Ghi Chép Phiêu Lưu\n${textToSummarize}\n\n### Tóm Tắt\n`;

                    const response = await fetch(apiUrl.replace('/chat/completions', '') + '/completions', {
                        method: 'POST',
                        headers: { 'Content-Type': 'application/json', 'Authorization': `Bearer ${apiKey}` },
                        body: JSON.stringify({
                            model: apiModel,
                            prompt: finalPrompt,
                            max_tokens: 1024,
                            temperature: 0.3,
                            stop: ["###"]
                        })
                    });
                    if (!response.ok) {
                        const errorData = await response.json();
                        throw new Error(`Yêu cầu API thất bại (${response.status}): ${errorData.error.message}`);
                    }
                    const data = await response.json();
                    summaryResult = data.choices[0].text;
                }
                if (thinkingMessage && thinkingMessage.parentNode) {
                    mainContentArea.removeChild(thinkingMessage);
                }
                return summaryResult;
            } catch (error) {
                if (thinkingMessage && thinkingMessage.parentNode) {
                    thinkingMessage.parentNode.removeChild(thinkingMessage);
                }
                await showCustomAlert(`Tóm tắt thất bại: ${error.message}`);
                console.error('Gọi API tóm tắt thất bại:', error);
                return null;
            }
        }

