            const archive = await db.archives.get(currentArchiveName);
            const logs = archive ? archive.data.logs : [];

            const physicalLogs = logs.filter(log => log.type !== MACRO_SUMMARY_TYPE);

            const defaultStartFloor = physicalLogs.length > 1 ? 2 : 1;
            const defaultEndFloor = physicalLogs.length;

            const dialogHtml = `
                <p>Vui lòng nhập phạm vi nhật ký trò chuyện cần tóm tắt sâu.</p>
                <p>Mở cài đặt trước tóm tắt để có hiệu quả tóm tắt tốt hơn.</p>
                <div style="display: flex; gap: 15px; align-items: center; margin-bottom: 20px;">
                    <input type="number" id="dialog-summary-start" class="styled-input" style="width: 80px;" value="${defaultStartFloor}" min="${defaultStartFloor}">
                    <span>Đến</span>
                    <input type="number" id="dialog-summary-end" class="styled-input" style="width: 80px;" value="${defaultEndFloor}" max="${defaultEndFloor}">
                </div>

                <div class="settings-section" style="padding: 10px; border-color: var(--primary-color);">
                    <h5 style="margin-top:0;">Chọn Nguồn Tóm Tắt</h5>
                    <label style="display: flex; gap: 10px; padding: 8px; border-radius: 4px; cursor: pointer;">
                        <input type="radio" name="summarySource" value="raw" checked>
                        <div>
                            <strong>Sử dụng nhật ký trò chuyện gốc (Độ chính xác cao nhất)</strong>
                            <small style="display:block; opacity: 0.7;">Nắm bắt mọi chi tiết, nhưng tốn nhiều Token và chậm.</small>
                        </div>
                    </label>
                    <label style="display: flex; gap: 10px; padding: 8px; border-radius: 4px; cursor: pointer;">
                        <input type="radio" name="summarySource" value="small_summary">
                        <div>
                            <strong>Sử dụng tóm tắt nhỏ hiện có (Cân bằng, khuyến nghị)</strong>
                            <small style="display:block; opacity: 0.7;">Lựa chọn tốt nhất giữa tốc độ và độ chính xác, phù hợp cho tóm tắt thông thường.</small>
                        </div>
                    </label>
                    <label style="display: flex; gap: 10px; padding: 8px; border-radius: 4px; cursor: pointer;">
                        <input type="radio" name="summarySource" value="large_summary">
                        <div>
                            <strong>Sử dụng tóm tắt lớn hiện có (Tốc độ cao nhất)</strong>
                            <small style="display:block; opacity: 0.7;">Tốc độ cực nhanh, tốn ít Token nhất, dùng để tinh chỉnh lại.</small>
                        </div>
                    </label>
                </div>
            `;

            const result = await showCustomDialog({
                title: 'Tạo Ký Ức Macro',
                message: dialogHtml,
                buttons: [
                    { text: 'Hủy Bỏ', value: () => null },
                    { text: 'Xác Nhận', value: () => {
                        const start = document.getElementById('dialog-summary-start').value;
                        const end = document.getElementById('dialog-summary-end').value;
                        const source = document.querySelector('input[name="summarySource"]:checked').value;
                        return { start, end, source };
                    }}
                ]
            });

            if (result === null || !result.start || !result.end) return;

            const startIndex = parseInt(result.start) - 1;
            const endIndex = parseInt(result.end) - 1;

            if (isNaN(startIndex) || isNaN(endIndex) || startIndex < 1 || endIndex >= physicalLogs.length || startIndex > endIndex) {
                await showCustomAlert('Phạm vi nhập không hợp lệ！Vui lòng đảm bảo tầng bắt đầu không nhỏ hơn 2 và phạm vi nằm trong nhật ký hợp lệ.');
