        function getPhysicalLogIndex(logs, targetLogId) {
            const physicalLogs = logs.filter(log => log.type !== MACRO_SUMMARY_TYPE);

            const index = physicalLogs.findIndex(log => log.id === targetLogId);

            return index !== -1 ? index + 1 : -1;
        }

        async function renderMacroSummaryList() {
            const listEl = document.getElementById('macro-summary-list');
            const archive = await db.archives.get(currentArchiveName);
            if (!archive || !archive.data) return;

            const logs = archive.data.logs || [];
            const macroSummaries = logs.filter(log => log.type === 'summary_macro');

            listEl.innerHTML = '';
            if (macroSummaries.length === 0) {
                listEl.innerHTML = '<p style="text-align:center; opacity:0.7;">Hiện không có Ký Ức Macro nào.</p>';
