            }
            const physicalLogs = logs.filter(log => log.type !== 'summary_macro');

            macroSummaries.forEach(summary => {
                const item = document.createElement('details');
                item.className = 'summary-list-item';
                const [startIdx, endIdx] = summary.range;

                const startLogPreview = physicalLogs[startIdx] ? getCleanTextFromLogContent(physicalLogs[startIdx].content).substring(0, 40) + '...' : 'Không Rõ(có thể đã bị xóa)';
                const endLogPreview = physicalLogs[endIdx] ? getCleanTextFromLogContent(physicalLogs[endIdx].content).substring(0, 40) + '...' : 'Không Rõ(có thể đã bị xóa)';

                item.innerHTML = `
                    <summary>
                        <div class="summary-header">
                            <strong>Ký Ức Macro: Tầng ${startIdx + 1} - ${endIdx + 1}</strong>
                            <div class="item-actions">
                                <button class="major-action-button edit-macro-summary-btn" data-id="${summary.id}" title="Chỉnh Sửa"><i class="fas fa-edit"></i></button>
                                <button class="major-action-button delete-macro-summary-btn" data-id="${summary.id}" title="Xóa" style="border-color: #e57373; color: #e57373;"><i class="fas fa-trash"></i></button>
                            </div>
                        </div>
                        <small class="summary-previews">
                            <span><strong>Bắt Đầu:</strong> ${startLogPreview}</span>
                            <span><strong>Kết Thúc:</strong> ${endLogPreview}</span>
