        async function handleDeleteMacroSummary(logId) {
            if (await showCustomConfirm('Bạn có chắc muốn xóa Ký Ức Macro này không？Các tóm tắt lớn và nhỏ trong khoảng tương ứng sẽ có hiệu lực trở lại.')) {
                const archive = await db.archives.get(currentArchiveName);
                archive.data.logs = archive.data.logs.filter(l => l.id !== logId);
                await db.archives.put(archive);
                await renderMacroSummaryList();
            }
