        async function executeSummary(startIndexInPhysical, endIndexInPhysical, sourceType = 'raw', physicalLogs) {
            let archive = await db.archives.get(currentArchiveName);
            let logs = archive ? archive.data.logs : [];

            const logsToSummarize = physicalLogs.slice(startIndexInPhysical, endIndexInPhysical + 1);
            const newRange = [startIndexInPhysical, endIndexInPhysical];

            const oldSummariesToDelete = logs.filter(log =>
                log.type === MACRO_SUMMARY_TYPE &&
                log.range[0] >= newRange[0] &&
                log.range[1] <= newRange[1]
            );

            if (oldSummariesToDelete.length > 0) {
                 const startFloor = startIndexInPhysical + 1;
                 const endFloor = endIndexInPhysical + 1;
                 if (!await showCustomConfirm(`Phạm vi bạn chọn (${startFloor}-${endFloor}) chứa ${oldSummariesToDelete.length} tóm tắt cũ nhỏ hơn. Có tiếp tục không?\n\nTiếp tục sẽ xóa những tóm tắt cũ này và tạo một tóm tắt mới lớn hơn.`)) {
                    return;
                 }
            }

            if (logsToSummarize.length === 0) {
                await showCustomAlert('Không có nhật ký nào để tóm tắt trong phạm vi đã chọn.');
                return;
            }

            const textToSummarize = logsToSummarize.map(log => {
                let contentToProcess = '';
                if (sourceType === 'large_summary') {
                    contentToProcess = log.largeSummary || getCleanTextFromLogContent(log.content || log.fullContent || '');
                } else if (sourceType === 'small_summary') {
                    contentToProcess = log.smallSummary || getCleanTextFromLogContent(log.content || log.fullContent || '');
                } else {
                    contentToProcess = getCleanTextFromLogContent(log.content || log.fullContent || '');
                }
                const role = log.type === 'user' ? 'Người Chơi' : 'AI';
                return `${role}: ${contentToProcess}`;
            }).join('\n');

            const summaryRequestPrompt = summaryConfig.macroSummaryPrompt || 'Yêu cầu tóm tắt lớn: <Request:Tạm dừng cốt truyện, lượt này không cần xuất ra nội dung cốt truyện. Vui lòng tóm tắt tất cả nội dung sau thành một đoạn văn mạch lạc, thống nhất, khách quan và súc tích theo dạng các ý chính. Tóm tắt phải tập trung vào các sự kiện cốt lõi, quyết định quan trọng và thay đổi trạng thái.>';

            const finalPrompt = `### 【Lịch Sử Ghi Chép】\n${textToSummarize}\n\n{{\setvar::Đầu Vào Người Chơi::${summaryRequestPrompt}}}\n\n### Đầu Vào Người Chơi: \n${summaryRequestPrompt}`;

            showLoading('Đang lưu trữ Ký Ức Vĩ Mô...');
            let summaryResultRaw = null;
            try {
                summaryResultRaw = await makeApiCall(finalPrompt);
            } catch (e) {
                hideLoading();
                await showCustomAlert(`Gọi API tóm tắt thất bại: ${e.message}`);
                return;
            }
            hideLoading();

            if (!summaryResultRaw) {
                await showCustomAlert('Tạo Ký Ức Vĩ Mô thất bại: AI không trả về nội dung tóm tắt hợp lệ.');
                return;
            }

            let summaryResult = summaryResultRaw;
            const yTextMatch = summaryResultRaw.match(/<y_text>([\s\S]*?)<\/y_text>/i);
            if (yTextMatch && yTextMatch[1]) {
                summaryResult = yTextMatch[1];
            } else {
                summaryResult = summaryResultRaw.replace(/<(?:y_actions|branches|think|thinking|tablethink)>[\s\S]*?<\/(?:y_actions|branches|think|thinking|tablethink)>/gi, '');
            }
            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = summaryResult;
            summaryResult = (tempDiv.textContent || tempDiv.innerText || '').trim();

            archive = await db.archives.get(currentArchiveName);
            logs = archive.data.logs;

            const logsToKeep = logs.filter(log => !oldSummariesToDelete.some(s => s.id === log.id));
            const newSummaryLog = {
                id: crypto.randomUUID(),
                timestamp: new Date().toISOString(),
                type: MACRO_SUMMARY_TYPE,
                content: summaryResult.trim(),
                range: newRange
            };

            archive.data.logs = [...logsToKeep, newSummaryLog].sort((a, b) => {
                const getIndex = (log) => {
                    const originalIndex = logs.findIndex(l => l.id === log.id);
                    return log.range ? log.range[0] : (originalIndex > -1 ? originalIndex : Infinity);
                };
                return getIndex(a) - getIndex(b);
            });

            await db.archives.put(archive);
            loadChatHistory(archive.data.logs);
            await showCustomAlert('Ký Ức Vĩ Mô đã được tạo/cập nhật thành công！');
        }

        async function createNewArchive() {
            if (await showCustomConfirm('Bạn có chắc muốn bắt đầu một cuộc đời mới không? Thao tác này sẽ rời khỏi giao diện quản lý lưu trữ hiện tại.')) {
                creationScreen.classList.remove('hidden');
                splashScreen.classList.add('hidden');
                gamePanel.classList.remove('hidden');
                startCharacterCreation();
            }
        }

        async function renameArchive(oldName) {
            if (!oldName) return;
            const newName = await showCustomPrompt("Vui lòng nhập tên lưu trữ mới:", oldName);
            if (newName && newName !== oldName) {
                const existingNew = await db.archives.get(newName);
                if (existingNew) {
                    await showCustomAlert("Lưu trữ với tên này đã tồn tại！");
                    return;
                }

                const oldArchive = await db.archives.get(oldName);
                if (oldArchive) {
                    await db.archives.delete(oldName);
                    oldArchive.name = newName;
                    await db.archives.add(oldArchive);
                }

                if (currentArchiveName === oldName) {
                    currentArchiveName = newName;
                    await dbSet(ACTIVE_ARCHIVE_KEY, newName);
                }
                await showCustomAlert("Lưu trữ đã được đổi tên！");
                toggleCenterView('archive-selection-view');
                await renderArchiveSelectionView();
            }
        }

        async function loadRegexConfig() {
            const defaultConfig = {
                fontScale: 1.1,
                fontSize: 17,
                fontColor: '#E0E5F5',
                chatFont: "'Lora', serif",
                renderLimit: 20,
                contextLimit: 0,
                autoHideSummarized: false,
                fixedHideRange: '',
                enableThinkingAnimation: true,
                enableTypewriterOutput: false,
                showThinkingProcess: false,
                rules: [],
                chainRules: []
            };
            try {
                const storedConfig = await dbGet(REGEX_CONFIG_KEY) || {};
                const correctedConfig = { ...defaultConfig, ...storedConfig };
                const parsedFontScale = parseFloat(correctedConfig.fontScale);
                correctedConfig.fontScale = isNaN(parsedFontScale) ? defaultConfig.fontScale : parsedFontScale;
                const parsedFontSize = parseInt(correctedConfig.fontSize);
                correctedConfig.fontSize = isNaN(parsedFontSize) ? defaultConfig.fontSize : parsedFontSize;
                regexConfig = correctedConfig;
            } catch (e) {
                regexConfig = defaultConfig;
            }

            applyAdaptiveFontSize(regexConfig.fontSize);
            document.documentElement.style.setProperty('--ai-font-size', `${regexConfig.fontScale}em`);
            document.documentElement.style.setProperty('--ai-font-color', regexConfig.fontColor);
            document.documentElement.style.setProperty('--chat-font-family', regexConfig.chatFont);

            document.getElementById('content-font-scale').value = regexConfig.fontScale;
            document.getElementById('content-font-size').value = regexConfig.fontSize;
            document.getElementById('content-font-color').value = regexConfig.fontColor;

            const fontSelect = document.getElementById('chat-font-family');
            fontSelect.innerHTML = '';
            for(const fontName in FONT_MAP) {
                const option = document.createElement('option');
                option.value = FONT_MAP[fontName];
                option.textContent = fontName;
                fontSelect.appendChild(option);
            }
            fontSelect.value = regexConfig.chatFont;

            document.getElementById('content-render-limit').value = regexConfig.renderLimit;
            document.getElementById('fixed-hide-range').value = regexConfig.fixedHideRange || '';
            document.getElementById('enable-thinking-animation-toggle').checked = regexConfig.enableThinkingAnimation;
            document.getElementById('enable-typewriter-output-toggle').checked = regexConfig.enableTypewriterOutput;
            document.getElementById('show-thinking-process-toggle').checked = regexConfig.showThinkingProcess;
        }

        async function saveRegexConfig() {
            regexConfig.fontScale = document.getElementById('content-font-scale').value;
            regexConfig.fontSize = parseInt(document.getElementById('content-font-size').value) || 16;
            regexConfig.fontColor = document.getElementById('content-font-color').value;
            regexConfig.chatFont = document.getElementById('chat-font-family').value;
            regexConfig.renderLimit = parseInt(document.getElementById('content-render-limit').value) || 100;
            regexConfig.fixedHideRange = document.getElementById('fixed-hide-range').value.trim();
            regexConfig.enableThinkingAnimation = document.getElementById('enable-thinking-animation-toggle').checked;
            regexConfig.enableTypewriterOutput = document.getElementById('enable-typewriter-output-toggle').checked;
            regexConfig.showThinkingProcess = document.getElementById('show-thinking-process-toggle').checked;

            try {
                await dbSet(REGEX_CONFIG_KEY, regexConfig);
                await showCustomAlert('Cài đặt Regex và ngữ cảnh đã được lưu！');
                regexSettingsOverlay.classList.remove('visible');

                applyAdaptiveFontSize(regexConfig.fontSize);
                document.documentElement.style.setProperty('--chat-font-family', regexConfig.chatFont);
                document.documentElement.style.setProperty('--ai-font-size', `${regexConfig.fontScale}em`);
                document.documentElement.style.setProperty('--ai-font-color', regexConfig.fontColor);

                if (currentArchiveName) {
                    const archive = await db.archives.get(currentArchiveName);
                    if (archive) {
                        loadChatHistory(archive.data.logs);
                    }
                }
            } catch (e) {
                await showCustomAlert('Lưu thất bại, thao tác cơ sở dữ liệu bị lỗi.');
                console.error('Lưu cài đặt Regex thất bại:', e);
            }
        }

        function applyAdaptiveFontSize(baseSize = 16) {
            const minSize = Math.max(12, baseSize * 0.8);
            const preferredSizeVW = (baseSize / 1440) * 100;
            const maxSize = baseSize * 1.5;

            const styleElement = document.getElementById('adaptive-font-style') || document.createElement('style');
            styleElement.id = 'adaptive-font-style';

            styleElement.innerHTML = `
                :root {
                    font-size: clamp(${minSize}px, ${preferredSizeVW.toFixed(4)}vw, ${maxSize}px);
                }
            `;
            if (!styleElement.parentElement) {
                document.head.appendChild(styleElement);
            }
        }

        function renderRegexRulesUI(configToRender = regexConfig) {
            const renderList = (listEl, rules, type) => {
                listEl.innerHTML = '';
                if (!rules || !Array.isArray(rules)) return;
                rules.forEach((rule, index) => {
                    const item = document.createElement('div');
                    item.className = 'regex-rule-item';
                    item.innerHTML = `
                        <input type="checkbox" data-index="${index}" data-type="${type}" ${!rule.disabled ? 'checked' : ''} title="Bật/Tắt">
                        <span class="rule-name">${rule.scriptName}</span>
                        <div class="rule-actions">
                            <button class="edit-regex-btn" data-index="${index}" data-type="${type}" title="Chỉnh Sửa"><i class="fas fa-edit"></i></button>
                            <button class="delete-regex-btn" data-index="${index}" data-type="${type}" title="Xóa"><i class="fas fa-trash"></i></button>
                            <button class="move-regex-up-btn" data-index="${index}" data-type="${type}" title="Lên" ${index === 0 ? 'disabled' : ''}><i class="fas fa-arrow-up"></i></button>
                            <button class="move-regex-down-btn" data-index="${index}" data-type="${type}" title="Xuống" ${index === rules.length - 1 ? 'disabled' : ''}><i class="fas fa-arrow-down"></i></button>
                        </div>
                    `;
                    listEl.appendChild(item);
                });
            };
            renderList(document.getElementById('regex-rules-list'), configToRender.rules, 'regular');
            renderList(document.getElementById('chain-regex-rules-list'), configToRender.chainRules, 'chain');
        }

        function openRegexEditor(index, type) {
            currentEditingRegexIndex = index;
            currentEditingRegexType = type;
            const rules = type === 'chain' ? (regexConfig.chainRules || []) : (regexConfig.rules || []);
            const rule = (index === -1) ? {} : rules[index];

            document.getElementById('regex-editor-title').textContent = (index === -1) ? `Thêm quy tắc ${type === 'chain' ? 'Chuỗi Tư Duy' : 'Thông Thường'} mới` : `Chỉnh Sửa Quy Tắc`;
            document.getElementById('regex-editor-name').value = rule.scriptName || '';
            document.getElementById('regex-editor-find').value = rule.findRegex || '//g';
            document.getElementById('regex-editor-replace').value = rule.replaceString || '';
            document.getElementById('regex-editor-disabled').checked = rule.disabled || false;
            document.getElementById('regex-editor-run-on-edit').checked = rule.runOnEdit || false;
            document.getElementById('regex-editor-markdown').checked = rule.markdownOnly || false;
            document.getElementById('regex-editor-prompt').checked = rule.promptOnly || false;
            document.getElementById('regex-editor-min-depth').value = rule.minDepth ?? '';
            document.getElementById('regex-editor-max-depth').value = rule.maxDepth ?? '';

            const subSelect = document.getElementById('regex-editor-substitute');
            subSelect.innerHTML = '<option value="0">Không thay thế</option>';
            subSelect.value = rule.substituteRegex || 0;

            const placements = rule.placement || [];
            document.querySelectorAll('#regex-editor-overlay [data-placement]').forEach(cb => {
                cb.checked = placements.includes(parseInt(cb.dataset.placement));
            });

            regexEditorOverlay.classList.add('visible');
        }

        async function saveRegexRuleFromEditor(configToUpdate) {
            const name = document.getElementById('regex-editor-name').value;
            const find = document.getElementById('regex-editor-find').value;
            const replace = document.getElementById('regex-editor-replace').value;

            if (!name || !find) {
                await showCustomAlert('Tên quy tắc và Regex tìm kiếm không được để trống！');
                return;
            }

            const placements = [];
            document.querySelectorAll('#regex-editor-overlay [data-placement]:checked').forEach(cb => {
                placements.push(parseInt(cb.dataset.placement));
            });

            const rules = currentEditingRegexType === 'chain' ? (configToUpdate.chainRules || []) : (configToUpdate.rules || []);

            const ruleData = {
                id: (currentEditingRegexIndex === -1) ? crypto.randomUUID() : rules[currentEditingRegexIndex].id,
                scriptName: name,
                findRegex: find,
                replaceString: replace,
                disabled: document.getElementById('regex-editor-disabled').checked,
                runOnEdit: document.getElementById('regex-editor-run-on-edit').checked,
                markdownOnly: document.getElementById('regex-editor-markdown').checked,
                promptOnly: document.getElementById('regex-editor-prompt').checked,
                placement: placements,
                minDepth: document.getElementById('regex-editor-min-depth').value ? parseInt(document.getElementById('regex-editor-min-depth').value) : null,
                maxDepth: document.getElementById('regex-editor-max-depth').value ? parseInt(document.getElementById('regex-editor-max-depth').value) : null,
                substituteRegex: parseInt(document.getElementById('regex-editor-substitute').value),
                trimStrings: []
            };

            if (currentEditingRegexIndex === -1) {
                rules.push(ruleData);
            } else {
                rules[currentEditingRegexIndex] = ruleData;
            }

            if (currentEditingRegexType === 'chain') {
                configToUpdate.chainRules = rules;
            } else {
                configToUpdate.rules = rules;
            }

            renderRegexRulesUI(configToUpdate);
            regexEditorOverlay.classList.remove('visible');
        }

        async function openExportArchiveSelection(actionType = 'export') {
            const archives = await db.archives.toArray();
            exportArchiveList.innerHTML = '';
            if (archives.length === 0) {
                exportArchiveList.innerHTML = '<p style="text-align:center; opacity:0.7;">Không có lưu trữ nào để thao tác</p>';
            } else {
                archives.forEach(archive => {
                    const item = document.createElement('div');
                    item.className = 'manual-summary-item';
                    item.textContent = archive.name;
                    if (actionType === 'copy') {
                        item.onclick = () => copySingleArchiveToClipboard(archive.name);
                    } else {
                        item.onclick = () => exportSingleArchive(archive.name);
                    }
                    exportArchiveList.appendChild(item);
                });
            }
            exportArchiveOverlay.classList.add('visible');
        }

        async function createExportObject(archiveName) {
            const archiveData = await db.archives.get(archiveName);
            if (!archiveData) return null;

            const attributePoints = await dbGet(`ATTRIB_POINTS_${archiveName}`) || 0;
            const customAvatar = await dbGet(`${CUSTOM_AVATAR_KEY}_${archiveName}`) || null;
            const npcAvatars = await dbGet(`${NPC_AVATARS_KEY}_${archiveName}`) || null;

            const exportData = { ...archiveData.data };
            if (!exportData.version) {
                exportData.version = GAME_VERSION;
            }

            return {
                archiveName: archiveName,
                data: exportData,
                extraData: {
                    attributePoints: attributePoints,
                    customAvatar: customAvatar,
                    npcAvatars: npcAvatars
                }
            };
        }

        async function exportSingleArchive(archiveName) {
            const exportObject = await createExportObject(archiveName);
            if (!exportObject) {
                await showCustomAlert('Lỗi: Không tìm thấy lưu trữ cần xuất.');
                return;
            }
            const dataStr = JSON.stringify(exportObject, null, 2);
            const dataBlob = new Blob([dataStr], {type: "application/json"});
            const url = URL.createObjectURL(dataBlob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${archiveName}.json`;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
            exportArchiveOverlay.classList.remove('visible');
        }

        async function copySingleArchiveToClipboard(archiveName) {
            const exportObject = await createExportObject(archiveName);
            if (!exportObject) {
                await showCustomAlert('Lỗi: Không tìm thấy lưu trữ cần sao chép.');
                return;
            }
            if (!navigator.clipboard || typeof navigator.clipboard.writeText !== 'function') {
                await showCustomAlert('Trình duyệt của bạn không hỗ trợ hoặc chưa được cấp phép chức năng ghi vào clipboard.');
                return;
            }
            try {
                await navigator.clipboard.writeText(JSON.stringify(exportObject));
                await showCustomAlert(`Lưu trữ "${archiveName}" đã được sao chép thành công vào clipboard！`);
            } catch (err) {
                await showCustomAlert(`Sao chép thất bại: ${err.message}`);
            } finally {
                exportArchiveOverlay.classList.remove('visible');
            }
        }

        async function processImportedArchiveData(jsonString) {
            try {
                const importedObject = JSON.parse(jsonString);
                if (!importedObject.archiveName || !importedObject.data || !importedObject.data.logs || !importedObject.data.state) {
                    throw new Error('Định dạng dữ liệu nhập không hợp lệ hoặc đã bị hỏng.');
                }
                const { archiveName, data, extraData } = importedObject;
                const existing = await db.archives.get(archiveName);
                if (existing) {
                    if (!await showCustomConfirm(`Lưu trữ có tên "${archiveName}" đã tồn tại. Bạn có muốn ghi đè lên nó không?`)) {
                        return;
                    }
                }

                const tempArchiveForMigration = { name: archiveName, data: data };
                const wasMigrated = await migrateSaveData(tempArchiveForMigration);
                if (wasMigrated) {
                    console.log(`Lưu trữ đã nhập [${archiveName}] đã tự động thực hiện di chuyển dữ liệu.`);
                }
                const finalData = tempArchiveForMigration.data;

                if (finalData && finalData.state && finalData.state.currentState) {
                    if (finalData.state.currentState['0']) {
                        Object.values(finalData.state.currentState['0']).forEach(charRow => {
                            recalculateAndCorrectNpcStats(charRow);
                        });
                    }
                    if (finalData.state.currentState['10']) {
                        Object.values(finalData.state.currentState['10']).forEach(monsterRow => {
                            recalculateAndCorrectNpcStats(monsterRow);
                        });
                    }
                }
                await autoCleanupNPCs(finalData.state.currentState);

                await db.archives.put({ name: archiveName, data: finalData });

                if (extraData) {
                    if (extraData.attributePoints !== undefined) {
                        await dbSet(`ATTRIB_POINTS_${archiveName}`, extraData.attributePoints);
                    }
                    if (extraData.customAvatar) {
                        await dbSet(`${CUSTOM_AVATAR_KEY}_${archiveName}`, extraData.customAvatar);
                    }
                }

                await showCustomAlert(`Lưu trữ "${archiveName}" đã được nhập thành công！`);
                if(splashScreen.classList.contains('hidden')) {
                    await renderArchiveSelectionView();
                } else {
                    await initPanel();
                }
            } catch (err) {
                await showCustomAlert(`Nhập thất bại: ${err.message}`);
            }
        }

        function handleArchiveImport(event) {
            const file = event.target.files[0];
            if (!file) return;
            const reader = new FileReader();
            reader.onload = async (e) => {
                await processImportedArchiveData(e.target.result);
                event.target.value = '';
            };
            reader.readAsText(file);
        }

