        function renderHibernatedCharacterList() {
            const listContainer = document.getElementById('hibernated-character-list-container');
            if (!listContainer) return;

            const hibernatedCharRows = Object.values(currentState['0'] || {}).filter(row => {
                if (!row['0'] || (!row['0'].startsWith('C') && !row['0'].startsWith('G'))) return false;
                try {
                    const booleans = parseRemarksString(row['20'] || '');
                    return booleans.isPresent === 'false' && booleans.isBonded !== 'true';
                } catch (e) {
                    return false;
                }
            });

            let listHtml = '';
            if (hibernatedCharRows.length === 0) {
                listHtml = '<p style="text-align:center; opacity:0.7;">Trong danh sách không có ghi chép nào đã rời đi.</p>';
            } else {
                hibernatedCharRows.forEach(charRow => {
                    const [name] = (charRow['1'] || '|').split('|');

                    const lastSeenTime = charRow['21'] || 'Thời Gian Không Rõ';
                    let datePart = lastSeenTime;
                    let timePart = '';

                    const lastSpaceIndex = lastSeenTime.lastIndexOf(' ');
                    if (lastSpaceIndex > -1 && lastSeenTime.substring(lastSpaceIndex + 1).includes(':')) {
                        datePart = lastSeenTime.substring(0, lastSpaceIndex);
                        timePart = lastSeenTime.substring(lastSpaceIndex + 1);
                    }

                    listHtml += `
                        <div class="character-list-item hibernated-item" data-id="${charRow['0']}">
                            <span class="name">${name}</span>
                            <span class="last-seen" style="display: flex; flex-direction: column; align-items: flex-end;">
                                <span>${datePart}</span>
                                <small style="opacity: 0.7;">${timePart}</small>
                            </span>
                            <button class="item-delete-btn hibernated-delete-btn" data-id="${charRow['0']}" title="Quên người này"><i class="fas fa-trash-alt"></i></button>
                        </div>
                    `;
                });
            }

            listContainer.innerHTML = `
                <div id="hibernated-list" style="flex-grow: 1; overflow-y: auto;">
                    ${listHtml}
                </div>
                <div class="manager-actions" style="grid-template-columns: 1fr;">
                    <button id="clear-hibernated-btn" class="major-action-button" style="border-color: #e57373; color: #e57373;"><i class="fas fa-broom"></i> Dọn dẹp NPC không xuất hiện trong 7 ngày</button>
                </div>
            `;

            listContainer.querySelectorAll('.character-list-item').forEach(item => {
                item.addEventListener('click', (e) => {
                    if (e.target.closest('.item-delete-btn')) return;
                    const charId = e.currentTarget.dataset.id;
                    const charData = characterDatabase[charId];
                    if (charData) {
                        showCharacterDetail(charData, e.currentTarget);
                    }
                });
            });

            listContainer.querySelectorAll('.hibernated-delete-btn').forEach(btn => {
                btn.addEventListener('click', async (e) => {
                    e.stopPropagation();
                    const npcId = e.currentTarget.dataset.id;
                    const npcName = (currentState['0'][npcId]['1'] || 'NPC').split('|')[0];
                    if (await showCustomConfirm(`Bạn có chắc muốn quên vĩnh viễn "${npcName}" không? Thao tác này không thể hoàn tác, sẽ xóa hoàn toàn mọi dữ liệu của nhân vật này khỏi lưu trữ.`)) {
                        delete currentState['0'][npcId];
                        await cleanupOrphanedData();
                        renderHibernatedCharacterList();
                    }
                });
            });

            const clearBtn = listContainer.querySelector('#clear-hibernated-btn');
            if (clearBtn) {
                clearBtn.addEventListener('click', async () => {
                    if (await showCustomConfirm(`Bạn có chắc muốn tự động dọn dẹp tất cả các NPC không quan trọng không xuất hiện trong 7 ngày không?\n（Những nhân vật được theo dõi, có thiện cảm quá cao/quá thấp, hoặc có liên quan đến nhiệm vụ sẽ không bị dọn dẹp）`)) {
                        const cleaned = await autoCleanupNPCs(currentState);
                        if (cleaned) {
                            await cleanupOrphanedData();
                            renderHibernatedCharacterList();
                        } else {
                            await showCustomAlert('Không có NPC nào cần dọn dẹp.');
                        }
                    }
                });
                clearBtn.disabled = hibernatedCharRows.length === 0;
            }
        }

