        async function exportNpcAsTemplate(npcId) {
            const npcRow = currentState['0'][npcId];
            if (!npcRow) {
                await showCustomAlert('Lỗi: Không tìm thấy dữ liệu NPC cần xuất.');
                return;
            }

            const [name, gender] = (npcRow['1'] || '|').split('|');
            const [race, career] = (npcRow['2'] || '|').split('|');

            const templateData = {
                name: name || 'Không Rõ',
                gender: gender || 'Không Rõ',
                race: race || 'Không Rõ',
                career: career || 'Thất Nghiệp',
                identity: npcRow['8'] || '',
                age: npcRow['5'] || 'Không Rõ',
                favorability: '50',
                level: '5',

                core_appearance: npcRow['26'] || '',
                rawAppearance: (JSON.parse(npcRow['27'] || '[]')).map(item => item[0]).join(', ') || '',
                personality: npcRow['3'] || '',
                motive: npcRow['12'] || '',
                background: npcRow['10'] || '',
                rawRelations: `B1:Đồng Hành Ban Đầu`,

                attributes: '{"Sức Mạnh":8,"Thể Chất":8,"Nhanh Nhẹn":8,"Trí Lực":8,"Cảm Ứng":8,"Mị Lực":8,"May Mắn":8,"Tinh Thần":8,"Tín Ngưỡng":0,"Thân Hòa Vực Sâu":0}'
            };

            const dataStr = JSON.stringify([templateData], null, 2);
            const dataBlob = new Blob([dataStr], {type: "application/json"});
            const url = URL.createObjectURL(dataBlob);
            const a = document.createElement('a');
            a.href = url;
            a.download = `${templateData.name}_template.json`;
            document.body.appendChild(a);
a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }

		<!-- DNEW Edit Func: Hàm này đã bị sửa đổi -->
		async function updateNpcAvatar(char) {
			const avatarContainer = document.getElementById('npc-avatar-container')?.querySelector('.char-detail-avatar');
			if (!avatarContainer) return;

			const deleteBtn = document.getElementById('npc-avatar-delete-btn');
			const defaultAvatarVideo = 'https://cdn.jsdelivr.net/gh/YouYuJun233/my/background.webm';

			const npcAvatars = await dbGet(`${NPC_AVATARS_KEY}_${currentArchiveName}`);
			const customAvatarData = npcAvatars ? npcAvatars[char.id] : null;

			avatarContainer.innerHTML = '';

			// Xử lý cả cấu trúc mới (object) và cũ (string)
			const imageData = (typeof customAvatarData === 'object' && customAvatarData !== null) ? customAvatarData.data : customAvatarData;

			if (imageData) {
				const img = document.createElement('img');
				img.id = 'npc-avatar-img';
				img.src = imageData;
				avatarContainer.appendChild(img);
				if(deleteBtn) deleteBtn.classList.remove('hidden');
			} else {
                const video = document.createElement('video');
                video.id = 'npc-avatar-img';
                video.autoplay = true;
                video.loop = true;
                video.muted = true;
                video.playsInline = true;
                cacheAndSetVideoBackground(video, defaultAvatarVideo);
                avatarContainer.appendChild(video);
                if(deleteBtn) deleteBtn.classList.add('hidden');
            }
