        function renderNpcRelationGraph(char, container) {
            container.innerHTML = `<div id="relation-graph-div" style="width: 100%; height: 100%;"></div>`;
            const graphContainer = document.getElementById('relation-graph-div');

            if (graphContainer.offsetWidth === 0 || graphContainer.offsetHeight === 0) {
                setTimeout(() => renderNpcRelationGraph(char, container), 100);
                return;
            }

            const nodes = new vis.DataSet();
            const edges = new vis.DataSet();
            const addedNodes = new Set();

            const containerWidth = graphContainer.offsetWidth;

            const lerp = (val, in_min, in_max, out_min, out_max) => {
                const percentage = Math.max(0, Math.min(1, (val - in_min) / (in_max - in_min)));
                return out_min + percentage * (out_max - out_min);
            };

            const nodeSize = lerp(containerWidth, 320, 800, 35, 70);
            const fontSize = lerp(containerWidth, 320, 800, 12, 16);
            const coreFontSize = lerp(containerWidth, 320, 800, 14, 18);
            const springLength = lerp(containerWidth, 320, 800, 150, 250);

            const addNode = (c, options = {}) => {
                if (addedNodes.has(c.id)) return;

                const nodeConfig = {
                    id: c.id,
                    label: c.name,
                    shape: 'ellipse',
                    font: { color: '#FFFFFF', face: 'Lora', size: fontSize, vadjust: 2 },
                    borderWidth: 0,
                    widthConstraint: { minimum: nodeSize, maximum: nodeSize },
                    heightConstraint: { minimum: nodeSize },
                    ...options
                };

                if (c.id === char.id) {
                    nodeConfig.color = { background: '#8E44AD' };
                    nodeConfig.font.size = coreFontSize;
                } else if (c.id === 'B1') {
                    nodeConfig.color = { background: '#2980B9' };
                    nodeConfig.font.size = coreFontSize;
                } else if (c.gender === 'Nữ' || c.gender === 'Nữ Giới' || c.gender === 'Cái') {
                    nodeConfig.color = { background: '#CF5B89' };
                } else if (c.gender === 'Nam' || c.gender === 'Nam Giới' || c.gender === 'Đực') {
                     nodeConfig.color = { background: '#54AB58' };
                } else {
                    nodeConfig.color = { background: '#7F8C8D' };
                }

                nodes.add(nodeConfig);
                addedNodes.add(c.id);
            };

            addNode(char);

            const allRelations = [];
            const processAllRelations = (sourceChar) => {
                if (!sourceChar.rawRelations) return;
                sourceChar.rawRelations.split(';').forEach(part => {
                    const [targetId, ...descParts] = part.split(':');
                    if (!targetId || !descParts.length) return;
                    const desc = descParts.join(':').trim();
                    allRelations.push({ from: sourceChar.id, to: targetId.trim(), label: desc });
                });
            };

            Object.values(characterDatabase).forEach(c => processAllRelations(c));
            const playerRow = currentState['0']['B1'];
            if(playerRow) {
                const playerRelations = (playerRow['13'] || '').split(';').filter(Boolean);
                playerRelations.forEach(rel => {
                    const [targetId, ...descParts] = rel.split(':');
                    if(targetId && descParts.length > 0) {
                        allRelations.push({ from: 'B1', to: targetId.trim(), label: descParts.join(':').trim() });
                    }
                });
            }

            const relevantRelations = allRelations.filter(r => r.from === char.id || r.to === char.id);

            relevantRelations.forEach(rel => {
                const otherPartyId = rel.from === char.id ? rel.to : rel.from;
                const otherPartyChar = characterDatabase[otherPartyId] || (otherPartyId === 'B1' ? currentPlayerData : null);
                if (otherPartyChar) {
                    addNode(otherPartyChar);
                    edges.add({ from: rel.from, to: rel.to, label: rel.label });
                }
            });

            if (nodes.length === 1 && edges.length === 0) {
                 graphContainer.innerHTML = '<p style="text-align: center; width: 100%; opacity: 0.7; margin-top: 20px;">Chưa phát hiện mối quan hệ xã hội trực tiếp của nhân vật này.</p>';
                 return;
            }

            const data = { nodes: nodes, edges: edges };

            const options = {
                physics: {
                    enabled: true,
                    solver: 'barnesHut',
                    barnesHut: {
                        gravitationalConstant: -30000,
                        centralGravity: 0.3,
                        springLength: springLength,
                        avoidOverlap: 1
                    },
                    stabilization: { iterations: 1000 }
                },
                layout: {
                    improvedLayout: true,
                },
                edges: {
                    length: springLength,
                    arrows: { to: { enabled: true, scaleFactor: 0.7 } },
                    color: 'rgba(122, 120, 194, 0.7)',
                    font: { color: '#ccc', size: 12, strokeWidth: 0, background: '#333' },
                    smooth: { enabled: true, type: 'curvedCW', roundness: 0.15 }
                },
                interaction: {
                    dragNodes: false,
                    dragView: true,
                    zoomView: true,
                    selectable: false,
                    hover: false,
                    tooltipDelay: 200
                }
            };

            const network = new vis.Network(graphContainer, data, options);

            network.once("stabilizationIterationsDone", function () {
                network.setOptions({ physics: false });
                network.fit({
                    animation: {
                        duration: 500,
                        easingFunction: 'easeInOutQuad'
                    }
                });
            });
        }

