        async function updateLocationInWorldBook() {
            if (!window.parent || !window.parent.TavernHelper) return;
            try {
                const primaryLorebook = await window.parent.TavernHelper.getCurrentCharPrimaryLorebook();
                if (!primaryLorebook) return;

                const entries = await window.parent.TavernHelper.getLorebookEntries(primaryLorebook);
                const loreComment = `§Bản Đồ_${currentArchiveName}`;
                let mapEntry = entries.find(e => e.comment === loreComment);

                if (!mapEntry) {
                    await writeMapToWorldBook(currentArchiveName, currentLocationsData);
                    const updatedEntries = await window.parent.TavernHelper.getLorebookEntries(primaryLorebook);
                    mapEntry = updatedEntries.find(e => e.comment === loreComment);
                }

                if (mapEntry) {
                    const mainLocation = currentLocationsData.find(loc => currentPlayerData.location && currentPlayerData.location.includes(loc.name));
                    const locationStrings = currentLocationsData.map(loc => {
                        if (loc.name === mainLocation?.name && currentPlayerData.detailedLocation && currentPlayerData.detailedLocation !== 'Không Rõ') {
                            return `${loc.name}(${currentPlayerData.detailedLocation})`;
                        }
                        return loc.name;
                    });
                    const newContent = `Địa Điểm Đã Biết: ${locationStrings.join(', ')}`;

                    if (mapEntry.content !== newContent) {
                        mapEntry.content = newContent;
                        await window.parent.TavernHelper.setLorebookEntries(primaryLorebook, [mapEntry]);
                    }
                }
            } catch (e) {
                console.error("Lỗi khi cập nhật địa điểm vào Lorebook:", e);
            }
        }

