        function calculateDistance(loc1, loc2, locationsData = currentLocationsData) {
            const getCoords = (loc) => loc.marker ? { x: parseFloat(loc.marker.left), y: parseFloat(loc.marker.top) } : loc;
            const pos1 = getCoords(loc1);
            const pos2 = getCoords(loc2);

            if (isNaN(pos1.x) || isNaN(pos1.y) || isNaN(pos2.x) || isNaN(pos2.y)) return 0;

            const mapScale = locationsData.mapScaleKm || 200;
            const mapImg = document.getElementById('main-map-img');
            const aspectRatio = (mapImg && mapImg.naturalHeight > 0 && mapImg.naturalWidth > 0)
                ? mapImg.naturalHeight / mapImg.naturalWidth
                : 1;

            const dx = (pos2.x - pos1.x) / 100;
            const dy = ((pos2.y - pos1.y) / 100) * aspectRatio;

            const distanceInKm = Math.round(Math.sqrt(dx*dx + dy*dy) * mapScale);
            return distanceInKm;
        }

        async function showLocationDetail(targetLoc) {
            const isCurrentLocation = currentPlayerData.location && currentPlayerData.location.startsWith(targetLoc.name);
            let distance = 0;
            const realmLocations = (currentLocationsData.mainRegions || []).concat(currentLocationsData.landmarks || []);

            if (!isCurrentLocation) {
                const playerLoc = realmLocations.find(l => currentPlayerData.location && currentPlayerData.location.startsWith(l.name));
                if (playerLoc && playerLoc.marker && targetLoc.marker) {
                    distance = calculateDistance(playerLoc, targetLoc);
                }
            }

            document.getElementById('location-detail-name').textContent = `Khám Phá: ${targetLoc.name}`;
            document.getElementById('location-detail-distance').textContent = isCurrentLocation ? `Bạn đang ở đây` : `Cách bạn khoảng ${distance} km`;

            const contentEl = document.getElementById('location-detail-content');
            contentEl.innerHTML = '';

            const mainLocationData = realmLocations.find(l => l.name === targetLoc.name) || targetLoc;
            if (!mainLocationData.subLocations) {
                mainLocationData.subLocations = [];
            }

            const knownSubLocationNames = new Set(mainLocationData.subLocations.map(sl => sl.name));
            let newLocationsFound = false;

            const discoverSubLocation = (name) => {
                if (name && name !== 'Không Rõ' && name !== targetLoc.name && !knownSubLocationNames.has(name)) {
                    knownSubLocationNames.add(name);
                    mainLocationData.subLocations.push({ name: name });
                    newLocationsFound = true;
                }
            };

            Object.values(characterDatabase).forEach(char => {
                if (char.location === targetLoc.name && char.detailedLocation) {
                    discoverSubLocation(char.detailedLocation);
                }
            });

            if (currentPlayerData.location === targetLoc.name && currentPlayerData.detailedLocation) {
                discoverSubLocation(currentPlayerData.detailedLocation);
            }

            if (newLocationsFound) {
                const mainRegionToUpdate = currentLocationsData.mainRegions.find(l => l.name === targetLoc.name);
                if (mainRegionToUpdate) {
                    mainRegionToUpdate.subLocations = mainLocationData.subLocations;
                    await saveCurrentState();
                }
            }

            const createCard = (title, icon, locationString, occupants, isSubLocation = false, subLocNameToDelete = null) => {
                const card = document.createElement('div');
                card.className = 'scene-card interactive';
                if (isCurrentLocation && (currentPlayerData.detailedLocation === locationString || (currentPlayerData.detailedLocation === 'Không Rõ' && locationString === targetLoc.name))) {
                    card.classList.add('player-location');
                }
                let deleteButtonHtml = '';
                if (isSubLocation) {
                    deleteButtonHtml = `<button class="item-delete-btn" data-subloc-name="${subLocNameToDelete}" title="Xóa địa điểm phụ này" style="position: absolute; top: 10px; right: 10px;"><i class="fas fa-trash-alt"></i></button>`;
                }

                card.style.position = 'relative';
                card.innerHTML = `
                    <div class="scene-card-icon"><i class="fas ${icon}"></i></div>
                    <div class="scene-card-info">
                        <div class="scene-card-title">${title}</div>
                        ${occupants ? `<div class="scene-card-occupants">Nhân Vật: ${occupants}</div>` : ''}
                    </div>
                    ${deleteButtonHtml}
                `;

                card.addEventListener('click', async (e) => {
                    if (e.target.closest('.item-delete-btn')) return;

                    if (await showCustomConfirm(`Bạn có chắc muốn dành thời gian để đến ${locationString} không?`)) {
                        addAction('travel', { location: locationString });
                    }
                });
                return card;
            };

            const occupantsInMain = Object.values(characterDatabase)
                .filter(c => c.detailedLocation === targetLoc.name || (c.location === targetLoc.name && (!c.detailedLocation || c.detailedLocation === 'Không Rõ')))
                .map(c => c.name).join(', ');
            contentEl.appendChild(createCard(`${targetLoc.name} (Khu Vực Chính)`, 'fa-map-marker-alt', targetLoc.name, occupantsInMain));

            mainLocationData.subLocations.forEach(subLoc => {
                const subLocName = subLoc.name;
                const occupantsInSub = Object.values(characterDatabase)
                    .filter(c => c.detailedLocation === subLocName)
                    .map(c => c.name).join(', ');
                contentEl.appendChild(createCard(subLocName, 'fa-store', `${targetLoc.name}/${subLocName}`, occupantsInSub, true, subLocName));
            });
            contentEl.querySelectorAll('.item-delete-btn').forEach(btn => {
                btn.addEventListener('click', async (e) => {
                    e.stopPropagation();
                    const subLocNameToDelete = e.currentTarget.dataset.sublocName;
                    if (await showCustomConfirm(`Bạn có chắc muốn xóa địa điểm phụ "${subLocNameToDelete}" không? Thao tác này sẽ xóa vĩnh viễn địa điểm này khỏi dữ liệu bản đồ.`)) {
                        const mainRegionToUpdate = currentLocationsData.mainRegions.find(l => l.name === targetLoc.name);
                        if (mainRegionToUpdate) {
                            mainRegionToUpdate.subLocations = mainRegionToUpdate.subLocations.filter(sl => sl.name !== subLocNameToDelete);
                            await saveCurrentState();
                            await showLocationDetail(targetLoc);
                        }
                    }
                });
            });

            const addSubLocationBtn = document.createElement('button');
            addSubLocationBtn.className = 'major-action-button';
            addSubLocationBtn.style.marginTop = '15px';
            addSubLocationBtn.innerHTML = '<i class="fas fa-plus-circle"></i> Thêm Địa Điểm Phụ Thủ Công';
            addSubLocationBtn.onclick = async () => {
                const subLocationName = await showCustomPrompt(`Thêm địa điểm phụ mới trong [${targetLoc.name}]:`);
                if (subLocationName && subLocationName.trim() !== "") {
                    const locIndex = realmLocations.findIndex(l => l.name === targetLoc.name);
                    const mainRegionToUpdate = currentLocationsData.mainRegions.find(l => l.name === targetLoc.name);
                    if (mainRegionToUpdate) {
                        if (!mainRegionToUpdate.subLocations) {
                            mainRegionToUpdate.subLocations = [];
                        }
                        if (!mainRegionToUpdate.subLocations.some(sl => sl.name === subLocationName.trim())) {
                            mainRegionToUpdate.subLocations.push({ name: subLocationName.trim() });
                            await saveCurrentState();
                            await showLocationDetail(targetLoc);
                        } else {
                            await showCustomAlert('Địa điểm phụ này đã tồn tại.');
                        }
                    }
                }
            };
            contentEl.appendChild(addSubLocationBtn);

            locationDetailOverlay.classList.add('visible');
        }

