        async function exportMapConfig(archiveName) {
            const archive = await db.archives.get(archiveName);
            if (archive && archive.data.state.locations) {
                const dataStr = JSON.stringify(archive.data.state.locations, null, 2);
                const dataBlob = new Blob([dataStr], {type: "application/json"});
                const url = URL.createObjectURL(dataBlob);
                const a = document.createElement('a');
                a.href = url;
                a.download = `${archiveName}_map_config.json`;
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
                URL.revokeObjectURL(url);
                mapExportSelectionOverlay.classList.remove('visible');
            } else {
                await showCustomAlert('Lưu trữ này không có dữ liệu bản đồ để xuất.');
            }
        }

        importMapInput.addEventListener('change', async (event) => {
            const file = event.target.files[0];
            if (!file) return;

            const reader = new FileReader();
            reader.onload = async (e) => {
                try {
                    const importedData = JSON.parse(e.target.result);

                    if (typeof importedData !== 'object' || importedData === null || Array.isArray(importedData) ||
                       (!importedData.landmarks && !importedData.mainRegions)) {
                        throw new Error('Định dạng tệp cấu hình bản đồ không hợp lệ. Phải là một đối tượng chứa "landmarks" hoặc "mainRegions".');
                    }

                    if (await showCustomConfirm('Bạn có chắc muốn nhập cấu hình bản đồ này vào lưu trữ đang hoạt động không? Thao tác này sẽ ghi đè dữ liệu bản đồ của lưu trữ hiện tại.')) {
                        const archive = await db.archives.get(currentArchiveName);

                        if (archive) {
                            const newLocationsData = {
                                mainRegions: importedData.mainRegions || [],
                                subRegions: importedData.subRegions || [],
                                landmarks: importedData.landmarks || [],
                                mapScaleKm: importedData.mapScaleKm || 200
                            };

                            archive.data.state.locations = newLocationsData;
                            await db.archives.put(archive);

                            currentLocationsData = newLocationsData;
                            currentState.locations = JSON.parse(JSON.stringify(newLocationsData));

                            await showCustomAlert('Cấu hình bản đồ đã được nhập thành công！');
                            mapArchiveSelectionOverlay.classList.remove('visible');

                            const mapTab = document.querySelector('.main-view-tab[data-tab="map"]');
                            if (mapTab && mapTab.classList.contains('active')) {
                                mapTab.click();
                            }

                        } else {
                            await showCustomAlert('Nhập thất bại: Không có lưu trữ đang hoạt động.');
                        }
                    }
                } catch (err) {
                    await showCustomAlert(`Nhập thất bại: ${err.message}`);
                } finally {
                    event.target.value = '';
                }
            };
            reader.readAsText(file);
        });

        document.getElementById('replace-map-input').addEventListener('change', async (event) => {
            const file = event.target.files[0];
            if (!file || !file.type.startsWith('image/')) return;

            const reader = new FileReader();
            reader.onload = async (e) => {
                try {
                    const imageDataUrl = e.target.result;
                    await dbSet('GLOBAL_CUSTOM_MAP_URL', imageDataUrl);
                    const mainMapImg = document.getElementById('main-map-img');
                    const editorImg = document.getElementById('map-editor-img');

                    const updatePromises = [];

                    const updateImage = (imgElement) => {
                        if (imgElement) {
                            return new Promise((resolve, reject) => {
                                imgElement.onload = () => {
                                    const pannable = imgElement.closest('.map-pannable');
                                    if (pannable) {
                                        pannable.style.aspectRatio = imgElement.naturalWidth / imgElement.naturalHeight;
                                    }
                                    resolve();
                                };
                                imgElement.onerror = reject;
                                imgElement.src = imageDataUrl;
                            });
                        }
                        return Promise.resolve();
                    };

                    updatePromises.push(updateImage(mainMapImg));
                    updatePromises.push(updateImage(editorImg));

                    await Promise.all(updatePromises);
                    renderMapLocations(document.getElementById('main-map-locations-container'), currentLocationsData, false);
                    renderCharacterMapMarkers(document.getElementById('main-map-locations-container'));
                    updateAllMapScales();

                    await showCustomAlert('Bản đồ nền toàn cục đã được cập nhật！');

                } catch (err) {
                    await showCustomAlert(`Thay đổi bản đồ thất bại: ${err.message}`);
                } finally {
                    event.target.value = '';
                }
            };
            reader.readAsDataURL(file);
        });

