        async function saveMapEditorChanges() {
            if (currentMapEditorMode !== 'archive' || !currentEditingMapArchive) return;

            const archive = await db.archives.get(currentEditingMapArchive);
            if (archive) {
                archive.data.state.locations = mapEditorLocations;
                archive.data.state.mapScaleKm = parseFloat(document.getElementById('map-scale-input').value) || 1000;
                await db.archives.put(archive);

                if (currentEditingMapArchive === currentArchiveName) {
                    currentLocationsData = JSON.parse(JSON.stringify(mapEditorLocations));
                    currentPlayerData.mapScaleKm = archive.data.state.mapScaleKm;
                }

                await writeMapToWorldBook(currentEditingMapArchive, mapEditorLocations);
                await showCustomAlert(`Bản đồ của lưu trữ "${currentEditingMapArchive}" đã được lưu！`);
