        async function populateSchemeSelector(elementId, defaultSelection = null) {
            const selector = document.getElementById(elementId);
            if (!selector) return;
            selector.innerHTML = '';
            if (elementId === 'map-scheme-selector-editor') {
                const archiveOption = document.createElement('option');
                archiveOption.value = '(Bản Đồ Lưu Trữ Này)';
                archiveOption.textContent = '(Bản Đồ Lưu Trữ Này)';
                selector.appendChild(archiveOption);
            }

            const defaultOption = document.createElement('option');
            defaultOption.value = 'Mặc Định';
            defaultOption.textContent = 'Scheme Mặc Định';
            selector.appendChild(defaultOption);

            const schemes = await db.mapSchemes.toArray();
            schemes.forEach(scheme => {
                const option = document.createElement('option');
                option.value = scheme.name;
                option.textContent = scheme.name;
                selector.appendChild(option);
            });

            if (defaultSelection && Array.from(selector.options).some(opt => opt.value === defaultSelection)) {
                selector.value = defaultSelection;
            } else if (elementId === 'map-scheme-selector-editor') {
                selector.value = '(Bản Đồ Lưu Trữ Này)';
            } else {
                selector.value = 'Mặc Định';
            }
        }

async function handleSaveMapScheme(selectorId = 'map-scheme-selector') {
            const currentSchemeName = document.getElementById(selectorId).value;
            const newName = await showCustomPrompt('Vui lòng nhập tên Scheme Địa Danh:', currentSchemeName !== 'Mặc Định' ? currentSchemeName : '');

            if (!newName || newName.trim() === "") return;
            if (newName.trim() === 'Mặc Định') {
                await showCustomAlert('Không thể sử dụng tên dành riêng "Mặc Định"！');
                return;
            }

            const existing = await db.mapSchemes.get(newName.trim());
            if (existing && newName.trim() !== currentSchemeName) {
                if (!await showCustomConfirm(`Scheme "${newName.trim()}" đã tồn tại, có muốn ghi đè lên nó không?`)) {
                    return;
                }
            }
            const locationsToSave = (selectorId === 'map-scheme-selector-editor')
                ? currentLocationsData
                : mapEditorLocations;

            await db.mapSchemes.put({ name: newName.trim(), locations: locationsToSave });
            await populateSchemeSelector(selectorId, newName.trim());
            const selector = document.getElementById(selectorId);
            if(selector) selector.dispatchEvent(new Event('change'));

            await showCustomAlert('Scheme Địa Danh đã được lưu！');
        }

        async function handleLoadMapScheme(schemeName) {
            if (schemeName === 'Mặc Định') {
                mapEditorLocations = JSON.parse(JSON.stringify(DEFAULT_LOCATIONS));
            } else {
                const scheme = await db.mapSchemes.get(schemeName);
                if (scheme) {
                    mapEditorLocations = scheme.locations;
                }
            }

            const isDefault = schemeName === 'Mặc Định';
            document.getElementById('overwrite-map-scheme-btn').disabled = isDefault;
            document.getElementById('save-map-scheme-btn').disabled = false;
            document.getElementById('delete-map-scheme-btn').disabled = isDefault;
            document.getElementById('clear-map-locations-btn').disabled = false;
            document.getElementById('add-location-mode-btn').disabled = false;

            const isCustomMap = !!(await dbGet('GLOBAL_CUSTOM_MAP_URL'));
            renderMapLocations(document.getElementById('map-editor-locations-container'), mapEditorLocations, true, null, isCustomMap);
