        async function writeMapToWorldBook(archiveName, locationsData) {
            if (!window.parent || !window.parent.TavernHelper) { console.warn("Không thể truy cập TavernHelper của cửa sổ cha, bỏ qua việc ghi vào Lorebook."); return false; }
            try {
                const primaryLorebook = await window.parent.TavernHelper.getCurrentCharPrimaryLorebook();
                if (!primaryLorebook) { console.warn("Không tìm thấy Lorebook chính của nhân vật hiện tại, không thể ghi bản đồ."); return false; }

                const formatLocations = (locations) => {
                    if (!locations || locations.length === 0) return '';
                    const mainLocation = locations.find(loc => currentPlayerData.location && currentPlayerData.location.includes(loc.name));
                    const locationStrings = locations.map(loc => {
                        if (loc.name === mainLocation?.name && currentPlayerData.detailedLocation && currentPlayerData.detailedLocation !== 'Không Rõ') {
                            return `${loc.name}(${currentPlayerData.detailedLocation})`;
                        }
                        return loc.name;
                    });
                    return `Địa Điểm Đã Biết: ${locationStrings.join(', ')}`;
                };

                const fullMapContent = formatLocations(locationsData.landmarks);

                const entries = await window.parent.TavernHelper.getLorebookEntries(primaryLorebook);
                const loreComment = `§Bản Đồ_${archiveName}`;
                const existingEntry = entries.find(e => e.comment === loreComment);

                const entryData = {
                    content: fullMapContent,
                    keys: [],
                    insertion_order: 4,
                    enabled: true
                };

                if (existingEntry) {
                    const updatedEntry = { ...existingEntry, ...entryData };
                    await window.parent.TavernHelper.setLorebookEntries(primaryLorebook, [updatedEntry]);
                } else {
                    const newEntry = { comment: loreComment, ...entryData };
                    await window.parent.TavernHelper.createLorebookEntries(primaryLorebook, [newEntry]);
                }
                return true;
            } catch (e) { console.error("Lỗi khi ghi bản đồ vào Lorebook:", e); return false; }
        }
        async function syncLorebookStatus(archiveName) {
            if (!window.parent || !window.parent.TavernHelper) {
                console.warn("Không thể truy cập TavernHelper của cửa sổ cha, bỏ qua đồng bộ hóa trạng thái Lorebook.");
                return;
            }
            try {
                const primaryLorebook = await window.parent.TavernHelper.getCurrentCharPrimaryLorebook();
                if (!primaryLorebook) {
                    console.warn("Không tìm thấy Lorebook chính, bỏ qua đồng bộ hóa.");
                    return;
                }

                const allEntries = await window.parent.TavernHelper.getLorebookEntries(primaryLorebook);
                if (!allEntries || allEntries.length === 0) return;

                const mode = localStorage.getItem(WORLDVIEW_MODE_KEY) || 'default';
                const customPrefixes = JSON.parse(localStorage.getItem(SANDBOX_PREFIXES_KEY) || '[]');

                let changesMade = false;
                const updatedEntries = [];

                for (const entry of allEntries) {
                    let updatedEntry = { ...entry };
                    const comment = entry.comment || '';

                    let shouldBeEnabled = false;

                    const isPinned = comment.startsWith(LOREBOOK_PREFIXES.PINNED);
                    const isForCurrentArchive = comment.startsWith(LOREBOOK_PREFIXES.ARCHIVE) && comment.endsWith(`_${archiveName}`);

                    const isDefaultWorldviewEntry = comment.startsWith(LOREBOOK_PREFIXES.WORLDVIEW_DEFAULT);
                    const isCustomWorldviewEntry = customPrefixes.some(p => p && comment.startsWith(p));
                    const isForCurrentWorldview = (mode === 'default' && isDefaultWorldviewEntry) || (mode === 'sandbox' && isCustomWorldviewEntry);

                    if (isPinned) {
                        shouldBeEnabled = entry.enabled;
                    }
                    else if (isForCurrentArchive || isForCurrentWorldview) {
                        shouldBeEnabled = true;
                    }

                    if (entry.enabled !== shouldBeEnabled) {
                        updatedEntry.enabled = shouldBeEnabled;
                        changesMade = true;
                    }

                    updatedEntries.push(updatedEntry);
                }

                if (changesMade) {
                    await window.parent.TavernHelper.setLorebookEntries(primaryLorebook, updatedEntries);
                    console.log(`Trạng thái Lorebook đã đồng bộ hóa: Chế độ [${mode}], Lưu trữ [${archiveName}].`);
                }
            } catch (e) {
                console.error("Lỗi khi đồng bộ hóa trạng thái Lorebook:", e);
            }
        }

