        async function handleResummarize(logId) {
            if (!await showCustomConfirm("Bạn có chắc muốn tóm tắt lại đoạn ghi chép này không? Tóm tắt cũ sẽ bị ghi đè.")) return;

            let archive = await db.archives.get(currentArchiveName);
            let logs = archive.data.logs;
            const summaryLogIndex = logs.findIndex(log => log.id === logId);
            if (summaryLogIndex === -1) {
                await showCustomAlert("Lỗi: Không tìm thấy ghi chép cần tóm tắt lại.");
                return;
            }

            const summaryLog = logs[summaryLogIndex];
            const rangeMatch = summaryLog.content.match(/\[Chương Quá Khứ: Tầng (\d+)-(\d+)\]/);
            if (!rangeMatch) {
                await showCustomAlert("Lỗi: Không thể phân tích phạm vi tầng hợp lệ từ tóm tắt này.");
                return;
            }

            const start = parseInt(rangeMatch[1]);
            const end = parseInt(rangeMatch[2]);

            const chatLogs = logs.filter(log => !log.content.startsWith('[Chương Quá Khứ:') && !log.content.includes('<h4>Vận Mệnh Khởi Đầu, Tinh Tú Vang Vọng</h4>'));
            const logsToSummarize = chatLogs.slice(start - 1, end);

            if (logsToSummarize.length === 0) {
                await showCustomAlert("Lỗi: Không tìm thấy ghi chép gốc để tóm tắt lại.");
                return;
            }

            const textToSummarize = logsToSummarize.map(log => log.content).join('\n---\n');
            const summaryResult = await callSummaryApi(textToSummarize);

            if (summaryResult) {
                summaryLog.content = `[Chương Quá Khứ: Tầng ${start}-${end}]\n${summaryResult}`;
                archive.data.logs = logs;
                await db.archives.put(archive);

                await showCustomAlert("Tóm tắt lại hoàn tất！");
                showSummaryDetail(logId);
                loadChatHistory(logs);
            }
        }

