        async function loadStateFromLog(logId) {
            let archive = await db.archives.get(currentArchiveName);
            let logs = archive.data.logs;
            const logIndex = logs.findIndex(l => l.id === logId);

            if (logIndex === -1 || !logs[logIndex].stateSnapshot) {
                await showCustomAlert('Khôi phục thất bại: Không tìm thấy khoảnh khắc tương ứng.');
                return;
            }

            const snapshotLog = logs[logIndex];

            try {
                const snapshotObject = JSON.parse(snapshotLog.stateSnapshot);
                if (snapshotObject.attributePoints !== undefined) {
                    await dbSet(`ATTRIB_POINTS_${currentArchiveName}`, snapshotObject.attributePoints);
                }

                if (snapshotObject.npcAvatars) {
                    await dbSet(`${NPC_AVATARS_KEY}_${currentArchiveName}`, snapshotObject.npcAvatars);
                    delete snapshotObject.npcAvatars;
                }
                const stateToLoad = snapshotObject.currentState ? snapshotObject : { currentState: snapshotObject };

                if (snapshotLog.achievementsSnapshot) {
                    stateToLoad.achievements = JSON.parse(snapshotLog.achievementsSnapshot);
                } else if(snapshotObject.achievements) {
                    stateToLoad.achievements = snapshotObject.achievements;
                }

                if (snapshotLog.attributePointsSnapshot !== undefined) {
                    await dbSet(`ATTRIB_POINTS_${currentArchiveName}`, snapshotLog.attributePointsSnapshot);
                }

                archive.data.state = stateToLoad;
                await db.archives.put(archive);

                await loadState(stateToLoad, true);

                const locationsContainer = document.getElementById('main-map-locations-container');
                if (locationsContainer && (document.querySelector('.main-view-tab[data-tab="map"]')?.classList.contains('active') || document.querySelector('#mobile-main-view-tabs .main-view-tab[data-tab="map"]')?.classList.contains('active'))) {
                    renderMapLocations(locationsContainer, currentLocationsData, false);
                    renderPlayerMapMarker(locationsContainer);
                    renderCharacterMapMarkers(locationsContainer);
                    updateAllMapScales();
                }
                clearMapHistory();
                initializeMapHistory();

            } catch(e) {
                await showCustomAlert('Khôi phục thất bại: Định dạng dữ liệu khoảnh khắc bị sai.');
                console.error("Error parsing snapshot:", e);
                return;
            }

            logs.splice(logIndex + 1);
            archive.data.logs = logs;

            maintainMacroSummaries(archive);

            await db.archives.put(archive);

            await saveCurrentState();

            loadChatHistory(logs);
            renderPlayerAttributes(currentPlayerData);
            renderInventory(inventoryItems);
            updateAvatar(currentPlayerData);

            await showCustomAlert('Khoảnh khắc cuộc đời đã được tải thành công！');
            snapshotOverlay.classList.remove('visible');

            if (snapshotLog.branchContent) {
                const branchMatch = snapshotLog.branchContent.match(/<branches>([\s\S]*?)<\/branches>/);
                if (branchMatch) {
                    const optionRegex = /\[(.*?)\]/g;
                    const allOptions = [];
                    let option;
                    while ((option = optionRegex.exec(branchMatch[1])) !== null) {
                        allOptions.push(option[1]);
                    }
                    updateBranchingOptions(allOptions);
                } else {
                    updateBranchingOptions([]);
                }
            } else {
                updateBranchingOptions([]);
            }

            clearMapHistory();
            initializeMapHistory();
        }

