            const textarea = document.getElementById('snapshot-editor-textarea');
            const newSnapshot = textarea.value;

            try {
                const parsedSnapshot = JSON.parse(newSnapshot);
                if (typeof parsedSnapshot !== 'object' || parsedSnapshot === null || Array.isArray(parsedSnapshot)) {
                    throw new Error("Khoảnh khắc phải là một đối tượng chứa khóa bảng.");
                }
            } catch (e) {
                await showCustomAlert(`Định dạng sai, không thể lưu: ${e.message}`);
                return;
            }

            if (await showCustomConfirm('Định dạng chính xác. Bạn có chắc muốn lưu các thay đổi đối với khoảnh khắc này không?')) {
