        async function equipItem(item, slotKey, slotIndex) {
            const oldItemInSlot = currentPlayerData[slotKey][slotIndex];
            if (oldItemInSlot && currentState['1'][oldItemInSlot.id]) {
                currentState['1'][oldItemInSlot.id]['6'] = "";
            }

            if (currentState['1'][item.id]) {
                currentState['1'][item.id]['6'] = `${slotKey}:${slotIndex}`;
            }

            await saveCurrentState();
            syncStateFromTables();
            renderPlayerAttributes(currentPlayerData);
            closeEquipmentPicker();
        }

        async function unequipItem(slotKey, slotIndex) {
            const itemToUnequip = currentPlayerData[slotKey][slotIndex];
            if (!itemToUnequip || !currentState['1'][itemToUnequip.id]) return;

            currentState['1'][itemToUnequip.id]['6'] = "";

            await saveCurrentState();
            syncStateFromTables();
            renderInventory(inventoryItems);

            const activeTabButton = document.querySelector('#player-info-tabs .tab-button.active');
            if (activeTabButton && activeTabButton.dataset.tab !== 'equipment') {
                document.querySelector('#player-info-tabs .tab-button[data-tab="equipment"]').click();
            }

            closeItemDetail();
        }

