        function setupRegexSettingsListeners() {
            let tempRegexConfig = {};
            const listContainer = document.getElementById('regex-settings-overlay');
            if (!listContainer) return;
            document.getElementById('open-regex-settings-btn').addEventListener('click', () => {
                systemSettingsOverlay.classList.remove('visible');
                tempRegexConfig = JSON.parse(JSON.stringify(regexConfig));
                renderRegexRulesUI(tempRegexConfig);

                document.getElementById('content-font-scale').value = tempRegexConfig.fontScale;
                document.getElementById('content-font-size').value = tempRegexConfig.fontSize;
                document.getElementById('content-font-color').value = tempRegexConfig.fontColor;
                document.getElementById('chat-font-family').value = tempRegexConfig.chatFont;
                document.getElementById('content-render-limit').value = tempRegexConfig.renderLimit;
                document.getElementById('fixed-hide-range').value = tempRegexConfig.fixedHideRange || '';
                document.getElementById('enable-thinking-animation-toggle').checked = tempRegexConfig.enableThinkingAnimation;
                document.getElementById('enable-typewriter-output-toggle').checked = tempRegexConfig.enableTypewriterOutput;

                regexSettingsOverlay.classList.add('visible');
            });

            document.getElementById('save-regex-config-btn').addEventListener('click', () => {
                regexConfig.rules = tempRegexConfig.rules;
                regexConfig.chainRules = tempRegexConfig.chainRules;
                saveRegexConfig();
            });

            listContainer.addEventListener('click', async (e) => {
                const button = e.target.closest('button');
                const checkbox = e.target.closest('input[type="checkbox"]');

                if (checkbox && checkbox.dataset.index) {
                    const index = parseInt(checkbox.dataset.index);
                    const type = checkbox.dataset.type;
                    const rules = type === 'chain' ? (tempRegexConfig.chainRules || []) : (tempRegexConfig.rules || []);
                    rules[index].disabled = !checkbox.checked;
                }
                if (!button) return;

                const index = parseInt(button.dataset.index);
                const type = button.dataset.type;
                const rules = type === 'chain' ? (tempRegexConfig.chainRules || []) : (tempRegexConfig.rules || []);

                if (button.classList.contains('edit-regex-btn')) {
                    openRegexEditor(index, type);
                } else if (button.classList.contains('delete-regex-btn')) {
                    if (await showCustomConfirm(`Bạn có chắc muốn xóa quy tắc "${rules[index].scriptName}" không?`)) {
                        rules.splice(index, 1);
                        renderRegexRulesUI(tempRegexConfig);
                    }
                } else if (button.classList.contains('move-regex-up-btn')) {
                    if (index > 0) {
                        [rules[index - 1], rules[index]] = [rules[index], rules[index - 1]];
                        renderRegexRulesUI(tempRegexConfig);
                    }
                } else if (button.classList.contains('move-regex-down-btn')) {
                    if (index < rules.length - 1) {
                        [rules[index], rules[index + 1]] = [rules[index + 1], rules[index]];
                        renderRegexRulesUI(tempRegexConfig);
                    }
                }
            });

            document.getElementById('add-regex-rule-btn').addEventListener('click', () => openRegexEditor(-1, 'regular'));
            document.getElementById('add-chain-regex-rule-btn').addEventListener('click', () => openRegexEditor(-1, 'chain'));

            document.addEventListener('click', (e) => {
                if (e.target.matches('.modal-close-btn')) {
                    const overlay = e.target.closest('.overlay');
                    if (overlay) {
                        overlay.classList.remove('visible');
                    }
                }
            });

            document.getElementById('save-regex-editor-btn').addEventListener('click', () => {
                saveRegexRuleFromEditor(tempRegexConfig);
            });

            const importInput = document.getElementById('import-regex-input');
            document.getElementById('import-regex-btn').addEventListener('click', () => importInput.click());
            importInput.addEventListener('change', (e) => {
                const file = e.target.files[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = async (event) => {
                    try {
                        const parsedData = JSON.parse(event.target.result);
                        if (typeof parsedData === 'object' && parsedData !== null && (Array.isArray(parsedData.rules) || Array.isArray(parsedData.chainRules))) {
                            if (await showCustomConfirm("Phát hiện tệp cấu hình Regex hoàn chỉnh. Bạn có muốn ghi đè tất cả các cài đặt liên quan (bao gồm Regex, phông chữ, ngữ cảnh, v.v.) không?")) {
                                tempRegexConfig = { ...regexConfig, ...parsedData };
                                renderRegexRulesUI(tempRegexConfig);
                                await showCustomAlert('Cấu hình Regex hoàn chỉnh đã được nhập thành công！Nhấp vào “Lưu và Đóng” để áp dụng.');
                            }
                        } else {
                            let rulesToImport = [];
                            if (Array.isArray(parsedData)) {
                                if (parsedData.length > 0 && typeof parsedData[0].scriptName === 'undefined') {
                                    throw new Error('Định dạng đối tượng trong mảng không chính xác.');
                                }
                                rulesToImport = parsedData;
                            } else if (typeof parsedData === 'object' && parsedData !== null && typeof parsedData.scriptName !== 'undefined') {
                                rulesToImport = [parsedData];
                            } else {
                                throw new Error('Định dạng tệp không chính xác. Vui lòng nhập tệp cấu hình hoàn chỉnh hoặc mảng quy tắc.');
                            }

                            const importType = await showCustomDialog({
                                title: 'Chọn Loại Nhập',
                                message: 'Vui lòng chọn loại để nhập các quy tắc này vào?',
                                buttons: [
                                    { text: 'Regex Chuỗi Tư Duy', value: () => 'chain' },
                                    { text: 'Regex Thông Thường', value: () => 'regular' }
                                ]
                            });

							/* <!-- Cũ: 
                            if (importType) {
                                const targetRulesKey = importType === 'chain' ? 'chainRules' : 'rules';
                                if (!tempRegexConfig[targetRulesKey]) {
                                    tempRegexConfig[targetRulesKey] = [];
                                }
                                tempRegexConfig[targetRulesKey].push(...rulesToImport);
                                renderRegexRulesUI(tempRegexConfig);
                                await showCustomAlert('Quy tắc đã được nhập thêm thành công！');
                            } --> */
							if (importType) {
								const importMethod = await showCustomDialog({
									title: 'Chọn Phương Thức Nhập',
									message: 'Bạn muốn thêm các quy tắc mới vào danh sách hiện có, hay thay thế hoàn toàn danh sách cũ?',
									buttons: [
										{ text: 'Thay Thế', value: () => 'replace', style: 'danger' },
										{ text: 'Nhập Thêm', value: () => 'append' }
									]
								});

								if (importMethod) {
									const targetRulesKey = importType === 'chain' ? 'chainRules' : 'rules';

									if (importMethod === 'replace') {
										tempRegexConfig[targetRulesKey] = rulesToImport;
										await showCustomAlert('Danh sách quy tắc đã được thay thế thành công！');
									} else { // 'append'
										if (!tempRegexConfig[targetRulesKey]) {
											tempRegexConfig[targetRulesKey] = [];
										}
										tempRegexConfig[targetRulesKey].push(...rulesToImport);
										await showCustomAlert('Quy tắc đã được nhập thêm thành công！');
									}

									renderRegexRulesUI(tempRegexConfig);
								}
							}							
                        }
                    } catch (err) {
                        await showCustomAlert(`Nhập thất bại: ${err.message}`);
                    } finally {
                        e.target.value = '';
                    }
                };
                reader.readAsText(file);
            });

            document.getElementById('export-regex-btn').addEventListener('click', () => {
                const dataStr = JSON.stringify(regexConfig, null, 2);
                const dataBlob = new Blob([dataStr], {type: "application/json"});
                const url = URL.createObjectURL(dataBlob);
                const a = document.createElement('a');
                a.href = url;
                a.download = 'panel_regex_config.json';
                document.body.appendChild(a);
                a.click();
                document.body.removeChild(a);
                URL.revokeObjectURL(url);
            });
            document.getElementById('content-font-scale').addEventListener('input', (e) => {
                document.documentElement.style.setProperty('--ai-font-size', `${e.target.value}em`);
            });
            document.getElementById('content-font-size').addEventListener('input', (e) => {
                applyAdaptiveFontSize(parseInt(e.target.value) || 16);
            });
            document.getElementById('content-font-color').addEventListener('input', (e) => document.documentElement.style.setProperty('--ai-font-color', e.target.value));
            document.getElementById('chat-font-family').addEventListener('change', (e) => document.documentElement.style.setProperty('--chat-font-family', e.target.value));

            document.getElementById('delete-hidden-logs-btn').addEventListener('click', async () => {
                const archive = await db.archives.get(currentArchiveName);
                const logs = archive?.data.logs || [];
                if (logs.length === 0) {
                    await showCustomAlert('Lưu trữ hiện tại không có ghi chép nào để dọn dẹp.');
                    return;
                }
                const { hiddenChatLogs } = getLogsForContext(logs);
                if (hiddenChatLogs.length === 0) {
                    await showCustomAlert('Không có ghi chép nào đã thu gọn hoặc ẩn để xóa.');
                    return;
                }
                if (await showCustomConfirm(`Bạn có chắc muốn xóa vĩnh viễn ${hiddenChatLogs.length} nhật ký trò chuyện đã thu gọn/ẩn không? Thao tác này không thể hoàn tác.`)) {
                    const hiddenIds = new Set(hiddenChatLogs.map(log => log.id));
                    archive.data.logs = logs.filter(log => !hiddenIds.has(log.id));
                    await db.archives.put(archive);
                    loadChatHistory(archive.data.logs);
                    await showCustomAlert('Đã xóa thành công các ghi chép ẩn.');
                }
            });

			<!-- Start New -->
			const deleteAllRegexBtn = document.getElementById('delete-all-regex-btn');
			if (deleteAllRegexBtn) {
				deleteAllRegexBtn.addEventListener('click', async () => {
					const confirmed = await showCustomConfirm(
						'Bạn có chắc muốn xóa vĩnh viễn TOÀN BỘ quy tắc Regex (cả Chuỗi Tư Duy và Thông Thường) không? Thao tác này không thể hoàn tác.'
					);

					if (confirmed) {
						tempRegexConfig.rules = [];
						tempRegexConfig.chainRules = [];

						renderRegexRulesUI(tempRegexConfig);

						await showCustomAlert("Tất cả quy tắc đã được xóa. Nhấn 'Lưu và Đóng' để xác nhận thay đổi.");
					}
				});
			}			
			<!-- End -->
        }

        function updateDeleteButtonState() {
            const selectedCount = archiveList.querySelectorAll('input[type="checkbox"]:checked').length;
            deleteSelectedArchivesBtn.disabled = selectedCount === 0;
        }

        function toggleSelectAllArchives() {
            const checkboxes = archiveList.querySelectorAll('input[type="checkbox"]');
            const isAllSelected = Array.from(checkboxes).every(cb => cb.checked);
            checkboxes.forEach(cb => cb.checked = !isAllSelected);
            updateDeleteButtonState();
        }

        async function deleteSelectedArchives() {
            const selectedCheckboxes = archiveList.querySelectorAll('input[type="checkbox"]:checked');
            if (selectedCheckboxes.length === 0) return;

            const namesToDelete = Array.from(selectedCheckboxes).map(cb => cb.dataset.archiveName);

            if (await showCustomConfirm(`Bạn có chắc muốn xóa vĩnh viễn ${namesToDelete.length} lưu trữ đã chọn không?\n\n${namesToDelete.join('\n')}\n\nThao tác này không thể hoàn tác.`)) {
                let activeArchiveDeleted = false;
                namesToDelete.forEach(name => {
                    if (name === currentArchiveName) {
                        activeArchiveDeleted = true;
                    }
                });

                await db.archives.bulkDelete(namesToDelete);

                if (activeArchiveDeleted) {
                    await dbRemove(ACTIVE_ARCHIVE_KEY);
                    currentArchiveName = null;
                }

                await showCustomAlert(`${namesToDelete.length} lưu trữ đã được xóa.`);
                await renderArchiveSelectionView();
            }
        }

