                tierMultiplier: (tier) => 1 + (tier * 0.2)
            },
            DICE_UPGRADE_PATH: ['d4', 'd6', 'd8', 'd10', 'd12', 'd20'],
            EFFECT_GROWTH_PER_LEVEL: (effect, level, tier) => {
                const baseDiceString = effect['1'] || '1d4';
                const growth = {
                    flat: 0,
                    diceCount: 0,
                    diceType: baseDiceString
                };

                if (level <= 1) return growth;
                const flatGrowthPerLevel = 1 + Math.floor(tier / 2);
                growth.flat = (level - 1) * flatGrowthPerLevel;

                const diceCountGrowth = Math.floor((level - 1) / 3);
                growth.diceCount = diceCountGrowth;

                const diceTypeGrowthSteps = Math.floor((level - 1) / 4);
                if (diceTypeGrowthSteps > 0) {
                    const baseDiceType = baseDiceString.split('d')[1];
                    if (baseDiceType) {
                        const currentDiceIndex = SKILL_SYSTEM_CONFIG.DICE_UPGRADE_PATH.indexOf(`d${baseDiceType}`);
                        if (currentDiceIndex > -1) {
                            const newDiceIndex = Math.min(SKILL_SYSTEM_CONFIG.DICE_UPGRADE_PATH.length - 1, currentDiceIndex + diceTypeGrowthSteps);
                            const newDice = SKILL_SYSTEM_CONFIG.DICE_UPGRADE_PATH[newDiceIndex];
                            growth.diceType = `${baseDiceString.split('d')[0]}${newDice}`;
                        }
                    }
                }

                return growth;
            },
            COST_GROWTH: {
                'MP': 2, 'HP': 1, 'Thể Lực': 0.5
            },
            SAVE_DC_FORMULA: (caster, attribute) => {
                const attrValue = caster.detailedAttributes[attribute] || 10;
                return 8 + Math.floor((attrValue - 10) / 2);
            }
        };

        function processAllRegionInteractions(editedRegion) {
            if (!editedRegion || !editedRegion.id) return;

            const regionType = editedRegion.parentName ? 'subRegions' : 'mainRegions';

            if (regionType === 'mainRegions') {
                const editedRegionShape = getPolygonClippingInput(editedRegion.points);
                const newRegionsToAdd = [];
                const regionsToProcess = (currentLocationsData.mainRegions || []).filter(r => r.id !== editedRegion.id);

                regionsToProcess.forEach(oldRegion => {
                    const oldRegionShape = getPolygonClippingInput(oldRegion.points);
                    if (polygonClipping.intersection(oldRegionShape, editedRegionShape).length > 0) {
                        const result = polygonClipping.difference(oldRegionShape, editedRegionShape);
                        if (result.length > 0) {
                            oldRegion.points = { outer: result[0][0].map(p => ({x: p[0], y: p[1]})), holes: result[0].slice(1).map(h => h.map(p => ({x: p[0], y: p[1]}))) };

                            for (let i = 1; i < result.length; i++) {
                                const newPartGeometry = result[i];
                                const newRegionClone = JSON.parse(JSON.stringify(oldRegion));
                                newRegionClone.id = 'mainregion_' + crypto.randomUUID();
                                newRegionClone.points = { outer: newPartGeometry[0].map(p => ({x: p[0], y: p[1]})), holes: newPartGeometry.slice(1).map(h => h.map(p => ({x: p[0], y: p[1]}))) };
                                newRegionsToAdd.push(newRegionClone);
                            }
                        } else {
                            oldRegion.toBeDeleted = true;
                        }
                    }
                });

                currentLocationsData.mainRegions = (currentLocationsData.mainRegions || []).filter(r => !r.toBeDeleted && r.id !== editedRegion.id);
                currentLocationsData.mainRegions.push(editedRegion);
                currentLocationsData.mainRegions.push(...newRegionsToAdd);

            } else if (regionType === 'subRegions') {
                const parentRegion = (currentLocationsData.mainRegions || []).find(r => r.name === editedRegion.parentName);
                if (parentRegion) {
                    const parentShape = getPolygonClippingInput(parentRegion.points);
                    const subRegionShape = getPolygonClippingInput(editedRegion.points);
                    const intersection = polygonClipping.intersection(subRegionShape, parentShape);
                    if (intersection.length > 0) {
                        editedRegion.points = { outer: intersection[0][0].map(p => ({x: p[0], y: p[1]})), holes: intersection[0].slice(1).map(h => h.map(p => ({x: p[0], y: p[1]}))) };
                    } else {
                         const index = (currentLocationsData.subRegions || []).findIndex(sr => sr.id === editedRegion.id);
                        if (index > -1) currentLocationsData.subRegions.splice(index, 1);
                        return;
                    }
                }

                const editedSubRegionShape = getPolygonClippingInput(editedRegion.points);
                const newSubRegionsToAdd = [];
                const siblingsToProcess = (currentLocationsData.subRegions || []).filter(sub => sub.parentName === editedRegion.parentName && sub.id !== editedRegion.id);

                siblingsToProcess.forEach(sibling => {
                    const siblingShape = getPolygonClippingInput(sibling.points);
                    if (polygonClipping.intersection(siblingShape, editedSubRegionShape).length > 0) {
                        const result = polygonClipping.difference(siblingShape, editedSubRegionShape);
                        if (result.length > 0) {
                            sibling.points = { outer: result[0][0].map(p => ({x: p[0], y: p[1]})), holes: result[0].slice(1).map(h => h.map(p => ({x: p[0], y: p[1]}))) };

                            for (let i = 1; i < result.length; i++) {
                                const newPartGeometry = result[i];
                                const newSubRegionClone = JSON.parse(JSON.stringify(sibling));
                                newSubRegionClone.id = 'subregion_' + crypto.randomUUID();
                                newSubRegionClone.points = { outer: newPartGeometry[0].map(p => ({x: p[0], y: p[1]})), holes: newPartGeometry.slice(1).map(h => h.map(p => ({x: p[0], y: p[1]}))) };
                                newSubRegionsToAdd.push(newSubRegionClone);
                            }
                        } else {
                            sibling.toBeDeleted = true;
                        }
                    }
                });

                currentLocationsData.subRegions = (currentLocationsData.subRegions || []).filter(sub => !sub.toBeDeleted);
                currentLocationsData.subRegions.push(...newSubRegionsToAdd);
            }
        }

        async function finishVertexEditing(isAutoSave = false) {
            if (!currentlyEditingPolygon) return;

            const editedRegion = currentlyEditingPolygon.region;

            processAllRegionInteractions(editedRegion);

            recordMapHistory();

            if (isAutoSave) {
                const locationsContainer = document.getElementById('main-map-locations-container');
                renderMapLocations(locationsContainer, currentLocationsData, true);
                displayVerticesForEditing(currentlyEditingPolygon.region);
            } else {
                currentlyEditingPolygon = null;
                const editSvgLayer = document.getElementById('map-edit-svg-layer');
                if (editSvgLayer) editSvgLayer.innerHTML = '';

            }
        }

        function findSnapPoint(cursorPos, snapThresholdPx = 10, ignoredRegionId = null, ignoredVertexIndex = -1) {
            let closestSnap = null;

            const pannable = document.getElementById('main-map-pannable');
            const scale = parseFloat(pannable.dataset.scale) || 1;
            const pannableWidth = pannable.offsetWidth;
            const dynamicThreshold = pannableWidth > 0 ? (snapThresholdPx / (pannableWidth * scale)) * 100 : 1.5;
            let minDistance = dynamicThreshold;

            const allPolygons = [...(currentLocationsData.mainRegions || []), ...(currentLocationsData.subRegions || [])];

            allPolygons.forEach(poly => {
                if (!poly || !poly.points) return;

                let pointsToCheck = [];
                if (Array.isArray(poly.points) && poly.points.length > 0 && poly.points[0]?.outer) {
                    poly.points.forEach(part => {
                        if (part && part.outer) pointsToCheck.push(...part.outer);
                    });
                } else if (poly.points?.outer) {
                    pointsToCheck.push(...poly.points.outer);
                } else if (Array.isArray(poly.points)) {
                    pointsToCheck.push(...poly.points);
                }

                pointsToCheck.forEach((vertex, index) => {
                    if (!vertex) return;
                    if (poly.id === ignoredRegionId && index === ignoredVertexIndex) return;

                    const dx = cursorPos.x - vertex.x;
                    const dy = cursorPos.y - vertex.y;
                    const distance = Math.sqrt(dx * dx + dy * dy);

                    if (distance < minDistance) {
                        minDistance = distance;
                        closestSnap = { x: vertex.x, y: vertex.y };
                    }
                });
            });

            if (closestSnap) {
                return closestSnap;
            }

            allPolygons.forEach(poly => {
                if (!poly || !poly.points) return;

                let polygonsToProcess = [];
                 if (Array.isArray(poly.points) && poly.points.length > 0 && poly.points[0]?.outer) {
                    polygonsToProcess = poly.points.map(part => part?.outer).filter(Boolean);
                } else if (poly.points?.outer) {
                    polygonsToProcess.push(poly.points.outer);
                } else if (Array.isArray(poly.points)) {
                    polygonsToProcess.push(poly.points);
                }

                polygonsToProcess.forEach(points => {
                    if (!points) return;
                    for (let i = 0; i < points.length; i++) {
                        const p1 = points[i];
                        const p2 = points[(i + 1) % points.length];

                        if (!p1 || !p2) continue;
                        if (poly.id === ignoredRegionId && (i === ignoredVertexIndex || ((i + 1) % points.length) === ignoredVertexIndex)) {
                             return;
                        }

                        const dx = p2.x - p1.x;
                        const dy = p2.y - p1.y;

                        if (dx === 0 && dy === 0) continue;

                        const t = ((cursorPos.x - p1.x) * dx + (cursorPos.y - p1.y) * dy) / (dx * dx + dy * dy);

                        let closestPointOnSegment;
                        if (t < 0) closestPointOnSegment = p1;
                        else if (t > 1) closestPointOnSegment = p2;
                        else closestPointOnSegment = { x: p1.x + t * dx, y: p1.y + t * dy };

                        const dist_dx = cursorPos.x - closestPointOnSegment.x;
                        const dist_dy = cursorPos.y - closestPointOnSegment.y;
                        const distance = Math.sqrt(dist_dx * dist_dx + dist_dy * dist_dy);

                        if (distance < minDistance) {
                            minDistance = distance;
                            closestSnap = { x: closestPointOnSegment.x, y: closestPointOnSegment.y };
                        }
                    }
                });
            });

            return closestSnap;
        }

        function createVertexDragHandler(pointsArray, index, onMoveCallback, onEndCallback) {
            return function startDrag(startEvent) {
                startEvent.stopPropagation();
                if (startEvent.type === 'touchstart') startEvent.preventDefault();

                activeVertexIndex = index;
                const draggedVertex = startEvent.currentTarget;
                const pannable = document.getElementById('main-map-pannable');
                if (!pannable) return;

                const onVertexMove = (moveEvent) => {
                    if (activeVertexIndex === -1) return;

                    const mapRect = pannable.getBoundingClientRect();
                    const clientX = moveEvent.touches ? moveEvent.touches[0].clientX : moveEvent.clientX;
                    const clientY = moveEvent.touches ? moveEvent.touches[0].clientY : moveEvent.clientY;
                    let x = ((clientX - mapRect.left) / mapRect.width) * 100;
                    let y = ((clientY - mapRect.top) / mapRect.height) * 100;

                    const snapPoint = findSnapPoint({ x, y }, 1.5, currentlyEditingPolygon ? currentlyEditingPolygon.region.id : null, activeVertexIndex);
                        if (snapPoint) {
                            x = snapPoint.x;
                            y = snapPoint.y;
                        }

                    pointsArray[activeVertexIndex] = { x: x, y: y };
                    draggedVertex.style.left = `${x}%`;
                    draggedVertex.style.top = `${y}%`;

                    if (onMoveCallback) onMoveCallback();
                };

                const onVertexUp = () => {
                    activeVertexIndex = -1;
                    if (onEndCallback) onEndCallback();

                    window.removeEventListener('mousemove', onVertexMove);
                    window.removeEventListener('mouseup', onVertexUp);
                    window.removeEventListener('touchmove', onVertexMove);
                    window.removeEventListener('touchend', onVertexUp);
                };

                window.addEventListener('mousemove', onVertexMove);
                window.addEventListener('mouseup', onVertexUp, { once: true });
                window.addEventListener('touchmove', onVertexMove, { passive: false });
                window.addEventListener('touchend', onVertexUp, { once: true });
            };
        }

        function isPointInPolygon(point, polygonData) {
            if (!polygonData) return false;
            const points = Array.isArray(polygonData) ? polygonData : polygonData.outer;
            if (!points || points.length === 0) return false;

            let x = point.x, y = point.y;
            let inside = false;
            for (let i = 0, j = points.length - 1; i < points.length; j = i++) {
                const pi = points[i];
                const pj = points[j];
                if (!pi || !pj) continue;
                let xi = pi.x, yi = pi.y;
                let xj = pj.x, yj = pj.y;
                let intersect = ((yi > y) !== (yj > y)) && (x < (xj - xi) * (y - yi) / (yj - yi) + xi);
                if (intersect) inside = !inside;
            }

            if (inside && !Array.isArray(polygonData) && polygonData.holes) {
                for (const hole of polygonData.holes) {
                    if (isPointInPolygon(point, hole)) return false;
                }
            }
            return inside;
        }

