        function calculateSkillCost(skillData, level) {
            const costString = skillData['7'];
            if (!costString) return 'Không';

            return costString.split(';').map(part => {
                const [type, valueStr] = part.split(':');
                if (!type || !valueStr) return '';

                const trimmedValue = valueStr.trim();
                const knownResources = ['HP', 'MP', 'Thể Lực'];

                if (knownResources.includes(type.toUpperCase())) {
                    const match = trimmedValue.match(/(\w+)\s*\*\s*([\d.]+)/);
                    if (match) {
                        const resource = match[1];
                        const multiplier = parseFloat(match[2]) * 100;
                        return `${multiplier}% ${resource}`;
                    }
                    if (trimmedValue.includes('%')) {
                        return `${trimmedValue} ${type.toUpperCase()}`;
                    }
                    if (trimmedValue.toLowerCase() === 'x') {
                        return `Bất kỳ ${type.toUpperCase()}`;
                    }
                    const baseCost = parseInt(trimmedValue);
                    if (!isNaN(baseCost)) {
                        const perLevelCost = SKILL_SYSTEM_CONFIG.COST_GROWTH[type.toUpperCase()] || 0;
                        const finalCost = baseCost + ((level - 1) * perLevelCost);
                        return `${finalCost} ${type.toUpperCase()}`;
                    }
                }
                return `${type} x ${trimmedValue}`;

            }).filter(Boolean).join(' + ');
        }

        function calculateSkillXPForLevel(level, tier) {
            const { base, growthFactor, tierMultiplier } = SKILL_SYSTEM_CONFIG.XP_FORMULA;
            const requiredXP = base + ((level - 1) * growthFactor);
            return Math.floor(requiredXP * tierMultiplier(tier));
        }

        function calculatePetXPForLevel(level) {
            const baseXP = 50;
            const exponent = 1.8;
            const linearGrowth = 25;
            return Math.floor(baseXP * Math.pow(level, exponent) + (level * linearGrowth));
        }

        function getSkillMaxLevel(tier) {
            return SKILL_SYSTEM_CONFIG.TIER_TO_MAX_LEVEL[tier] || 1;
        }

