        function calculateRemainingPoints(state = creationState) {
            let points = state.totalPoints || 0;

            const getRaceDataFromState = (s) => (s.selectedRace === 'Tùy Chỉnh' && s.customRace) ? s.customRace : CREATION_CONFIG.RACES[s.selectedRace];
            const getBirthDataFromState = (s) => (s.selectedBirth === 'Tùy Chỉnh' && s.customBirth) ? s.customBirth : CREATION_CONFIG.BIRTHS[s.selectedBirth];

            const raceData = getRaceDataFromState(state);
            if (raceData) {
                if (state.selectedRace === 'Tùy Chỉnh' && state.customRace) {
                    const baseAttributes = state.customRace.base_attributes || {};
                    const attrTotal = Object.keys(CREATION_CONFIG.ATTRIBUTES)
                        .filter(key => key !== 'Tín Ngưỡng' && key !== 'Thân Hòa Vực Sâu')
                        .reduce((sum, key) => sum + (parseInt(baseAttributes[key]) || 0), 0);

                    let attrCost = 0;
                    if (attrTotal > 80) attrCost = 20 + (attrTotal - 80) * 2;
                    else if (attrTotal > 70) attrCost = (attrTotal - 70) * 2;
                    else if (attrTotal > 60) attrCost = -(70 - attrTotal) * 1.5;
                    else if (attrTotal > 50) attrCost = -(15 + (60 - attrTotal) * 1);
                    else attrCost = -25;
                    points -= attrCost;

                    if (state.customRace.traits && state.customRace.traits.length > 0) {
                        const totalBonus = Object.values(state.customRace.traits[0].bonus || {}).reduce((sum, val) => sum + val, 0);
                        points -= (totalBonus * 4);
                    }
                } else {
                    points -= (raceData.cost || 0);
                }
            }

            const birthData = getBirthDataFromState(state);
            if (birthData) {
                if (state.selectedBirth === 'Tùy Chỉnh' && state.customBirth) {
                    const totalBonus = Object.values(state.customBirth.bonus || {}).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                    points -= (totalBonus * 4);
                } else {
                    points -= (birthData.cost || 0);
                }
            }

            if (state.selectedImprint) {
                points -= (state.selectedImprint.cost || 0);
            }

            if (state.selectedTraits && state.selectedTraits.length > 0) {
                if (state.isSelfSelectingTraits) {
                    const traitsCost = state.selectedTraits.reduce((total, trait) => {
                        const cost = CREATION_CONFIG.TRAIT_RARITIES[trait.rarity]?.cost || calculateCustomTraitCost(trait.bonus);
                        return total + cost;
                    }, 0);
                    points -= traitsCost;
                }
            }

            if (state.hasReachedAbilityStep && state.attributes) {
                const baseRaceData = getRaceDataFromState(state);
                const baseAttributes = (baseRaceData ? baseRaceData.base_attributes : {}) || {};
                let netAttributeCost = 0;

                for (const attr in state.attributes) {
                    const isSpecial = attr === 'Tín Ngưỡng' || attr === 'Thân Hòa Vực Sâu';
                    const baseValue = baseAttributes[attr] !== undefined ? baseAttributes[attr] : (isSpecial ? 0 : 8);
                    const currentValue = state.attributes[attr];

                    if (currentValue > baseValue) {
                        for (let i = baseValue; i < currentValue; i++) {
                            netAttributeCost += getPointCost(i, 'increase', true);
                        }
                    } else if (currentValue < baseValue) {
                        for (let i = currentValue; i < baseValue; i++) {
                            netAttributeCost -= getPointCost(i, 'decrease', true);
                        }
                    }
                }
                points -= netAttributeCost;
            }

            return Math.round(points);
        }

