                            if (creationState.customRace) {
                                const race = creationState.customRace;
                                const baseAttributes = race.base_attributes || {};
                                const attrTotal = Object.keys(CREATION_CONFIG.ATTRIBUTES)
                                    .filter(key => key !== 'Tín Ngưỡng' && key !== 'Thân Hòa Vực Sâu')
                                    .reduce((sum, key) => sum + (parseInt(baseAttributes[key]) || 0), 0);

                                let attrCost = 0;
                                if (attrTotal > 80) attrCost = 20 + (attrTotal - 80) * 2;
                                else if (attrTotal > 70) attrCost = (attrTotal - 70) * 2;
                                else if (attrTotal > 60) attrCost = -(70 - attrTotal) * 1.5;
                                else if (attrTotal > 50) attrCost = -(15 + (60 - attrTotal) * 1);
                                else attrCost = -25;

                                let traitCost = 0;
                                if (race.traits && race.traits.length > 0) {
                                    const totalBonus = Object.values(race.traits[0].bonus || {}).reduce((sum, val) => sum + val, 0);
                                    traitCost = totalBonus * 4;
                                }

                                const totalCost = Math.round(attrCost + traitCost);

                                if (totalCost > 0) costText = `<span class="cost">(-${totalCost} điểm)</span>`;
                                else if (totalCost < 0) costText = `<span class="bonus">(+${-totalCost} điểm)</span>`;
