        function showCreationDetailPopup(type, name) {
            let title = '';
            let contentHtml = '';

            if (type === 'race') {
                const data = CREATION_CONFIG.RACES[name];
                if (!data) return;
                title = `Chi Tiết Chủng Tộc: ${name}`;

                let attributesHtml = '<h4>Thuộc Tính Cơ Bản</h4><div class="char-info-grid" style="grid-template-columns: 1fr 1fr 1fr 1fr;">';
                for(const attr in data.base_attributes) {
                    attributesHtml += `<div class="label">${attr}:</div><div>${data.base_attributes[attr]}</div>`;
                }
                attributesHtml += '</div>';

                let traitsHtml = '';
                if (data.traits && data.traits.length > 0) {
                    traitsHtml = '<h4>Thiên Phú Chủng Tộc</h4>';
                    data.traits.forEach(trait => {
                        traitsHtml += `
                            <div style="margin-bottom: 10px;">
                                <strong>${trait.name} [${trait.rarity}]</strong>
                                <p style="font-size: 0.9em; margin: 2px 0 0 0; color: #ccc;">${trait.desc}<br><em>Hiệu Ứng: ${trait.effects}</em></p>
                            </div>
                        `;
                    });
                }
                contentHtml = `${attributesHtml}<hr style="border-color: var(--separator-color);">${traitsHtml}`;

            } else if (type === 'class') {
                const data = CREATION_CONFIG.CLASSES[name];
                if (!data) return;
                title = `Chi Tiết Chức Nghiệp: ${name}`;

                let itemHtml = '<h4>Vật Phẩm Khởi Đầu</h4>';
                if (data.item && data.item !== 'Không') {
                    const itemMatch = data.item.match(/【(.*?)】/);
                    if (itemMatch) {
                        const [itemName, itemDesc, itemType, itemEffect] = itemMatch[1].split('|');
                        itemHtml += `
                            <div class="char-info-grid">
                                <div class="label">Tên:</div><div>${itemName}</div>
                                <div class="label">Loại:</div><div>${itemType}</div>
                                <div class="label">Mô Tả:</div><div>${itemDesc}</div>
                                <div class="label">Hiệu Ứng:</div><div>${itemEffect}</div>
                            </div>
                        `;
                    }
                } else {
                    itemHtml += '<p>Không có vật phẩm khởi đầu đặc biệt.</p>';
                }
                contentHtml = itemHtml;
            }

            showCustomDialog({
                title: title,
                message: contentHtml,
                buttons: [{ text: 'Đóng', value: () => true }]
            });
        }
