            if (!creationState.attributes || Object.keys(creationState.attributes).length === 0) {
                creationState.attributes = {};
                Object.keys(CREATION_CONFIG.ATTRIBUTES).forEach(key => {
                    const isSpecial = key === 'Tín Ngưỡng' || key === 'Thân Hòa Vực Sâu';
                    creationState.attributes[key] = baseAttributes[key] !== undefined ? baseAttributes[key] : (isSpecial ? 0 : 8);
                });
            }

