            `;

            const grid = contentEl.querySelector('.attribute-allocation-grid');
            const pointsSummaryEl = document.querySelector('#points-summary-fixed .cost');

            const getAbsoluteMin = (attrName) => (attrName === 'Tín Ngưỡng' || attrName === 'Thân Hòa Vực Sâu') ? 0 : 1;

            const updateUI = () => {
                const remainingPoints = calculateRemainingPoints(creationState);
                pointsSummaryEl.textContent = remainingPoints;

                grid.querySelectorAll('.attribute-item').forEach(item => {
                    const attr = item.querySelector('.attr-btn').dataset.attr;
                    const value = creationState.attributes[attr];
                    const absoluteMin = getAbsoluteMin(attr);

                    const costToIncrease = getPointCost(value, 'increase', true);
                    const refundToDecrease = getPointCost(value, 'decrease', true);

                    const costTextEl = item.querySelector('.cost-text');
                    costTextEl.innerHTML = `
                        <span style="color: #e57373;">(-${refundToDecrease})</span>
                        <span style="color: #66bb6a;">(+${costToIncrease})</span>
                    `;

                    item.querySelector('.value').value = value;
                    item.querySelector('.plus').disabled = value >= ATTR_MAX || remainingPoints < costToIncrease;
                    item.querySelector('.minus').disabled = value <= absoluteMin;
                });
            };

            Object.entries(CREATION_CONFIG.ATTRIBUTES).forEach(([key, desc]) => {
                const isSpecial = key === 'Tín Ngưỡng' || key === 'Thân Hòa Vực Sâu';
                const baseValue = baseAttributes[key] !== undefined ? baseAttributes[key] : (isSpecial ? 0 : 8);
                const currentValue = creationState.attributes[key];

                const item = document.createElement('div');
                item.className = 'attribute-item';
                item.innerHTML = `
                    <div class="name-desc">
                        <strong title="${desc}">${key} (Cơ Bản: ${baseValue}) <span class="cost-text" style="font-size:0.8em; font-weight:normal;"></span></strong>
                    </div>
                    <div class="attribute-controls">
                        <button class="attr-btn minus" data-attr="${key}">-</button>
                        <input type="number" class="value" data-attr-val="${key}" value="${currentValue}" min="${getAbsoluteMin(key)}" max="${ATTR_MAX}">
                        <button class="attr-btn plus" data-attr="${key}">+</button>
                    </div>
                `;

                const inputEl = item.querySelector('input.value');
                inputEl.addEventListener('change', () => {
                    let newValue = parseInt(inputEl.value);
                    const oldValue = creationState.attributes[key];
                    const absoluteMin = getAbsoluteMin(key);

                    if (isNaN(newValue)) newValue = oldValue;
                    newValue = Math.max(absoluteMin, Math.min(ATTR_MAX, newValue));

                    const tempState = JSON.parse(JSON.stringify(creationState));
                    tempState.attributes[key] = newValue;

                    if(calculateRemainingPoints(tempState) < 0) {
                        showCustomAlert('Không đủ Điểm Số Mệnh để thực hiện thay đổi này！');
                        inputEl.value = oldValue;
                    } else {
                        creationState.attributes[key] = newValue;
                    }
                    updateUI();
                });

                item.querySelector('.plus').addEventListener('click', () => {
                    const attr = key;
                    const cost = getPointCost(creationState.attributes[attr], 'increase', true);
                    const remainingPoints = calculateRemainingPoints();

                    if (creationState.attributes[attr] < ATTR_MAX && remainingPoints >= cost) {
                        creationState.attributes[attr]++;
                        updateUI();
                    }
                });

                item.querySelector('.minus').addEventListener('click', () => {
                    const attr = key;
                    const absoluteMin = getAbsoluteMin(attr);
                    if (creationState.attributes[attr] > absoluteMin) {
                        creationState.attributes[attr]--;
                        updateUI();
                    }
                });

                grid.appendChild(item);
            });

            navEl.querySelector('#creation-prev-btn').addEventListener('click', () => {
                creationState.currentStep--;
                renderCreationStep();
            });
            navEl.querySelector('#creation-next-btn').addEventListener('click', () => {
                creationState.currentStep++;
                renderCreationStep();
            });
            document.getElementById('save-preset-btn').addEventListener('click', saveCreationPreset);

            updateUI();
        }

