                async function handleRandomizeBatchTraits(event) {
            const count = parseInt(event.currentTarget.dataset.count);
            const traitCosts = { 1: 10, 2: 20, 3: 30, 4: 40, 5: 50 };
            const cost = traitCosts[count];

            if (calculateRemainingPoints() < cost) {
                await showCustomAlert('Không đủ Điểm Số Mệnh để rút！');
                return;
            }

            creationState.totalPoints -= cost;

            creationState.selectedTraits = [];

            const container = document.getElementById('trait-options-container');
            container.classList.add('animating');

            setTimeout(async () => {
                const newTraits = await generateRandomTraits(count);
                creationState.selectedTraits = newTraits;
                renderCreationStep();

                const contentEl = document.getElementById('creation-content');
                if (contentEl) {
                    contentEl.scrollTo({ top: 0, behavior: 'smooth' });
                }
            }, 250);
        }

        async function generateRandomTraits(count = 6) {
            const allTraits = [];
            for (const rarity in CREATION_CONFIG.TRAITS) {
                CREATION_CONFIG.TRAITS[rarity].forEach(trait => {
                    allTraits.push({ ...trait, rarity });
                });
            }

            const customTraits = await getCustomTraits();
            const activeCustomTraits = customTraits.filter(t => t.inPool);
            allTraits.push(...activeCustomTraits);

            const traits = [];
            const rarityWeights = { 'Tiêu Cực': 10, 'Phổ Thông': 30, 'Hiếm Có': 25, 'Sử Thi': 20, 'Truyền Thuyết': 10, 'Thần Tích': 5 };
            const totalWeight = Object.values(rarityWeights).reduce((sum, weight) => sum + weight, 0);

            const pickRarity = () => {
                let random = Math.random() * totalWeight;
                for (const rarity in rarityWeights) {
                    if (random < rarityWeights[rarity]) {
                        return rarity;
                    }
                    random -= rarityWeights[rarity];
                }
                return 'Phổ Thông';
            };

            while(traits.length < count) {
                const randRarity = pickRarity();
                const traitPool = allTraits.filter(t => t.rarity === randRarity);
                if (traitPool.length === 0) continue;

                const randTrait = traitPool[Math.floor(Math.random() * traitPool.length)];
                if (!traits.some(t => t.name === randTrait.name)) {
                    traits.push(randTrait);
                }
            }
            return traits;
        }

