        async function openSelfSelectTraitModal() {
            if (creationState.selectedTraits.length > 0 && !creationState.isSelfSelectingTraits) {
                if (!await showCustomConfirm('Tự chọn thiên phú sẽ xóa hết các thiên phú đã rút hiện tại, bạn có muốn tiếp tục không?')) {
                    return;
                }
            } else {
                if (!await showCustomConfirm('Vào giao diện tự chọn thiên phú sẽ xóa tất cả các thiên phú đã chọn hiện tại và bắt đầu lại. Bạn có muốn tiếp tục không?')) {
                    return;
                }
            }

            creationState.selectedTraits = [];
            creationState.isSelfSelectingTraits = true;

            const overlay = document.getElementById('self-select-trait-overlay');
            overlay.innerHTML = `
                <div class="imprint-select-modal modal">
                    <button class="modal-close-btn">&times;</button>
                    <h4>Tự Chọn Thiên Phú (Tối đa 5)</h4>
                    <div id="trait-select-tabs" class="modal-tabs">
