                        <button class="tab-button" data-tab="custom">Thiên Phú Tùy Chỉnh</button>
                    </div>
                    <div class="imprint-list-container">
                        <div id="default-traits-container" class="tab-content active"></div>
                        <div id="custom-traits-container" class="tab-content"></div>
                    </div>
                    <div class="imprint-selection-footer">
                        <div id="self-select-trait-details"></div>
                        <button id="confirm-self-select-trait-btn" class="major-action-button">Xác Nhận Lựa Chọn</button>
                    </div>
                </div>
            `;

            const defaultContainer = overlay.querySelector('#default-traits-container');
            const customContainer = overlay.querySelector('#custom-traits-container');
            const detailsEl = overlay.querySelector('#self-select-trait-details');
            const confirmBtn = overlay.querySelector('#confirm-self-select-trait-btn');

            let tempSelected = [...creationState.selectedTraits];
            let currentCost = 0;

            const defaultTraits = [];
            for (const rarity in CREATION_CONFIG.TRAITS) {
                defaultTraits.push({ rarity, traits: CREATION_CONFIG.TRAITS[rarity] });
            }
            const customTraits = (await getCustomTraits()).filter(t => t.inPool);

            const renderList = (container, traitsData, isCustom = false) => {
                if (isCustom) {
                    if (traitsData.length === 0) {
                        container.innerHTML = `<p style="text-align:center; opacity:0.7; padding: 20px;">Không có thiên phú tùy chỉnh nào khả dụng, vui lòng tạo và bật trong trình quản lý trước.</p>`;
                        return;
                    }
                    const list = traitsData.map(trait => {
                        const validationError = validateCustomTraitStructure(trait);
                        const cost = calculateCustomTraitCost(trait.bonus);
                        const displayCost = -cost;
                        const costText = displayCost > 0 ? `+${displayCost}` : displayCost;
                        const costClass = displayCost >= 0 ? 'bonus' : 'penalty';
                        const invalidClass = validationError ? 'invalid' : '';
                        const title = validationError ? `Lỗi định dạng dữ liệu: ${validationError}` : trait.desc;
                        return `<li data-name="${trait.name}" data-rarity="${trait.rarity}" data-custom="true" data-cost="${cost}" class="${invalidClass}" title="${title}"><strong>${trait.name} [${trait.rarity}]</strong><p>${trait.desc} <span class="${costClass}">(${costText} điểm)</span></p></li>`;
                    }).join('');
                    container.innerHTML = `<ul class="imprint-list">${list}</ul>`;
                } else {
                    traitsData.forEach(({ rarity, traits }) => {
                        if (traits.length === 0) return;
                        const group = document.createElement('div');
                        group.className = 'imprint-rank-group';
                        const cost = CREATION_CONFIG.TRAIT_RARITIES[rarity].cost;
                        const displayCost = -cost;
                        const list = traits.map(trait => `<li data-name="${trait.name}" data-rarity="${rarity}" data-cost="${cost}" title="${trait.desc}"><strong>${trait.name}</strong><p>${trait.desc} <span class="penalty">(${displayCost} điểm)</span></p></li>`).join('');
                        group.innerHTML = `<h3 class="rank-title">${rarity}</h3><ul class="imprint-list">${list}</ul>`;
                        container.appendChild(group);
                    });
                }
            };

            renderList(defaultContainer, defaultTraits);
            renderList(customContainer, customTraits, true);

            const updateSelection = () => {
                currentCost = 0;
                overlay.querySelectorAll('li').forEach(li => {
                    const isSelected = tempSelected.some(t => t.name === li.dataset.name);
                    if (isSelected) {
                        currentCost += parseInt(li.dataset.cost);
                    }
                    li.classList.toggle('selected', isSelected);
                });

                const remainingPointsAfterSelection = calculateRemainingPoints() - currentCost;

                let costHtml = '';
                if (currentCost > 0) {
                    costHtml = `Tiêu hao <span class="penalty">${currentCost}</span> điểm`;
                } else if (currentCost < 0) {
                    costHtml = `Hoàn trả <span class="bonus">${-currentCost}</span> điểm`;
                } else {
                    costHtml = 'Tốn 0 điểm';
                }

                detailsEl.innerHTML = `Đã Chọn: ${tempSelected.length}/5 | ${costHtml} | Sau khi kết thúc còn lại: <span class="${remainingPointsAfterSelection >= 0 ? 'bonus' : 'penalty'}">${remainingPointsAfterSelection}</span>`;
                confirmBtn.disabled = remainingPointsAfterSelection < 0;
            };

            overlay.querySelectorAll('li').forEach(li => {
                li.addEventListener('click', () => {
                    if (li.classList.contains('invalid')) {
                        showCustomAlert(li.title);
                        return;
                    }

                    const traitName = li.dataset.name;
                    const selectedIndex = tempSelected.findIndex(t => t.name === traitName);

                    if (selectedIndex > -1) {
                        tempSelected.splice(selectedIndex, 1);
                    } else {
                        if (tempSelected.length >= 5) {
                            showCustomAlert('Chỉ có thể chọn tối đa 5 thiên phú！'); return;
                        }
                        const rarity = li.dataset.rarity;
                        const isCustom = li.dataset.custom === 'true';
