                async function openImprintDrawModal() {
            const cost = 10;
            const currentRemaining = calculateRemainingPoints();
            const oldImprintCost = creationState.selectedImprint ? creationState.selectedImprint.cost : 0;
            const tempTotalPoints = creationState.totalPoints;

            if (currentRemaining < cost) {
                await showCustomAlert('Không đủ 10 Điểm Số Mệnh để rút thẻ vận mệnh！');
                return;
            }

            if (creationState.selectedImprint) {
                creationState.totalPoints += oldImprintCost;
            }
            creationState.totalPoints -= cost;
            creationState.selectedImprint = null;

            const overlay = document.getElementById('imprint-draw-overlay');
            const cardArea = overlay.querySelector('.tarot-card-area');
            const infoPanel = overlay.querySelector('.draw-info-panel');
            const closeBtn = overlay.querySelector('.modal-close-btn');

            cardArea.innerHTML = '';
            infoPanel.textContent = 'Hãy rút một lá bài vận mệnh thuộc về bạn...';
            cardArea.classList.remove('selection-made');
            closeBtn.style.display = 'block';

            const getRankFromImprint = (imprint) => {
                for (const rank in CREATION_CONFIG.SOUL_IMPRINTS) {
                    if (CREATION_CONFIG.SOUL_IMPRINTS[rank].some(i => i.id === imprint.id)) {
                        return rank;
                    }
                }
                return 'F';
            };

            const drawnCardsData = [];
            const rankWeights = { 'C': 60, 'B': 35, 'A': 14, 'S': 6 };
            const totalWeight = Object.values(rankWeights).reduce((sum, weight) => sum + weight, 0);

            const pickRank = () => {
                let random = Math.random() * totalWeight;
                for (const rank in rankWeights) {
                    if (random < rankWeights[rank]) {
                        return rank;
                    }
                    random -= rankWeights[rank];
                }
                return 'C';
            };

            while (drawnCardsData.length < 3) {
                const randRank = pickRank();
                const imprintPool = CREATION_CONFIG.SOUL_IMPRINTS[randRank];
                if (!imprintPool || imprintPool.length === 0) continue;
                const randImprint = { ...imprintPool[Math.floor(Math.random() * imprintPool.length)], rank: randRank };
                if (!drawnCardsData.some(c => c.id === randImprint.id)) {
                    drawnCardsData.push(randImprint);
                }
            }

            drawnCardsData.forEach(imprintData => {
                const cardEl = document.createElement('div');
                const rank = imprintData.rank || getRankFromImprint(imprintData);
                cardEl.className = `tarot-card rank-${rank}`;
                cardEl.innerHTML = `
                    <div class="card-face card-back"><i class="fas fa-question"></i></div>
                    <div class="card-face card-front">
                        <div class="card-rank-display">${rank}</div>
                        <div class="card-title">${imprintData.name}</div>
                        <i class="fas ${imprintData.icon} card-icon"></i>
                        <div class="card-cost">${imprintData.effect}</div>
                    </div>
                `;

                cardEl.addEventListener('click', () => {
                    if (cardArea.classList.contains('selection-made')) return;

                    cardArea.classList.add('selection-made');
                    cardEl.classList.add('chosen');
                    closeBtn.style.display = 'none';

                    cardEl.classList.add('is-flipped');

                    setTimeout(() => {
                        infoPanel.innerHTML = `<button id="confirm-draw-btn" class="major-action-button">Xác Nhận</button>`;
                        infoPanel.querySelector('#confirm-draw-btn').addEventListener('click', () => {
                            creationState.selectedImprint = { ...imprintData, cost: 0 };
                            overlay.classList.remove('visible');
                            renderCreationStep();
                        });
                    }, 500);
                });
                cardArea.appendChild(cardEl);
            });

            closeBtn.onclick = () => {
                creationState.totalPoints = tempTotalPoints;
                overlay.classList.remove('visible');
                renderCreationStep();
            };
            overlay.classList.add('visible');
        }

