        function redrawEditingPolygon() {
            if (!currentlyEditingPolygon) return;

            const editSvgLayer = document.getElementById('map-edit-svg-layer');
            if (!editSvgLayer) return;

            let previewPolygon = editSvgLayer.querySelector('polygon');
            const { region } = currentlyEditingPolygon;
            let pointsToDraw = [];

            if (Array.isArray(region.points) && region.points.length > 0 && region.points[0].outer) {
                pointsToDraw = region.points[0].outer;
            } else if (region.points && region.points.outer) {
                pointsToDraw = region.points.outer;
            } else if (Array.isArray(region.points)) {
                pointsToDraw = region.points;
            }

            if (pointsToDraw.length < 3) {
                if (previewPolygon) previewPolygon.remove();
                return;
            }

            const pointsStr = pointsToDraw.map(p => `${p.x},${p.y}`).join(' ');

            if (!previewPolygon) {
                previewPolygon = document.createElementNS('http://www.w3.org/2000/svg', 'polygon');
                previewPolygon.style.fill = region.style?.fill || 'rgba(130, 216, 247, 0.2)';
                previewPolygon.style.stroke = region.style?.stroke || '#82D8F7';
                previewPolygon.style.pointerEvents = 'none';
                editSvgLayer.appendChild(previewPolygon);
            }

            previewPolygon.setAttribute('points', pointsStr);
            const pannable = document.getElementById('main-map-pannable');
            const scale = parseFloat(pannable.dataset.scale) || 1;
            previewPolygon.style.strokeWidth = `${1.5 / scale}px`;
        }

        function displayVerticesForEditing(regionData) {
            const pannable = document.getElementById('main-map-pannable');
            const vertexContainer = pannable.querySelector('#main-map-locations-container');
            if (!vertexContainer) return;

            vertexContainer.querySelectorAll('.map-edit-vertex-html').forEach(v => v.remove());

            let pointsToEdit = [];
            let pointsObjectToUpdate = null;

            if (Array.isArray(regionData.points) && regionData.points.length > 0 && regionData.points[0].outer) {
                pointsToEdit = regionData.points[0].outer;
                pointsObjectToUpdate = regionData.points[0];
            } else if (regionData.points && regionData.points.outer) {
                pointsToEdit = regionData.points.outer;
                pointsObjectToUpdate = regionData.points;
            } else if (Array.isArray(regionData.points)) {
                pointsToEdit = regionData.points;
                pointsObjectToUpdate = regionData;
            }

            if (pointsToEdit.length === 0) return;

            const originalPath = document.querySelector(`#main-map-svg-layer [data-id="${regionData.id}"]`);
            if (originalPath) {
                originalPath.style.visibility = 'hidden';
            }
            redrawEditingPolygon();

            const scale = parseFloat(pannable.dataset.scale) || 1;

            pointsToEdit.forEach((p, index) => {
                const vertex = document.createElement('div');
                vertex.className = 'map-edit-vertex-html';
                vertex.dataset.index = index;
                vertex.style.left = `${p.x}%`;
                vertex.style.top = `${p.y}%`;
                vertex.style.setProperty('--map-marker-scale', 1 / scale);

                const onMove = () => redrawEditingPolygon();
                const onEnd = () => {
                    const pointToSave = pointsToEdit[index];
                    pointToSave.x = parseFloat(pointToSave.x.toFixed(4));
                    pointToSave.y = parseFloat(pointToSave.y.toFixed(4));

                    finishVertexEditing(true);
                };
                const startVertexDrag = createVertexDragHandler(pointsToEdit, index, onMove, onEnd);

                vertex.addEventListener('mousedown', startVertexDrag);
                vertex.addEventListener('touchstart', startVertexDrag, { passive: false });
                vertexContainer.appendChild(vertex);
            });
        }

		<!-- DNEW Edit Func: Nhấp tên npc gần đây trên map sẽ hiện info -->
        async function handleMapQueryClick(event, mode = 'query', contextPannable, contextContainer, contextViewport, locationsDataForCheck) {
            if (currentMapEditMode !== null) return;

            const pannable = contextPannable;
            const locationsContainer = contextContainer;

            if (queryMarkerElement) queryMarkerElement.remove();

            let x, y;
            if (event._map_override_location) {
                const location = event._map_override_location;
                let markerPos = location.marker;
                if (location.type === 'polygon' && !location.marker) {
                    let allPoints = location.points.outer || location.points;
                    const centerX = allPoints.reduce((sum, p) => sum + p.x, 0) / allPoints.length;
                    const centerY = allPoints.reduce((sum, p) => sum + p.y, 0) / allPoints.length;
                    markerPos = { top: `${centerY}%`, left: `${centerX}%` };
                }
                x = parseFloat(markerPos.left);
                y = parseFloat(markerPos.top);
            } else {
                const viewportRect = contextViewport.getBoundingClientRect();
                const scale = parseFloat(pannable.dataset.scale) || 1;
                const panX = parseFloat(pannable.dataset.panX) || 0;
                const panY = parseFloat(pannable.dataset.panY) || 0;
                const clickInViewportX = event.clientX - viewportRect.left;
                const clickInViewportY = event.clientY - viewportRect.top;
                const worldX = (clickInViewportX - panX) / scale;
                const worldY = (clickInViewportY - panY) / scale;
                x = (worldX / pannable.offsetWidth) * 100;
                y = (worldY / pannable.offsetHeight) * 100;
            }

            queryMarkerElement = document.createElement('div');
            queryMarkerElement.className = 'map-query-marker';
            queryMarkerElement.style.left = `${x}%`;
            queryMarkerElement.style.top = `${y}%`;
            locationsContainer.appendChild(queryMarkerElement);
            updateAllMapScales();

            let parentRegion = null;
            let parentSubRegion = null;
            (locationsDataForCheck.mainRegions || []).forEach(region => {
                if(isPointInPolygon({x,y}, region.points)) parentRegion = region;
            });
            (locationsDataForCheck.subRegions || []).forEach(subRegion => {
                if(isPointInPolygon({x,y}, subRegion.points)) {
                    parentSubRegion = subRegion;
                    if (!parentRegion) parentRegion = (locationsDataForCheck.mainRegions || []).find(r => r.name === subRegion.parentName);
                }
            });

            let locationString = 'Khu Vực Không Rõ';
            let areaInfoHtml = '';
            if (parentRegion) {
                locationString = parentRegion.name;
                const mainArea = calculatePolygonArea(parentRegion.points);
                areaInfoHtml += `<li><span class="label">Khu Vực Chính:</span> <span class="value">${parentRegion.name} (Khoảng ${mainArea.toLocaleString()} km²)</span></li>`;
                if (parentSubRegion) {
                    locationString += ` / ${parentSubRegion.name}`;
                    const subArea = calculatePolygonArea(parentSubRegion.points);
                    areaInfoHtml += `<li><span class="label">Khu Vực Phụ:</span> <span class="value">${parentSubRegion.name} (Khoảng ${subArea.toLocaleString()} km²)</span></li>`;
                }
            }

            let distanceHtml = '';
            let distanceToPlayer = -1;
            if (currentPlayerData && currentPlayerData.position && currentPlayerData.position.x >= 0) {
                const playerPos = currentPlayerData.position;
                distanceToPlayer = calculateDistance(playerPos, {x, y}, locationsDataForCheck);
                distanceHtml = `<li><span class="label">Cách Bạn:</span> <span class="value">Khoảng ${distanceToPlayer} km</span></li>`;
            }

            const landmarks = (locationsDataForCheck.landmarks || []);
            const nearbyLandmarks = landmarks.map(lm => ({ ...lm, distance: calculateDistance({x, y}, lm, locationsDataForCheck) }))
                .filter(lm => lm.distance > 0).sort((a,b) => a.distance - b.distance).slice(0, 3);
            let nearbyLandmarksHtml = nearbyLandmarks.length > 0
                ? nearbyLandmarks.map(lm => `<li><span class="label">- ${lm.name}</span> <span class="value">Khoảng ${lm.distance} km</span></li>`).join('')
                : '<li><span class="label">Gần đây không có địa danh nào được biết.</span></li>';

            const nearbyNpcs = Object.values(characterDatabase).filter(c => c.isPresent && c.position)
                .map(c => ({...c, distance: calculateDistance({x, y}, c.position, locationsDataForCheck)}))
                .filter(c => c.distance <= 5)
                .sort((a, b) => a.distance - b.distance);
			<!-- <li> empty ban đầu-->
            let nearbyNpcsHtml = nearbyNpcs.length > 0
                ? nearbyNpcs.map(c => `<li class="npc-list-item-query" data-npc-id="${c.id}" style="cursor: pointer;"><span class="label">- ${c.name}</span> <span class="value">Khoảng ${c.distance.toFixed(1)} km</span></li>`).join('')
                : '<li><span class="label">Không có NPC nào trong phạm vi 5 km.</span></li>';

            let infobox = document.getElementById('map-query-infobox');
            if (!infobox) {
                infobox = document.createElement('div');
                infobox.id = 'map-query-infobox';
            }
            contextViewport.appendChild(infobox);

            if (mode === 'birthplace_selection') {
                queryMarkerElement.classList.add('high-z-marker');
                infobox.classList.add('high-z-infobox');
            } else {
                queryMarkerElement.classList.remove('high-z-marker');
                infobox.classList.remove('high-z-infobox');
            }

            infobox.innerHTML = `
                <h5>Thông Tin Điểm Truy Vấn</h5>
                <ul>
                    <li><span class="label">Tọa Độ:</span> <span class="value">${x.toFixed(2)}%, ${y.toFixed(2)}%</span></li>
                    <li><span class="label">Vị Trí:</span> <span class="value">${locationString}</span></li>
                    ${distanceHtml}
                </ul>
                <details id="map-query-details" style="margin-top: 10px;">
                    <summary style="cursor: pointer; color: var(--accent-color); font-weight: bold; padding: 5px 0;">Hiển Thị Thông Tin Chi Tiết</summary>
                    <div style="padding-top: 10px;">
                        <hr style="border-color: var(--separator-color); opacity: 0.5; margin: 0 0 10px 0;">
                        <h5>Chi Tiết Khu Vực</h5><ul>${areaInfoHtml || '<li><span class="label">Vùng Hoang Dã Không Rõ</span></li>'}</ul>
                        ${nearbyNpcs.length > 0 ? `
                        <hr style="border-color: var(--separator-color); opacity: 0.5; margin: 10px 0;">
                        <h5>NPC Gần Đây (5km)</h5><ul>${nearbyNpcsHtml}</ul>
                        ` : ''}
                        <hr style="border-color: var(--separator-color); opacity: 0.5; margin: 10px 0;">
                        <h5>Địa Danh Gần Đây</h5><ul>${nearbyLandmarksHtml}</ul>
                    </div>
                </details>
