        function calculatePolygonArea(pointsData) {
            let points = [];
            if (Array.isArray(pointsData) && pointsData.length > 0 && pointsData[0]?.outer) {
                points = pointsData[0].outer;
            } else if (pointsData?.outer) {
                points = pointsData.outer;
            } else if (Array.isArray(pointsData)) {
                points = pointsData;
            }

            if (points.length < 3) return 0;

            let area = 0;
            for (let i = 0; i < points.length; i++) {
                const p1 = points[i];
                const p2 = points[(i + 1) % points.length];
                area += (p1.x * p2.y - p2.x * p1.y);
            }
            const percentageArea = Math.abs(area / 2);

            const mapScale = currentLocationsData.mapScaleKm || 200;
            const mapImg = document.getElementById('main-map-img');
            const aspectRatio = (mapImg && mapImg.naturalHeight > 0 && mapImg.naturalWidth > 0)
                ? mapImg.naturalHeight / mapImg.naturalWidth
                : 1;

            const realArea = (percentageArea / (100 * 100)) * mapScale * (mapScale / aspectRatio);
            return realArea;
        }

        function getPolygonClippingInput(pointsData) {
            if (!pointsData) return [];
            if (Array.isArray(pointsData) && pointsData.length > 0 && pointsData[0]?.outer) {
                return pointsData.map(part => [part.outer.map(p => [p.x, p.y]), ...(part.holes || []).map(h => h.map(p => [p.x, p.y]))]);
            }
            if (pointsData.outer) {
                return [[pointsData.outer.map(p => [p.x, p.y]), ...(pointsData.holes || []).map(h => h.map(p => [p.x, p.y]))]];
            }
            if (Array.isArray(pointsData)) {
                return [[pointsData.map(p => [p.x, p.y])]];
            }
            return [];
        }

        function createPolygonPathData(pointsData) {
            let pathString = '';

            const formatPoints = (points) => {
                if (!points || points.length === 0) return '';
                const start = points[0];
                return `M ${start.x},${start.y} ` + points.slice(1).map(p => `L ${p.x},${p.y}`).join(' ') + ' Z';
            };

            if (Array.isArray(pointsData) && pointsData.length > 0 && pointsData[0].outer) {
                pathString = pointsData.map(part => createPolygonPathData(part)).join(' ');
            } else if (Array.isArray(pointsData)) {
                pathString = formatPoints(pointsData);
            } else if (pointsData && pointsData.outer) {
                pathString = formatPoints(pointsData.outer);
                if (pointsData.holes) {
                    pointsData.holes.forEach(hole => {
                        pathString += ' ' + formatPoints(hole);
                    });
                }
            }
            return pathString;
        }

        function renderPlayerMapMarker(container) {
            if (!container) return;
            container.querySelectorAll('.map-location-marker.current-location').forEach(marker => marker.remove());

            if (currentPlayerData && currentPlayerData.position) {
                const playerMarker = document.createElement('div');
                playerMarker.className = 'map-location-marker current-location';
                playerMarker.style.left = `${currentPlayerData.position.x}%`;
                playerMarker.style.top = `${currentPlayerData.position.y}%`;
                playerMarker.style.zIndex = '12';
                playerMarker.innerHTML = `<div class="dot"></div><div class="label">${currentPlayerData.name}</div>`;
                container.appendChild(playerMarker);
            }
        }

        function renderMapLocations(container, locationsData, isEditor, clickCallback = null, isCustomMap = false, isRestoringHistory = false) {
            container.innerHTML = '';

            const pannable = container.closest('.map-pannable');
            const svgLayer = pannable ? pannable.querySelector('.map-svg-layer') : null;
            if (svgLayer) svgLayer.innerHTML = '';

            let realmData = locationsData || { mainRegions: [], subRegions: [], landmarks: [] };

            (realmData.landmarks || []).forEach(landmark => {
                landmark.mainRegionName = null;
                landmark.subRegionName = null;
                if (!landmark.marker) return;

                const point = {
                    x: parseFloat(landmark.marker.left),
                    y: parseFloat(landmark.marker.top)
                };

                for (const subRegion of (realmData.subRegions || [])) {
                    if (subRegion.points && isPointInPolygon(point, subRegion.points)) {
                        landmark.subRegionName = subRegion.name;
                        landmark.mainRegionName = subRegion.parentName;
                        break;
                    }
                }
                if (!landmark.mainRegionName) {
                    for (const mainRegion of (realmData.mainRegions || [])) {
                        if (mainRegion.points && isPointInPolygon(point, mainRegion.points)) {
                            landmark.mainRegionName = mainRegion.name;
                            break;
                        }
                    }
                }
            });

            const renderPolygon = (region, className) => {
                if (region.type !== 'polygon' || !region.points || !svgLayer) return;

                const path = document.createElementNS('http://www.w3.org/2000/svg', 'path');
                path.dataset.id = region.id;
                const pathData = createPolygonPathData(region.points);
                if (!pathData) return;

                path.setAttribute('d', pathData);
                path.setAttribute('class', `map-polygon ${className}`);
                path.setAttribute('fill-rule', 'evenodd');

                const defaultFill = className === 'main-region-poly' ? 'rgba(130, 216, 247, 0.2)' : 'rgba(70, 130, 180, 0.3)';
                const defaultStroke = 'rgba(0,0,0,0)';

                path.style.fill = region.style?.fill || defaultFill;
                path.style.stroke = region.style?.stroke || defaultStroke;

                const currentPannable = container.closest('.map-pannable');
                const scale = currentPannable ? (parseFloat(currentPannable.dataset.scale) || 1) : 1;
                path.style.strokeWidth = `${1.5 / scale}px`;

                if (currentMapEditMode === 'edit-landmark') {
                    path.style.pointerEvents = 'none';
                    path.style.zIndex = '1';
                }

                svgLayer.appendChild(path);
                return path;
            };

            (realmData.mainRegions || []).forEach(region => renderPolygon(region, 'main-region-poly'));
            (realmData.subRegions || []).forEach(region => renderPolygon(region, 'sub-region-poly'));

            const clearHighlight = () => {
                pannable.querySelectorAll('.map-polygon.highlight, .map-location-marker.highlight').forEach(el => {
                    el.classList.remove('highlight');
                });
                const sidebar = document.getElementById('map-editor-sidebar');
                if(sidebar) sidebar.querySelectorAll('.creator-item.selected').forEach(el => el.classList.remove('selected'));
            };

            pannable.addEventListener('click', (e) => {
                if (e.target === pannable || e.target === pannable.querySelector('img')) {
                    clearHighlight();
                }
            });

            const allLocations = [
                ...(realmData.mainRegions || []),
                ...(realmData.subRegions || []),
                ...(realmData.landmarks || [])
            ];

            allLocations.forEach((loc, index) => {
                const polygonEl = svgLayer ? svgLayer.querySelector(`[data-id="${loc.id}"]`) : null;
                const markerEl = document.createElement('div');

                if (loc.marker || loc.type === 'polygon') {
                    markerEl.className = 'map-location-marker';
                    markerEl.style.zIndex = '10';

                    let markerPos = loc.marker;
                    if (loc.type === 'polygon' && !loc.marker) {
                        let allPoints = [];
                        if (Array.isArray(loc.points) && loc.points.length > 0 && loc.points[0].outer) {
                            allPoints = loc.points.flatMap(p => p.outer);
                        } else if (loc.points.outer) {
                            allPoints = loc.points.outer;
                        } else {
                            allPoints = loc.points;
                        }

                        if (allPoints && allPoints.length > 0) {
                            const centerX = allPoints.reduce((sum, p) => sum + p.x, 0) / allPoints.length;
                            const centerY = allPoints.reduce((sum, p) => sum + p.y, 0) / allPoints.length;
                            markerPos = { top: `${centerY}%`, left: `${centerX}%` };
                        }
                    }

                    if (markerPos) {
                        markerEl.style.top = markerPos.top;
                        markerEl.style.left = markerPos.left;
                    }
                    markerEl.dataset.id = loc.id;
                    markerEl.dataset.index = index;

                    if (loc.type === 'polygon') {
                        markerEl.innerHTML = `<div class="label">${loc.name}</div>`;
                    } else {
                        markerEl.innerHTML = `<div class="dot"></div><div class="label">${loc.name}</div>`;
                    }
                    container.appendChild(markerEl);
                }
                const interactiveElements = [markerEl, polygonEl].filter(Boolean);

                const setupInteractions = (el) => {
                    let clickTimeout = null;

                    const handleSingleClick = async () => {
                        if (isEditor) {
                            if (currentMapEditMode === 'edit-vertices' && loc.type === 'polygon') {
                                if (selectedMapElement && selectedMapElement.id === loc.id) {
                                    if (currentlyEditingPolygon) {
                                         if (await showCustomConfirm(`Bạn đang chỉnh sửa "${currentlyEditingPolygon.region.name}". Bạn có muốn hủy bỏ các thay đổi không?`)) {
                                            clearSelection();
                                         }
                                    } else {
                                        clearSelection();
                                    }
                                } else {
                                    if (currentlyEditingPolygon) {
                                        if (await showCustomConfirm(`Bạn đang chỉnh sửa "${currentlyEditingPolygon.region.name}". Bạn có muốn hủy bỏ các thay đổi và chuyển sang "${loc.name}" không?`)) {
                                            clearSelection();
                                            selectElement(loc);
                                        }
                                    } else {
                                        selectElement(loc);
                                    }
                                }
                            }
                        } else {
                             if (selectedMapElement && selectedMapElement.id === loc.id) {
                                clearSelection();
                            } else {
                                selectElement(loc);
                            }
                        }
                    };

                    const handleDoubleClick = async () => {
                         if (isEditor) {
                            if (currentMapEditMode === 'edit-landmark' && loc.type === 'point') {
                                const locationsToUpdate = isEditor ? currentLocationsData : mapEditorLocations;

                                const action = await showCustomDialog({ title: `Chỉnh Sửa: ${loc.name}`, message: `Vui lòng chọn thao tác cần thực hiện.`, buttons: [{ text: 'Sửa Tên', value: () => 'rename' }, { text: 'Xóa', value: () => 'delete', style: 'danger' }, { text: 'Hủy Bỏ', value: () => null }] });
                                if (action === 'rename') {
                                    const newName = await showCustomPrompt('Nhập tên mới:', loc.name);
                                    if (newName && newName.trim()) {
                                        const itemToEdit = (locationsToUpdate.landmarks || []).find(l => l.id === loc.id);
                                        if (itemToEdit) {
                                            itemToEdit.name = newName.trim();
                                            recordMapHistory();
                                            renderMapLocations(container, locationsToUpdate, true);
                                        }
                                    }
                                } else if (action === 'delete') {
                                    if (await showCustomConfirm(`Bạn có chắc muốn xóa "${loc.name}" không?`)) {
                                        if (!locationsToUpdate.landmarks) locationsToUpdate.landmarks = [];
                                        const itemIndex = locationsToUpdate.landmarks.findIndex(l => l.id === loc.id);
                                        if (itemIndex > -1) {
                                            locationsToUpdate.landmarks.splice(itemIndex, 1);
                                            recordMapHistory();
                                            renderMapLocations(container, locationsToUpdate, true);
                                        }
                                    }
                                }
                            }
                        } else {
                            showLocationDetail(loc);
                        }
                    };

                    if (isEditor && currentMapEditMode === 'edit-landmark' && loc.type === 'point') {
                        markerEl.style.cursor = 'move';
                         const startDrag = (startEvent) => {
                            startEvent.preventDefault();
                            startEvent.stopPropagation();
                            let hasDragged = false;
                            const onDragMove = (moveEvent) => {
                                hasDragged = true;
                                markerEl.classList.add('dragging');
                                const mapRect = pannable.getBoundingClientRect();
                                const clientX = moveEvent.touches ? moveEvent.touches[0].clientX : moveEvent.clientX;
                                const clientY = moveEvent.touches ? moveEvent.touches[0].clientY : moveEvent.clientY;
                                const leftPercent = ((clientX - mapRect.left) / mapRect.width) * 100;
                                const topPercent = ((clientY - mapRect.top) / mapRect.height) * 100;
                                markerEl.style.left = `${leftPercent}%`;
                                markerEl.style.top = `${topPercent}%`;
                            };
                            const onDragEnd = () => {
                                window.removeEventListener('mousemove', onDragMove);
                                window.removeEventListener('mouseup', onDragEnd);
                                window.removeEventListener('touchmove', onDragMove);
                                window.removeEventListener('touchend', onDragEnd);
                                markerEl.classList.remove('dragging');
                                if (hasDragged) {
                                    const locationToUpdate = (mapEditorLocations.landmarks || []).find(l => l.id === loc.id);
                                    if (locationToUpdate) {
                                        locationToUpdate.marker.left = markerEl.style.left;
                                        locationToUpdate.marker.top = markerEl.style.top;
                                        recordMapHistory();
                                    }
                                }
                            };
                            window.addEventListener('mousemove', onDragMove);
                            window.addEventListener('mouseup', onDragEnd, { once: true });
                            window.addEventListener('touchmove', onDragMove, { passive: false });
                            window.addEventListener('touchend', onDragEnd, { once: true });
                        };
                        markerEl.addEventListener('mousedown', startDrag);
                        markerEl.addEventListener('touchstart', startDrag, { passive: false });
                    }

                    el.addEventListener('click', (e) => {
                        e.stopPropagation();
                        if (clickCallback) { clickCallback(loc); return; }
                        if (clickTimeout) {
                            clearTimeout(clickTimeout);
                            clickTimeout = null;
                            handleDoubleClick();
                        } else {
                            clickTimeout = setTimeout(() => {
                                handleSingleClick();
                                clickTimeout = null;
                            }, 250);
                        }
                    });
                    el.addEventListener('dblclick', (e) => {
                        e.stopPropagation();
                        if (clickTimeout) { clearTimeout(clickTimeout); clickTimeout = null; }
                        if (clickCallback) return;
                        handleDoubleClick();
                    });
                };

                interactiveElements.forEach(setupInteractions);

                if (isEditor) {
                     if (currentMapEditMode === 'edit-landmark') {
                        if (loc.type === 'point') {
                            markerEl.style.cursor = 'move';
                            const startDrag = (startEvent) => {
                                startEvent.preventDefault();
                                startEvent.stopPropagation();
                                const pannable = container.closest('.map-pannable');
                                if (!pannable) return;
                                let hasDragged = false;
                                const dragThreshold = 5;
                                const startClientX = startEvent.touches ? startEvent.touches[0].clientX : startEvent.clientX;
                                const startClientY = startEvent.touches ? startEvent.touches[0].clientY : startEvent.clientY;
                                const onDragMove = (moveEvent) => {
                                    const clientX = moveEvent.touches ? moveEvent.touches[0].clientX : moveEvent.clientX;
                                    const clientY = moveEvent.touches ? moveEvent.touches[0].clientY : moveEvent.clientY;
                                    if (!hasDragged) {
                                        const dx = clientX - startClientX;
                                        const dy = clientY - startClientY;
                                        if (Math.sqrt(dx*dx + dy*dy) > dragThreshold) { hasDragged = true; markerEl.classList.add('dragging'); }
                                    }
                                    if (hasDragged) {
                                        const mapRect = pannable.getBoundingClientRect();
                                        const leftPercent = ((clientX - mapRect.left) / mapRect.width) * 100;
                                        const topPercent = ((clientY - mapRect.top) / mapRect.height) * 100;
                                        markerEl.style.left = `${leftPercent}%`;
                                        markerEl.style.top = `${topPercent}%`;
                                    }
                                };
                                const onDragEnd = () => {
                                    window.removeEventListener('mousemove', onDragMove);
                                    window.removeEventListener('mouseup', onDragEnd);
                                    window.removeEventListener('touchmove', onDragMove);
                                    window.removeEventListener('touchend', onDragEnd);
                                    markerEl.classList.remove('dragging');
                                    if (hasDragged) {
                                        const locationsDataSource = isEditor ? currentLocationsData : mapEditorLocations;
                                        if (!locationsDataSource.landmarks) locationsDataSource.landmarks = [];
                                        const locationToUpdate = locationsDataSource.landmarks.find(l => l.id === loc.id);
                                        if (locationToUpdate) {
                                            locationToUpdate.marker.left = markerEl.style.left;
                                            locationToUpdate.marker.top = markerEl.style.top;
                                            recordMapHistory();
                                        }
                                    }
                                };
                                window.addEventListener('mousemove', onDragMove);
                                window.addEventListener('mouseup', onDragEnd, { once: true });
                                window.addEventListener('touchmove', onDragMove, { passive: false });
                                window.addEventListener('touchend', onDragEnd, { once: true });
                            };
                            markerEl.addEventListener('mousedown', startDrag);
                            markerEl.addEventListener('touchstart', startDrag, { passive: false });
                            markerEl.addEventListener('contextmenu', handleMarkerContextMenu);
                        } else {
                            if (polygonEl) polygonEl.style.pointerEvents = 'none';
                            markerEl.style.pointerEvents = 'none';
                        }
                    }
                }
            });

            const sidebar = document.getElementById('map-editor-sidebar');
if (sidebar) {
    const editInfoBtn = sidebar.querySelector('button[title="Chỉnh Sửa Thông Tin"]');
    const editStyleBtn = sidebar.querySelector('button[title="Sửa Kiểu Dáng"]');
    const deleteSelectedBtn = sidebar.querySelector('button[title="Xóa Mục Đã Chọn"]');

    const populatePane = (paneId, items, type) => {
        const pane = document.getElementById(paneId);
        if (!pane) return;
        pane.innerHTML = '';
        if (!items || items.length === 0) {
            pane.innerHTML = `<p style="opacity: 0.7; font-size: 0.9em; text-align: center; padding: 10px;">Chưa có ${type}</p>`;
            return;
        }
        items.forEach((item, index) => {
            if (!item.id) {
                item.id = `${type}_${crypto.randomUUID()}`;
            }

            const div = document.createElement('div');
            div.className = 'creator-item';
            div.style.cursor = 'pointer';
            div.dataset.id = item.id;

            let subtext = '';
            if (type === 'Địa Danh') {
                subtext = item.mainRegionName ? `Thuộc: ${item.mainRegionName}` : 'Chưa Thuộc Về';
                if (item.subRegionName) subtext += ` / ${item.subRegionName}`;
            } else if (type === 'Khu Vực Phụ') {
                subtext = `Thuộc: ${item.parentName}`;
            }
            div.innerHTML = `<div class="item-name">${item.name}<small style="display:block; opacity:0.6;">${subtext}</small></div>`;
            div.addEventListener('click', (e) => {
                e.stopPropagation();

                if (div.classList.contains('selected')) {
                    clearSelection();
                } else {
                    selectElement(item);
                }
            });

            pane.appendChild(div);
