        function setupMapInteraction(viewport, pannable) {
            if (viewport.dataset.mapInteractionInitialized === 'true') {
                return;
            }
            viewport.dataset.mapInteractionInitialized = 'true';

            let scale = 1, panX = 0, panY = 0;
            const dragThreshold = 5;
            let lodUpdateTimeout = null;
            let scheduledFrame = false;
            const performHeavyUpdates = () => {
                updateAllMapScales(viewport);
                updateMapLOD(pannable, scale);
                if (typeof drawOnEditLayer === 'function' && isDrawing) {
                    drawOnEditLayer();
                }
            };

            const updateTransform = () => {
                pannable.style.transform = `translate(${panX}px, ${panY}px) scale(${scale})`;
                pannable.dataset.panX = panX;
                pannable.dataset.panY = panY;
                pannable.dataset.scale = scale;
                clearTimeout(lodUpdateTimeout);
                lodUpdateTimeout = setTimeout(performHeavyUpdates, 150);
            };

            const requestUpdate = () => {
                if (!scheduledFrame) {
                    scheduledFrame = true;
                    requestAnimationFrame(() => {
                        updateTransform();
                        scheduledFrame = false;
                    });
                }
            };

            const onWheel = (e) => {
                e.preventDefault();
                const rect = viewport.getBoundingClientRect();
                const mouseX = e.clientX - rect.left;
                const mouseY = e.clientY - rect.top;
                const scaleAmount = -e.deltaY * 0.001;
                const newScale = Math.max(0.2, Math.min(15, scale + scaleAmount));
                const worldX = (mouseX - panX) / scale;
                const worldY = (mouseY - panY) / scale;
                panX = mouseX - worldX * newScale;
                panY = mouseY - worldY * newScale;
                scale = newScale;
                requestUpdate();
            };

            viewport.addEventListener('wheel', onWheel, { passive: false });

            let initialPinchDistance = null;
            let lastScale = 1;

            const handleTouch = (e) => {
                if (e.target.closest('button, .map-location-marker, .map-polygon, .map-edit-vertex-html, a')) {
                    return;
                }

                if (e.touches.length === 2) {
                    e.preventDefault();
                    const touch1 = e.touches[0];
                    const touch2 = e.touches[1];
                    const distance = Math.hypot(touch1.clientX - touch2.clientX, touch1.clientY - touch2.clientY);

                    const rect = viewport.getBoundingClientRect();
                    const centerX = (touch1.clientX + touch2.clientX) / 2 - rect.left;
                    const centerY = (touch1.clientY + touch2.clientY) / 2 - rect.top;

                    if (initialPinchDistance === null) {
                        initialPinchDistance = distance;
                        lastScale = scale;
                    }

                    const scaleMultiplier = distance / initialPinchDistance;
                    const newScale = Math.max(0.2, Math.min(15, lastScale * scaleMultiplier));

                    const worldX = (centerX - panX) / scale;
                    const worldY = (centerY - panY) / scale;
                    panX = centerX - worldX * newScale;
                    panY = centerY - worldY * newScale;

                    scale = newScale;
                    requestUpdate();

                } else if (e.touches.length === 1) {
                    let isDragging = false;
                    const startX = e.touches[0].clientX;
                    const startY = e.touches[0].clientY;
                    const initialPanX = panX;
                    const initialPanY = panY;

                    const onTouchMove = (moveEvent) => {
                        if (moveEvent.touches.length !== 1) return;
                        const clientX = moveEvent.touches[0].clientX;
                        const clientY = moveEvent.touches[0].clientY;
                        const dx = clientX - startX;
                        const dy = clientY - startY;

                        if (!isDragging && Math.sqrt(dx*dx + dy*dy) > dragThreshold) {
                            isDragging = true;
                        }

                        if (isDragging) {
                            moveEvent.preventDefault();
                            panX = initialPanX + dx;
                            panY = initialPanY + dy;
                            requestUpdate();
                        }
                    };

                    const onTouchEnd = () => {
                        viewport.removeEventListener('touchmove', onTouchMove);
                        viewport.removeEventListener('touchend', onTouchEnd);
                    };

                    viewport.addEventListener('touchmove', onTouchMove, { passive: false });
                    viewport.addEventListener('touchend', onTouchEnd, { once: true });
                }
            };

            viewport.addEventListener('touchstart', (e) => {
                initialPinchDistance = null;
                if (e.touches.length > 0) {
                    handleTouch(e);
                }
            }, { passive: false });

            viewport.addEventListener('touchmove', handleTouch, { passive: false });

            const handleMouseDown = (e) => {
                if (e.target.closest('button, .map-location-marker, .map-polygon, .map-edit-vertex-html, a')) return;
                if (e.button !== 0) return;

                let isDragging = false;
                const startX = e.clientX, startY = e.clientY;
                const initialPanX = panX, initialPanY = panY;

                const onMouseMove = (moveEvent) => {
                    const dx = moveEvent.clientX - startX, dy = moveEvent.clientY - startY;
                    if (!isDragging && Math.sqrt(dx*dx + dy*dy) > dragThreshold) {
                        isDragging = true;
                        viewport.style.cursor = 'grabbing';
                    }
                    if (isDragging) {
                        panX = initialPanX + dx;
                        panY = initialPanY + dy;
                        requestUpdate();
                    }
                };
                const onMouseUp = () => {
                    window.removeEventListener('mousemove', onMouseMove);
                    window.removeEventListener('mouseup', onMouseUp);
                    viewport.style.cursor = 'grab';
                };
                window.addEventListener('mousemove', onMouseMove);
                window.addEventListener('mouseup', onMouseUp, { once: true });
            };

            viewport.addEventListener('mousedown', handleMouseDown);
        }

