                }
                viewport.queryClickListener = (startEvent) => {
                    if (startEvent.target.closest('.map-location-marker, .map-polygon')) return;

                    const startX = startEvent.clientX;
                    const startY = startEvent.clientY;

                    const onMouseUp = (endEvent) => {
                        const dx = endEvent.clientX - startX;
                        const dy = endEvent.clientY - startY;
                        if (Math.sqrt(dx * dx + dy * dy) < 10) {
                            handleMapClick(endEvent);
                        }
                        window.removeEventListener('mouseup', onMouseUp);
                    };
                    window.addEventListener('mouseup', onMouseUp, { once: true });
