*Thiên Phú: ${uniqueTraits.length > 0 ? '\n' + uniqueTraits.map(t => `  - ${t.name}: ${t.desc || 'Không có mô tả đặc biệt.'}${t.effects && t.effects !== 'Không' ? ` Hiệu ứng: ${t.effects}` : ''}`).join('\n') : 'Không'}
