        async function handleContinueOrResend() {
            const archive = await db.archives.get(currentArchiveName);
            if (!archive) return;
            const lastLog = archive.data.logs[archive.data.logs.length - 1];
            if (!lastLog) return;

            if (lastLog.type === 'ai') {
                await sendMessage(null, true);
            } else if (lastLog.type === 'user') {
                const messageToSend = lastLog.content.startsWith('> ') ? lastLog.content.substring(2) : lastLog.content;
                await sendMessage(null, true, messageToSend);
            }
        }

        async function getCustomTraits() {
            return await dbGet(CUSTOM_TRAITS_KEY) || [];
        }

        async function saveCustomTraits(traits) {
            await dbSet(CUSTOM_TRAITS_KEY, traits);
        }

        async function openCustomTraitManager() {
            await renderCustomTraitManager();
            customTraitManagerOverlay.classList.add('visible');
        }

        async function renderCustomTraitManager() {
            const listEl = document.getElementById('custom-traits-list');
            const traits = await getCustomTraits();
            listEl.innerHTML = '';

            if (traits.length === 0) {
                listEl.innerHTML = '<p style="text-align:center; opacity:0.7;">Chưa tạo bất kỳ đặc điểm tùy chỉnh nào.</p>';
                return;
            }

            traits.forEach((trait, index) => {
                const item = document.createElement('div');
                item.className = 'custom-trait-item';
                item.innerHTML = `
                    <input type="checkbox" data-index="${index}">
                    <span class="trait-rarity" style="color: ${CREATION_CONFIG.TRAIT_RARITIES[trait.rarity].color};">${trait.rarity}</span>
                    <span class="trait-name">${trait.name}</span>
                    <span class="active-indicator">${trait.inPool ? '<i class="fas fa-check-circle"></i>' : ''}</span>
                `;
                item.addEventListener('dblclick', () => openCustomTraitEditor(index));
                listEl.appendChild(item);
            });
        }

        async function openCustomTraitEditor(index = -1, context = { type: 'general' }) {
            currentEditingTraitContext = context;
            currentEditingTraitIndex = index;
            const isEditing = index > -1;

            let trait;
            if (context.type === 'race') {
                trait = (isEditing && tempRaceTraits[index]) ? tempRaceTraits[index] : {};
            } else {
                const traits = await getCustomTraits();
                trait = (isEditing && traits[index]) ? traits[index] : {};
            }

            const itemFieldset = document.getElementById('custom-trait-item-fieldset');
            itemFieldset.style.display = context.type === 'race' ? 'none' : 'block';

            document.getElementById('custom-trait-editor-title').textContent = isEditing ? 'Chỉnh Sửa Thiên Phú' : 'Tạo Thiên Phú Mới';

            const raritySelect = document.getElementById('custom-trait-rarity');
            raritySelect.innerHTML = Object.keys(CREATION_CONFIG.TRAIT_RARITIES).map(r => `<option value="${r}">${r}</option>`).join('');
            raritySelect.value = trait.rarity || 'Phổ Thông';

            document.getElementById('custom-trait-name').value = trait.name || '';
            document.getElementById('custom-trait-desc').value = trait.desc || '';
            document.getElementById('custom-trait-effects').value = trait.effects || 'Không';

            const bonusGrid = document.getElementById('custom-trait-bonus-grid');
            const summaryEl = document.getElementById('custom-trait-bonus-summary');
            const traitBonus = { ...(trait.bonus || {}) };

            const updateSummaryAndControls = () => {
                const total = Object.values(traitBonus).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                summaryEl.textContent = `${total} / 5`;
                summaryEl.parentElement.style.color = total > 5 ? '#e57373' : 'var(--accent-color)';

                bonusGrid.querySelectorAll('.attribute-item').forEach(item => {
                    const attr = item.dataset.attr;
                    const currentValue = traitBonus[attr] || 0;
                    const minusBtn = item.querySelector('.minus');
                    const plusBtn = item.querySelector('.plus');

                    minusBtn.disabled = currentValue <= -5;
                    plusBtn.disabled = currentValue >= 5 || total >= 5;
                });
                return total;
            };

            bonusGrid.innerHTML = Object.keys(CREATION_CONFIG.ATTRIBUTES).map(attr => `
                <div class="attribute-item" data-attr="${attr}">
                    <div class="name-desc"><strong>${attr}</strong></div>
                    <div class="attribute-controls">
                        <button class="attr-btn minus" data-attr="${attr}">-</button>
                        <input type="number" class="value custom-bonus-input" data-attr-val="${attr}" value="${traitBonus[attr] || 0}" min="-5" max="5">
                        <button class="attr-btn plus" data-attr="${attr}">+</button>
                    </div>
                </div>
            `).join('');

            bonusGrid.querySelectorAll('.custom-bonus-input').forEach(input => {
                input.addEventListener('change', () => {
                    const attr = input.dataset.attrVal;
                    const oldValue = traitBonus[attr] || 0;
                    let newValue = parseInt(input.value) || 0;
                    newValue = Math.max(-5, Math.min(5, newValue));

                    const currentTotal = Object.values(traitBonus).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                    const newTotal = currentTotal - oldValue + newValue;

                    if (newTotal > 5) {
                        input.value = oldValue;
                        showCustomAlert('Tổng điều chỉnh thuộc tính không được vượt quá 5！');
                    } else {
                        traitBonus[attr] = newValue;
                        input.value = newValue;
                    }
                    updateSummaryAndControls();
                });
            });

            bonusGrid.querySelectorAll('.attr-btn').forEach(btn => {
                btn.addEventListener('click', (e) => {
                    const attr = e.target.dataset.attr;
                    const isPlus = e.target.classList.contains('plus');
                    const itemRow = e.target.closest('.attribute-item');
                    const inputEl = itemRow.querySelector('.custom-bonus-input');

                    let currentValue = parseInt(inputEl.value) || 0;
                    const currentTotal = Object.values(traitBonus).reduce((sum, val) => sum + (parseInt(val) || 0), 0) - (traitBonus[attr] || 0);

                    if (isPlus) {
                        if (currentValue < 5 && (currentTotal + currentValue + 1) <= 5) {
                            currentValue++;
                        }
                    } else {
                        if (currentValue > -5) {
                            currentValue--;
                        }
                    }

                    traitBonus[attr] = currentValue;
                    inputEl.value = currentValue;
                    updateSummaryAndControls();
                });
            });

            updateSummaryAndControls();

            const itemTypeSelect = document.getElementById('custom-trait-item-type');
            itemTypeSelect.innerHTML = Object.keys(itemIconMap).map(type => `<option value="${type}">${type}</option>`).join('');

            const itemValueInput = document.getElementById('custom-trait-item-value');

            if (trait.item && trait.item !== 'Không') {
                const itemMatch = trait.item.match(/【(.*?)】/);
                if (itemMatch) {
                    const parts = itemMatch[1].split('|');
                    document.getElementById('custom-trait-item-name').value = parts[0] || '';
                    document.getElementById('custom-trait-item-desc').value = parts[1] || '';
                    itemTypeSelect.value = parts[2] || 'Mặc Định';
                    document.getElementById('custom-trait-item-effect').value = parts[3] || '';
                    document.getElementById('custom-trait-item-quantity').value = parts[4] || '1';
                    itemValueInput.value = parts[5] || '0';
                }
            } else {
                document.getElementById('custom-trait-item-name').value = '';
                document.getElementById('custom-trait-item-desc').value = '';
                itemTypeSelect.value = 'Mặc Định';
                document.getElementById('custom-trait-item-effect').value = '';
                document.getElementById('custom-trait-item-quantity').value = '1';
                itemValueInput.value = '0';
            }

            itemValueInput.onblur = () => {
                let value = parseInt(itemValueInput.value) || 0;
