        async function saveCustomTrait() {
            const name = document.getElementById('custom-trait-name').value.trim();
            if (!name) {
                await showCustomAlert('Tên thiên phú không được để trống！');
                return;
            }
            const bonus = {};
            document.querySelectorAll('#custom-trait-bonus-grid .custom-bonus-input').forEach(input => {
                const value = parseInt(input.value);
                if (!isNaN(value) && value !== 0) {
                    bonus[input.dataset.attrVal] = value;
                }
            });
            let itemString = 'Không';
            if (currentEditingTraitContext.type !== 'race') {
                const itemName = document.getElementById('custom-trait-item-name').value.trim();
                if (itemName) {
                    const itemDesc = document.getElementById('custom-trait-item-desc').value.trim();
                    const itemType = document.getElementById('custom-trait-item-type').value;
                    const itemEffect = document.getElementById('custom-trait-item-effect').value.trim();
                    const itemQuantity = document.getElementById('custom-trait-item-quantity').value || '1';

                    const itemValueInput = document.getElementById('custom-trait-item-value');
                    let itemValue = parseInt(itemValueInput.value) || 0;
                    itemValue = Math.max(0, Math.min(1000, itemValue));
                    itemValueInput.value = itemValue;
                    itemString = `【${itemName}|${itemDesc}|${itemType}|${itemEffect}|${itemQuantity}|${itemValue}】`;
                }
            }
            const newTraitData = {
                rarity: document.getElementById('custom-trait-rarity').value,
                name: name,
                desc: document.getElementById('custom-trait-desc').value.trim(),
                effects: document.getElementById('custom-trait-effects').value.trim() || 'Không',
                bonus: bonus,
                item: itemString
            };
            if (currentEditingTraitContext.type === 'race') {
                if (currentEditingTraitIndex > -1) {
                    tempRaceTraits[currentEditingTraitIndex] = { ...tempRaceTraits[currentEditingTraitIndex], ...newTraitData };
                } else {
                    newTraitData.id = crypto.randomUUID();
                    tempRaceTraits.push(newTraitData);
                }
                customTraitEditorOverlay.classList.remove('visible');
                renderRaceTraitsDisplay();
            } else {
                const traits = await getCustomTraits();
                const finalTrait = {
                    ...newTraitData,
                    id: currentEditingTraitIndex > -1 ? traits[currentEditingTraitIndex].id : crypto.randomUUID(),
                    inPool: currentEditingTraitIndex > -1 ? traits[currentEditingTraitIndex].inPool : false,
                };
                if (currentEditingTraitIndex > -1) {
                    traits[currentEditingTraitIndex] = finalTrait;
                } else {
                    traits.push(finalTrait);
                }
                await saveCustomTraits(traits);
                customTraitEditorOverlay.classList.remove('visible');
                await renderCustomTraitManager();
            }
        }

