function renderAllTaskLists() {
    const allTasks = Object.values(currentState['6'] || {});

    allTasks.forEach(task => {
        if (!task['9']) task['9'] = 'unaccepted';
    });

    renderTaskList(allTasks.filter(t => t['9'] === 'unaccepted'), 'unaccepted-task-list');
    renderTaskList(allTasks.filter(t => t['9'] === 'in-progress'), 'in-progress-task-list');
    renderTaskList(allTasks.filter(t => t['9'] === 'completed'), 'completed-task-list');
    renderTaskList(allTasks.filter(t => t['9'] === 'closed'), 'closed-task-list');
}

        function renderTaskList(tasks, containerId) {
            const container = document.getElementById(containerId);
            container.innerHTML = '';

            if (tasks.length === 0) {
                const messages = {
                    'unaccepted-task-list': 'Bảng ủy thác rất sạch sẽ, không có ủy thác nào có thể nhận.',
                    'in-progress-task-list': 'Bạn hiện không có ủy thác nào đang tiến hành.',
                    'completed-task-list': 'Bạn không có ủy thác nào chờ nộp.',
                    'closed-task-list': 'Nơi đây trống rỗng, ghi lại quá khứ đã hoàn thành hoặc thất bại của bạn.'
                };
                container.innerHTML = `<p style="text-align:center; opacity:0.7;">${messages[containerId]}</p>`;
                return;
            }

            tasks.forEach(task => {
                const item = document.createElement('div');
                item.className = 'task-list-item';
                const difficulty = task['5'] || 'Không Yêu Cầu';
                const difficultyColor = ADVENTURE_RANK_COLORS[difficulty] || ADVENTURE_RANK_COLORS.default;

                let deleteButtonHtml = '';
                const status = task['9'] || 'unaccepted';
                if (status === 'unaccepted' || status === 'completed') {
                    deleteButtonHtml = `<button class="item-delete-btn" data-id="${task['0']}"><i class="fas fa-trash-alt"></i></button>`;
                }

                item.innerHTML = `
                    <div class="task-info">
                        <span class="name">${task['1']}</span>
                        <span class="difficulty" style="background-color:${difficultyColor}; color: #1a1a1a;">${difficulty}</span>
                    </div>
                    ${deleteButtonHtml}
                `;

                item.querySelector('.task-info').addEventListener('click', () => showTaskDetailView(task['0']));

                const deleteBtn = item.querySelector('.item-delete-btn');
                if (deleteBtn) {
                    deleteBtn.addEventListener('click', async (e) => {
                        e.stopPropagation();
                        const taskId = e.currentTarget.dataset.id;
                        const taskName = task['1'];
                        if (await showCustomConfirm(`Bạn có chắc muốn xóa vĩnh viễn ủy thác "${taskName}" không? Thao tác này không thể hoàn tác.`)) {
                            delete currentState['6'][taskId];
                            await saveCurrentState();
                            renderAllTaskLists();
                        }
                    });
                }
                container.appendChild(item);
            });
        }

        function showTaskDetailView(taskId) {
            document.getElementById('task-list-view').classList.add('hidden');
            const detailView = document.getElementById('task-detail-view');
            detailView.classList.remove('hidden');

            const detailPanel = document.getElementById('task-detail-panel');
            const task = currentState['6'][taskId];
            if (!task) return;

            const difficulty = task['5'] || 'Không Yêu Cầu';
            const difficultyColor = ADVENTURE_RANK_COLORS[difficulty] || ADVENTURE_RANK_COLORS.default;
            const status = task['9'] || 'unaccepted';
            const judgementType = task['10'] || 'system_judged';

            const rankOrder = ['Không Yêu Cầu', 'Hắc Thiết', 'Đồng', 'Bạc', 'Vàng', 'Bạch Kim', 'Mithril'];
            let playerRankIndex = rankOrder.indexOf(currentPlayerData.adventureRank);
            if (playerRankIndex === -1) {
                playerRankIndex = 0;
            }
            const requiredRankIndex = rankOrder.indexOf(difficulty);
            const canAccept = playerRankIndex >= requiredRankIndex;

            const requirementsHtml = `
                <p>Hạng Mạo Hiểm: <strong>${difficulty}</strong> ${canAccept || status !== 'unaccepted' ? '<i class="fas fa-check-circle" style="color: #66bb6a;"></i>' : '<i class="fas fa-times-circle" style="color: #e57373;"></i>'}</p>
                <p><strong>Điều Kiện Hoàn Thành:</strong> ${judgementType === 'ai_judged' ? (task['11'] || 'Do cốt truyện quyết định.') : 'Cần đạt được mục tiêu cụ thể.'}</p>
                <p><strong>Phương Thức Phán Định:</strong> <span style="font-style: italic;">${judgementType === 'ai_judged' ? 'Do AI phán định' : 'Do hệ thống tự động phán định'}</span></p>
            `;

            detailPanel.innerHTML = `
                <div class="task-detail-section">
                    <h5>${task['1']} <span class="task-difficulty" style="background-color:${difficultyColor}; color: #1a1a1a; float: right;">${difficulty}</span></h5>
                    <p>${task['2'] || 'Không'}</p>
                </div>
                <div class="detail-section">
                    <h4><i class="fas fa-tasks"></i> Yêu Cầu Nhiệm Vụ</h4>
                    ${requirementsHtml}
                </div>
                <div class="detail-section">
                    <h4><i class="fas fa-gift"></i> Phần Thưởng Nhiệm Vụ</h4>
                    <p class="task-reward">${task['3'] || 'Không'}</p>
                </div>
                <div class="detail-section">
                    <h4><i class="fas fa-exclamation-triangle"></i> Hình Phạt Thất Bại</h4>
                    <p class="task-punishment">${task['4'] || 'Không'}</p>
                </div>
                <div class="task-detail-actions" id="task-detail-buttons"></div>
            `;

            const buttonsContainer = detailPanel.querySelector('#task-detail-buttons');
            switch(status) {
                case 'unaccepted':
                    buttonsContainer.innerHTML = `<button class="major-action-button" id="accept-task-btn" ${!canAccept ? 'disabled' : ''}><i class="fas fa-check"></i> Nhận Ủy Thác</button>`;
                    const acceptBtn = buttonsContainer.querySelector('#accept-task-btn');
                    if (!canAccept) acceptBtn.title = `Hạng Mạo Hiểm của bạn không đủ (${currentPlayerData.adventureRank})`;
                    acceptBtn.onclick = async () => {
                        if (currentState['6'][taskId]) {
                            currentState['6'][taskId]['9'] = 'in-progress';
                            await saveCurrentState();
                            showDanmaku(`Đã nhận ủy thác: ${currentState['6'][taskId]['1']}`, 'player');
                            showTaskDetailView(taskId);
                        }
                    };
                    break;
                case 'in-progress':
                    buttonsContainer.innerHTML = `<button class="major-action-button" id="abandon-task-btn" style="border-color: #e57373; color: #e57373;"><i class="fas fa-times"></i> Hủy Bỏ Ủy Thác</button>`;
                    buttonsContainer.querySelector('#abandon-task-btn').onclick = async () => {
                        const currentTask = currentState['6'][taskId];
                        if (!currentTask) return;
                        if (await showCustomConfirm(`Bạn có chắc muốn hủy bỏ ủy thác "${currentTask['1']}" không? Bạn có thể phải chịu hình phạt thất bại.`)) {
                            const penaltyCommands = currentTask['4'];
                            if (penaltyCommands) {
                                const { delta } = parseTableEditCommands(penaltyCommands);
                                const result = await applyChanges(currentState, delta);
                                currentState = result.state;
                                showDanmaku(`Hình phạt nhiệm vụ đã được thực thi！`, 'error');
                            }

                            if (currentState['6'][taskId]) {
                                currentState['6'][taskId]['9'] = 'closed';
                            }

                            await saveCurrentState();
                            syncStateFromTables();
                            showDanmaku(`Đã hủy bỏ ủy thác: ${currentTask['1']}`, 'error');
                            showTaskListView();
                        }
                    };
                    break;
                case 'completed':
                    buttonsContainer.innerHTML = `<button class="major-action-button" id="submit-task-btn" style="border-color: #ffd700; color: #ffd700;"><i class="fas fa-hand-holding-usd"></i> Nộp Ủy Thác</button>`;
                    buttonsContainer.querySelector('#submit-task-btn').onclick = () => {
                        const currentTask = currentState['6'][taskId];
                        if (currentTask) {
                            addAction('submit_task', { id: taskId, name: currentTask['1'] });
                            tasksOverlay.classList.remove('visible');
                        }
                    };
                    break;
                case 'closed':
                    buttonsContainer.innerHTML = `<p style="opacity: 0.7; text-align: center; width: 100%;">Ủy thác này đã kết thúc.</p>`;
                    break;
            }
        }

function showTaskListView() {
    document.getElementById('task-list-view').classList.remove('hidden');
    document.getElementById('task-detail-view').classList.add('hidden');
