}

function updateClearButtonVisibility() {
    const clearBtn = document.getElementById('clear-task-list-btn');
    const activeTab = document.querySelector('#task-tabs .tab-button.active');
    if (!activeTab) {
        clearBtn.style.display = 'none';
        return;
    }

    const tabName = activeTab.dataset.tab;
    if (tabName === 'in-progress') {
        clearBtn.style.display = 'none';
    } else {
        clearBtn.style.display = 'block';
        const listId = `${tabName}-task-list`;
        const list = document.getElementById(listId);
        clearBtn.disabled = !list || list.children.length === 0 || (list.children.length === 1 && list.children[0].tagName === 'P');
    }
}

async function clearCurrentTaskList() {
    const activeTab = document.querySelector('#task-tabs .tab-button.active');
    if (!activeTab) return;

    const tabName = activeTab.dataset.tab;
    const statusToClear = tabName;
    const confirmMessage = tabName === 'unaccepted' ? 'Bạn có chắc muốn xóa tất cả các ủy thác chưa nhận không?' : 'Bạn có chắc muốn xóa tất cả các ghi chép ủy thác đã hoàn thành không?';

    if (await showCustomConfirm(confirmMessage)) {
        const allTasks = Object.values(currentState['6'] || {});
        const tasksToKeep = allTasks.filter(t => (t['9'] || 'unaccepted') !== statusToClear);

        const newTasksObject = {};
        tasksToKeep.forEach(task => {
            newTasksObject[task['0']] = task;
        });

        currentState['6'] = newTasksObject;
        await saveCurrentState();
        renderAllTaskLists();
        updateClearButtonVisibility();
    }
}

        async function openTaskItemPicker(task) {
            tasksOverlay.classList.remove('visible');

            pickerTitle.textContent = `Chọn vật phẩm cần nộp cho ủy thác [${task['1']}]`;
            pickerGrid.innerHTML = '';

            const requirements = (task['10'] || '').split(';').map(req => {
                const [id, count] = req.split(':');
                return { id, count: parseInt(count) };
            }).filter(r => r.id && r.count);

            const requiredItemIds = new Set(requirements.map(r => r.id));
            const submittableItems = inventoryItems.filter(item => requiredItemIds.has(item.id));

            if (submittableItems.length === 0) {
                pickerGrid.innerHTML = `<p style="grid-column: 1 / -1; text-align: center; opacity: 0.7;">Trong túi của bạn không có vật phẩm cần thiết cho nhiệm vụ.</p>`;
            } else {
                submittableItems.forEach(item => {
                    const slot = document.createElement('div');
                    slot.className = 'inventory-slot';
                    slot.title = `${item.name}\nLoại: ${item.type}`;
                    const iconClass = itemIconMap[item.type] || itemIconMap['Mặc Định'];
                    slot.innerHTML = `<i class="fas ${iconClass} inventory-slot-icon"></i><span class="inventory-slot-name">${item.name}</span><span class="inventory-slot-quantity">${item.quantity}</span>`;

                    slot.addEventListener('click', async () => {
                        const requiredAmount = requirements.find(r => r.id === item.id).count;
                        const quantityToSubmit = await showCustomPrompt(`Cần nộp bao nhiêu [${item.name}]? (Yêu cầu ${requiredAmount})`, item.quantity);
                        const numToSubmit = parseInt(quantityToSubmit);

                        if (isNaN(numToSubmit) || numToSubmit <= 0) return;
                        if (numToSubmit > item.quantity) {
                            await showCustomAlert('Số lượng không đủ！');
                            return;
                        }


                        const itemInState = currentState['1'][item.id];
                        if (itemInState) {
                            const currentQuantity = parseInt(itemInState['5']);
                            if (numToSubmit >= currentQuantity) {
                                delete currentState['1'][item.id];
                            } else {
                                itemInState['5'] = (currentQuantity - numToSubmit).toString();
                            }
                        }

                        await saveCurrentState();
                        syncStateFromTables();

                        await showCustomAlert(`Bạn đã nộp ${numToSubmit} [${item.name}].`);
                        closeEquipmentPicker();

                        let allMet = true;
                        for (const req of requirements) {
                            const itemInBag = inventoryItems.find(i => i.id === req.id);
                            if (!itemInBag || itemInBag.quantity < req.count) {
                                allMet = false;
                                break;
                            }
                        }

                        if (allMet) {
                            currentState['6'][task['0']]['9'] = 'completed';
                            showDanmaku(`Hoàn thành ủy thác: ${task['1']}`, 'achievement');
                            if (task['12']) {
                                const { delta } = parseTableEditCommands(task['12']);
                                currentState = applyChanges(currentState, delta);
                            }
                            await saveCurrentState();
                            syncStateFromTables();
                        }

                        tasksOverlay.classList.add('visible');
                        showTaskDetailView(task['0']);
                    });
                    pickerGrid.appendChild(slot);
                });
            }
            pickerOverlay.classList.add('visible');
        }

