        function showSkillDetail(skill) {
            const nameEl = document.getElementById('skill-detail-name');
			makeElementCopyable(nameEl, skill['1']); <!-- New -->
            const contentEl = document.getElementById('skill-detail-content');

            showOverlaySafely(skillDetailOverlay, () => {
                const [level, xp] = (skill['4'] || '1|0').split('|').map(Number);
                const tier = parseInt(skill['3']);
                const maxLevel = getSkillMaxLevel(tier);
                const xpToNext = calculateSkillXPForLevel(level, tier);
                const createRow = (label, value) => { if (value === null || value === undefined || value === '') return ''; return `<div class="skill-detail-row"><span class="skill-detail-label">${label}:</span><span class="skill-detail-value">${value}</span></div>`; };

                let xpBarHtml = '';
                if (skill['2']?.toLowerCase() !== 'bị động' && level < maxLevel) {
                    const progressPercentage = xpToNext > 0 ? (xp / xpToNext) * 100 : 100;
                    xpBarHtml = `<div class="skill-detail-row"><span class="skill-detail-label">Độ Thông Thạo Hiện Tại:</span><div class="xp-bar"><div class="xp-bar-fill" style="width: ${progressPercentage}%"></div><div class="xp-bar-text">${xp} / ${xpToNext}</div></div></div>`;
                }

                let successRateHtml = '';
                if (skill['10']) {
                    const baseChance = parseInt(skill['10']);
                    const senseBonus = Math.floor(((currentPlayerData.detailedAttributes['Cảm Ứng'] || 10) - 10) / 2);
                    const luckBonus = Math.floor(((currentPlayerData.detailedAttributes['May Mắn'] || 10) - 10) / 4);
                    const finalChance = Math.max(0, Math.min(100, baseChance + senseBonus + luckBonus));
                    successRateHtml = createRow('Tỷ Lệ Thành Công Cơ Bản', `${finalChance}%`);
                }
                let effectsHtml = '';
                if (skill['9']) {
                    try {
                        const effects = JSON.parse(skill['9']);
                        if (Array.isArray(effects)) {
                            effectsHtml = effects.map(effect => {
                                return `
                                    <div class="detail-section">
                                        <h4>Hiệu Ứng: ${effect.type || 'Không Rõ'}</h4>
                                        <p style="text-align: left; padding-left: 10px;">${effect.desc || 'Không có mô tả chi tiết'}</p>
                                    </div>
                                `;
                            }).join('');
                        } else {
                            effectsHtml = `<div class="detail-section"><h4>Hiệu Ứng</h4><p>${skill['9']}</p></div>`;
                        }
                    } catch (e) {
                        effectsHtml = `<div class="detail-section"><h4>Hiệu Ứng</h4><p>${skill['9']}</p></div>`;
                    }
                }

                nameEl.textContent = skill['1'];
                contentEl.innerHTML = `
                    ${createRow('Tên', skill['1'])}
                    ${createRow('Loại', skill['2'])}
                    ${createRow('Bậc', `Bậc ${tier}`)}
                    ${createRow('Cấp Hiện Tại', `${level}`)}
                    ${xpBarHtml}
                    ${createRow('Tag', skill['5'])}
                    ${createRow('Mục Tiêu Tác Dụng', skill['6'])}
                    ${createRow('Tiêu Hao Cơ Bản', calculateSkillCost(skill, level))}
                    ${successRateHtml}
                    ${createRow('Mô Tả', skill['8'])}
                    ${effectsHtml}
                `;
            });
        }

        async function handleAvatarUpload(event) {
            const file = event.target.files[0];
            if (!file) {
                event.target.value = '';
                return;
            }

            const reader = new FileReader();
            reader.onload = async (e) => {
                try {
                    const base64String = e.target.result;

                    if (creationScreen.classList.contains('hidden')) {
                        await dbSet(`${CUSTOM_AVATAR_KEY}_${currentArchiveName}`, base64String);
                        await updateAvatar(currentPlayerData);
                    } else {
                        creationState.customAvatar = base64String;
                        await showCustomAlert("Chân Dung tùy chỉnh đã được cài đặt！");
                    }
                } catch (err) {
                    await showCustomAlert(`Xử lý avatar thất bại: ${err.message}`);
                } finally {
                    event.target.value = '';
                }
            };
            reader.readAsDataURL(file);
        }

