                    item.className = `bonded-char-selection-item ${isSelected ? 'selected' : ''}`;
                    const genderClass = char.gender === 'Nam' ? 'char-name-male' : (char.gender === 'Nữ' ? 'char-name-female' : '');
                    item.innerHTML = `<span class="char-name ${genderClass}">${char.name}</span><span>${char.identity}</span>`;
                    item.addEventListener('click', () => {
                        const selectedIndex = creationState.bondedCharacters.findIndex(c => c.id === char.id);
                        if (selectedIndex > -1) {
                            creationState.bondedCharacters.splice(selectedIndex, 1);
                        } else {
                            creationState.bondedCharacters.push(char);
                        }
                        openBondedCharacterSelection();
                    });
                    listEl.appendChild(item);
                });
            }

            const actionsContainer = document.getElementById('bonded-char-manager-actions');
            actionsContainer.innerHTML = `<button id="manage-bonded-chars-btn" class="major-action-button"><i class="fas fa-users-cog"></i> Quản Lý Danh Sách</button>`;
            actionsContainer.querySelector('#manage-bonded-chars-btn').addEventListener('click', renderBondedCharManager);

            bondedCharacterSelectionOverlay.classList.add('visible');
        }

        async function renderBondedCharManager() {
            const listEl = document.getElementById('bonded-character-selection-list');
            listEl.innerHTML = '';
            const allChars = await getBondedChars();

            if (allChars.length === 0) {
                listEl.innerHTML = '<p style="text-align:center; opacity:0.7;">Danh sách trống.</p>';
            } else {
                allChars.forEach((char) => {
                    const item = document.createElement('div');
                    item.className = 'custom-trait-item';
                    const gender = char.gender || '';
                    const genderClass = (gender === 'Nam' || gender === 'Đực') ? 'char-name-male' : ((gender === 'Nữ' || gender === 'Cái') ? 'char-name-female' : '');
                    item.innerHTML = `
                        <input type="checkbox" data-id="${char.id}">
                        <span class="char-name ${genderClass}" style="flex-grow:1;">${char.name}</span>
                        <button class="edit-bonded-char-btn" data-id="${char.id}" title="Chỉnh Sửa"><i class="fas fa-edit"></i></button>
                    `;
                    listEl.appendChild(item);
                });
            }

            const actionsContainer = document.getElementById('bonded-char-manager-actions');
            actionsContainer.innerHTML = `
                <button id="bc-create-btn" class="major-action-button"><i class="fas fa-plus"></i> Tạo Mới</button>
                <button id="bc-import-btn" class="major-action-button"><i class="fas fa-file-import"></i> Nhập</button>
                <button id="bc-export-btn" class="major-action-button"><i class="fas fa-file-export"></i> Xuất</button>
                <button id="bc-delete-btn" class="major-action-button"><i class="fas fa-trash"></i> Xóa</button>
                <button id="bc-back-to-select-btn" class="major-action-button"><i class="fas fa-arrow-left"></i> Quay Lại</button>
            `;

            listEl.querySelectorAll('.edit-bonded-char-btn').forEach(btn => btn.addEventListener('click', async (e) => {
                const charId = e.currentTarget.dataset.id;
                const chars = await getBondedChars();
                const index = chars.findIndex(c => c.id === charId);
                if (index > -1) {
                    openBondedCharEditor(index);
                }
            }));
            document.getElementById('bc-create-btn').addEventListener('click', () => openBondedCharEditor());
            document.getElementById('bc-import-btn').addEventListener('click', () => handleImportCustomData(CUSTOM_BONDED_CHARS_KEY, 'Nhân Vật Gắn Kết'));
            document.getElementById('bc-export-btn').addEventListener('click', () => handleExportCustomData(CUSTOM_BONDED_CHARS_KEY, 'custom_bonded_chars.json'));
            document.getElementById('bc-delete-btn').addEventListener('click', async () => {
                const selectedIds = Array.from(listEl.querySelectorAll('input:checked')).map(cb => cb.dataset.id);
                if (selectedIds.length === 0) return;
                if (await showCustomConfirm(`Bạn có chắc muốn xóa ${selectedIds.length} nhân vật đã chọn khỏi danh sách không?`)) {
                    let chars = await getBondedChars();
                    chars = chars.filter(char => !selectedIds.includes(char.id));
                    await dbSet(CUSTOM_BONDED_CHARS_KEY, chars);
                    await renderBondedCharManager();
                }
            });
            document.getElementById('bc-back-to-select-btn').addEventListener('click', openBondedCharacterSelection);
        }

        async function openInGameCharacterEditor(charId) {
            const editorOverlay = document.getElementById('bonded-character-editor-overlay');
            const char = characterDatabase[charId];
            if (!char) { showCustomAlert('Không tìm thấy nhân vật cần chỉnh sửa！'); return; }

            currentEditingInGameCharId = charId;
            const charRow = currentState['0'][charId];
            const templates = await dbGet(CUSTOM_BONDED_CHARS_KEY) || [];
            const [name, gender] = (charRow['1'] || '|').split('|');
            const template = templates.find(t => t.name === name);

            const actionParts = (charRow['16'] || '|').split('|');

            const fullCharData = {
                name: name,
                gender: gender,
                race: (charRow['2'] || '|').split('|')[0],
                career: (charRow['2'] || '|').split('|')[1],
                level: charRow['9'] || '1',
                age: charRow['5'] || 'Không Rõ',
                favorability: charRow['15'] || '0',
                core_appearance: charRow['26'] || '',
                wardrobe: charRow['27'] || '[]',
                status: charRow['4'] || 'Mọi Thứ Bình Thường',
                personality: charRow['3'] || '',
                motive: charRow['12'] || '...',
                identity: charRow['8'] || '',
                background: charRow['10'] || '',
                attributes: charRow['11'] || '{}',
                rawRelations: charRow['13'] || '',
                action: actionParts[0] || '',
                detailedLocation: actionParts[1] || '',
                stages: template ? template.stages : []
            };

            await renderCharacterEditorPanel({
                container: editorOverlay.querySelector('.modal'),
                title: `Chỉnh Sửa: ${fullCharData.name}`,
                charData: fullCharData,
                onSave: saveInGameCharacterEdit,
                availableNpcsForRelations: Object.values(characterDatabase).filter(c => c.id !== charId)
            });

            editorOverlay.classList.add('visible');
        }

