                                </fieldset>
                            </div>
                            <div class="editor-col">
                                 <fieldset><legend>Hoạt Động Nội Tâm</legend>
                                     <label>Tính Cách: <textarea id="bc-editor-personality" rows="1" oninput="autosizeTextarea(this)">${charData.personality || ''}</textarea></label>
