            container.querySelector('.modal-close-btn').addEventListener('click', () => container.parentElement.classList.remove('visible'));

            const genderSelect = container.querySelector('#bc-editor-gender');
            genderSelect.innerHTML = `<option value="Nam">Nam</option><option value="Nữ">Nữ</option><option value="Đực">Đực</option><option value="Cái">Cái</option><option value="Futanari">Futanari</option><option value="Vô Tính">Vô Tính</option><option value="Khác">Khác</option><option value="Không Rõ">Không Rõ</option>`;
            genderSelect.value = charData.gender || 'Không Rõ';

            const attributes = JSON.parse(charData.attributes || '{}');
            Object.keys(CREATION_CONFIG.ATTRIBUTES).forEach(key => {
                if (attributes[key] === undefined) {
                    const isSpecial = key === 'Tín Ngưỡng' || key === 'Thân Hòa Vực Sâu';
                    attributes[key] = isSpecial ? 0 : 8;
                }
            });

            const attributesGrid = container.querySelector('#bc-editor-attributes-grid');
            const summaryEl = container.querySelector('#npc-attr-points-summary');

            const getAttrMin = (attrName) => (attrName === 'Tín Ngưỡng' || attrName === 'Thân Hòa Vực Sâu') ? 0 : 1;

            const updateSummary = () => {
                const level = parseInt(document.getElementById('bc-editor-level').value) || 1;
                const pool = getValidPointPool(level);
                let totalPoints = 0;
                Object.values(attributes).forEach(val => totalPoints += (parseInt(val) || 0));

                let summaryHTML = `Điểm: <span class="${totalPoints > pool.max ? 'penalty' : 'bonus'}">${totalPoints}</span> / ${pool.min}-${pool.max}`;
                if (totalPoints > pool.max) {
                    summaryHTML += ` <span class="penalty">(Vượt quá giới hạn!)</span>`;
                }
                summaryEl.innerHTML = summaryHTML;
                return totalPoints;
            };

            attributesGrid.innerHTML = Object.keys(CREATION_CONFIG.ATTRIBUTES).map(key => `
                <div class="attribute-item">
                    <div class="name-desc"><strong>${key}</strong></div>
                    <div class="attribute-controls">
                        <button class="attr-btn minus" data-attr="${key}">-</button>
                        <input type="number" class="value bonded-char-attr-input" data-attr-val="${key}" value="${attributes[key]}" min="${getAttrMin(key)}" max="100">
                        <button class="attr-btn plus" data-attr="${key}">+</button>
                    </div>
                </div>
            `).join('');

            const levelInput = container.querySelector('#bc-editor-level');
            levelInput.addEventListener('change', updateSummary);

            const updateAttributeUI = () => {
                const totalPoints = updateSummary();
                const level = parseInt(levelInput.value) || 1;
                const pool = getValidPointPool(level);
                attributesGrid.querySelectorAll('.attribute-item').forEach(item => {
                    const attr = item.querySelector('.plus').dataset.attr;
                    const currentValue = attributes[attr];
                    const minValue = getAttrMin(attr);
                    item.querySelector('.value').value = currentValue;
                    item.querySelector('.plus').disabled = currentValue >= 30 || totalPoints >= pool.max;
                    item.querySelector('.minus').disabled = currentValue <= minValue;
                });
            };

            attributesGrid.querySelectorAll('.bonded-char-attr-input').forEach(input => {
                input.addEventListener('change', (e) => {
                    const attr = e.target.dataset.attrVal;
                    const oldValue = attributes[attr] || 0;
                    const minValue = getAttrMin(attr);
                    let newValue = parseInt(e.target.value) || 0;

                    newValue = Math.max(minValue, Math.min(30, newValue));

                    const totalPoints = updateSummary();
                    const newTotalPoints = totalPoints - oldValue + newValue;
                    const level = parseInt(levelInput.value) || 1;
                    const pool = getValidPointPool(level);

                    if (newTotalPoints > pool.max) {
                        e.target.value = oldValue;
                        showCustomAlert(`Tổng điểm thuộc tính (${newTotalPoints}) sẽ vượt quá giới hạn (${pool.max}) của cấp ${level}, không thể thực hiện thay đổi này！`);
                    } else {
                        attributes[attr] = newValue;
                        e.target.value = newValue;
                    }
                    updateAttributeUI();
                });
            });

            attributesGrid.querySelectorAll('.attr-btn').forEach(btn => {
                btn.addEventListener('click', (e) => {
                    const attr = e.currentTarget.dataset.attr;
                    const isPlus = e.currentTarget.classList.contains('plus');
                    const itemRow = e.currentTarget.closest('.attribute-item');
                    const inputEl = itemRow.querySelector('.bonded-char-attr-input');

                    let currentValue = attributes[attr] || 0;
                    const minValue = getAttrMin(attr);
                    const totalPoints = updateSummary();
                    const level = parseInt(levelInput.value) || 1;
                    const pool = getValidPointPool(level);

                    if (isPlus) {
                        if (currentValue < 30 && totalPoints < pool.max) currentValue++;
                    } else {
                        if (currentValue > minValue) currentValue--;
                    }

                    attributes[attr] = currentValue;
                    inputEl.value = currentValue;
                    updateAttributeUI();
                });
            });

            attributesGrid.querySelectorAll('.custom-bonus-input').forEach(input => {
                input.addEventListener('change', (e) => {
                    const attr = e.target.dataset.attrVal;
                    const oldValue = baseAttributes[attr] || 0;
                    const minValue = getAttrMin(attr);
                    let newValue = parseInt(e.target.value) || 0;
                    newValue = Math.max(minValue, Math.min(15, newValue));

                    const pointsUsed = updateUI();
                    const newPointsUsed = pointsUsed - oldValue + newValue;

                    if (newPointsUsed > 90) {
                        e.target.value = oldValue;
                        showCustomAlert('Tổng điểm thuộc tính cơ bản không được vượt quá 90！');
                    } else {
                        baseAttributes[attr] = newValue;
                        e.target.value = newValue;
                    }
                    updateUI();
                });
            });

            updateAttributeUI();

            const relationListEl = container.querySelector('#bc-editor-npc-relation-list');
            const relationTargetSelect = container.querySelector('#bc-editor-relation-target');
            if (relationTargetSelect) {
                relationTargetSelect.innerHTML = availableNpcsForRelations.map(npc => `<option value="${npc.id}">${npc.name}</option>`).join('');
            }

            const allRelations = (charData.rawRelations || '').split(';').filter(r => r.trim());
            const playerRelationEntry = allRelations.find(r => r.trim().startsWith('B1:'));
            container.querySelector('#bc-editor-player-relation').value = playerRelationEntry ? playerRelationEntry.split(':')[1] || '' : '';
            const npcRelations = allRelations.filter(r => !r.trim().startsWith('B1:'));
            npcRelations.forEach(relationEntry => {
                const [targetId, ...relationTextParts] = relationEntry.split(':');
                const relationText = relationTextParts.join(':');
                const targetNpc = availableNpcsForRelations.find(npc => npc.id === targetId);
                if (targetNpc) addNpcRelationToListUI(targetId, targetNpc.name, relationText);
            });

            const addRelationBtn = container.querySelector('#bc-editor-add-relation-btn');
            if (addRelationBtn) {
                addRelationBtn.addEventListener('click', () => {
                    const targetId = relationTargetSelect.value;
                    const targetName = relationTargetSelect.options[relationTargetSelect.selectedIndex]?.text;
                    const text = container.querySelector('#bc-editor-relation-text').value.trim();
                    if (targetId && text) {
                        addNpcRelationToListUI(targetId, targetName, text);
                        container.querySelector('#bc-editor-relation-text').value = '';
                    }
                });
            }

            if (relationListEl) {
                relationListEl.addEventListener('click', (e) => {
                    if (e.target.closest('.relation-delete-btn')) {
                        e.target.closest('.relation-item').remove();
                    }
                });
            }

            const stagesContainer = container.querySelector('#favor-stages-container');
            (charData.stages || []).forEach(stage => addFavorStage(stagesContainer, stage));

            container.querySelector('#save-bonded-char-editor-btn').onclick = async () => {
                const updatedData = { ...charData };
                updatedData.attributes = JSON.stringify(attributes);

                const stages = [];
                container.querySelectorAll('#favor-stages-container .favor-stage').forEach(el => {
                    stages.push({
                        min: parseInt(el.querySelector('.favor-min').value) || 0,
                        max: parseInt(el.querySelector('.favor-max').value) || 0,
                        attitude: el.querySelector('.favor-attitude').value,
                        description: el.querySelector('.favor-description').value
                    });
                });
                updatedData.stages = stages;
                await onSave(updatedData);
            };

            setTimeout(() => container.querySelectorAll('textarea').forEach(autosizeTextarea), 0);
        }

        async function openBondedCharEditor(index = -1) {
