                charData: charData,
            });
            const summaryEl = document.getElementById('npc-attr-points-summary');
            const saveBtn = document.getElementById('save-bonded-char-editor-btn');
            const level = 5;
            const pool = getValidPointPool(level);
            const totalPoints = Object.values(JSON.parse(charData.attributes || '{}')).reduce((sum, val) => sum + (parseInt(val) || 0), 0);

            if (totalPoints > pool.max) {
                summaryEl.innerHTML += ` <span class="penalty">(Đã vượt quá giới hạn!)</span>`;
            }

            editorOverlay.classList.add('visible');
        }

