            const genderSelect = container.querySelector('#bc-editor-gender');
            genderSelect.innerHTML = `<option value="Nam">Nam</option><option value="Nữ">Nữ</option><option value="Đực">Đực</option><option value="Cái">Cái</option><option value="Futanari">Futanari</option><option value="Vô Tính">Vô Tính</option><option value="Khác">Khác</option><option value="Không Rõ">Không Rõ</option>`;
            genderSelect.value = charData.gender || 'Không Rõ';

            const attributes = JSON.parse(charData.attributes || '{}');
            Object.keys(CREATION_CONFIG.ATTRIBUTES).forEach(key => {
                if (attributes[key] === undefined) {
                    const isSpecial = key === 'Tín Ngưỡng' || key === 'Thân Hòa Vực Sâu';
                    attributes[key] = isSpecial ? 0 : 8;
                }
            });

            const attributesGrid = container.querySelector('#bc-editor-attributes-grid');
            const summaryEl = container.querySelector('#npc-attr-points-summary');

            const getAttrMin = (attrName) => (attrName === 'Tín Ngưỡng' || attrName === 'Thân Hòa Vực Sâu') ? 0 : 1;

            const updateSummary = () => {
                const totalPoints = Object.values(attributes).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                const pool = getValidPointPool(5);
                summaryEl.innerHTML = `Điểm (Theo tiêu chuẩn cấp 5): <span class="${totalPoints > pool.max ? 'penalty' : 'bonus'}">${totalPoints}</span> / ${pool.min}-${pool.max}`;
                return totalPoints;
            };

            attributesGrid.innerHTML = Object.keys(CREATION_CONFIG.ATTRIBUTES).map(key => `
                <div class="attribute-item">
                    <div class="name-desc"><strong>${key}</strong></div>
                    <div class="attribute-controls">
                        <button class="attr-btn minus" data-attr="${key}">-</button>
                        <input type="number" class="value bonded-char-attr-input" data-attr-val="${key}" value="${attributes[key]}" min="${getAttrMin(key)}" max="100">
                        <button class="attr-btn plus" data-attr="${key}">+</button>
                    </div>
                </div>
            `).join('');

            attributesGrid.querySelectorAll('.bonded-char-attr-input, .attr-btn').forEach(el => {
                const updateAttribute = (attr, newValue) => {
                    attributes[attr] = newValue;
                    updateSummary();
                    return newValue;
                };

                if (el.tagName === 'INPUT') {
                    el.addEventListener('change', (e) => {
                        const attr = e.target.dataset.attrVal;
                        let newValue = parseInt(e.target.value) || 0;
                        newValue = Math.max(getAttrMin(attr), Math.min(30, newValue));
                        e.target.value = updateAttribute(attr, newValue);
                    });
                } else {
                    el.addEventListener('click', (e) => {
                        const attr = e.currentTarget.dataset.attr;
                        let currentValue = attributes[attr] || 0;
                        if (e.currentTarget.classList.contains('plus')) {
                            if (currentValue < 30) currentValue++;
                        } else {
                            if (currentValue > getAttrMin(attr)) currentValue--;
                        }
                        const inputEl = attributesGrid.querySelector(`[data-attr-val="${attr}"]`);
                        inputEl.value = updateAttribute(attr, currentValue);
                    });
                }
            });

            updateSummary();

            container.querySelector('#save-bonded-char-editor-btn').addEventListener('click', async () => {
                const name = document.getElementById('bc-editor-name').value.trim();
                if (!name) { await showCustomAlert('Tên không được để trống！'); return; }

                const pool = getValidPointPool(5);
                const totalPoints = Object.values(attributes).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                if (totalPoints > pool.max) {
                    await showCustomAlert(`Lưu thất bại:\n\nTổng điểm thuộc tính (${totalPoints}) đã vượt quá giới hạn khuyến nghị (${pool.max}) của cấp 5 ban đầu.\n\nVui lòng giảm điểm thuộc tính trước khi lưu.`);
                    return;
                }

                const chars = await getBondedChars();
                const playerRelationText = document.getElementById('bc-editor-player-relation').value.trim();

                const charDataToSave = {
                    id: currentEditingBondedCharIndex > -1 ? chars[currentEditingBondedCharIndex].id : `G${crypto.randomUUID()}`,
                    name: name,
                    gender: document.getElementById('bc-editor-gender').value,
                    race: document.getElementById('bc-editor-race').value.trim(),
                    career: document.getElementById('bc-editor-career').value.trim(),
                    identity: document.getElementById('bc-editor-identity').value.trim(),
                    core_appearance: document.getElementById('bc-editor-core-appearance').value.trim(),
                    rawAppearance: document.getElementById('bc-editor-raw-appearance').value.trim(),
                    personality: document.getElementById('bc-editor-personality').value.trim(),
                    background: document.getElementById('bc-editor-background').value.trim(),
                    attributes: JSON.stringify(attributes),
                    age: document.getElementById('bc-editor-age').value.trim() || '25',
                    level: '5',
                    favorability: '50',
                    rawRelations: `B1:${playerRelationText || 'Đồng Hành Ban Đầu'}`
                };

                if (currentEditingBondedCharIndex > -1) {
                    chars[currentEditingBondedCharIndex] = charDataToSave;
                } else {
                    chars.push(charDataToSave);
                }
                await dbSet(CUSTOM_BONDED_CHARS_KEY, chars);

                document.getElementById('bonded-character-editor-overlay').classList.remove('visible');
                await renderBondedCharManager();
            });

            setTimeout(() => container.querySelectorAll('textarea').forEach(autosizeTextarea), 0);
        }

