        function stopAllStreams() {
            if (fakeStreamInterval) clearInterval(fakeStreamInterval);
            if (fakeStreamPauseTimeout) clearTimeout(fakeStreamPauseTimeout);
            if (typewriterInterval) clearInterval(typewriterInterval);
            fakeStreamInterval = null;
            fakeStreamPauseTimeout = null;
            typewriterInterval = null;
        }

        async function typewriterStream(element, htmlContent, callback) {
            stopAllStreams();

            const tempDiv = document.createElement('div');
            tempDiv.innerHTML = htmlContent;
            const sourceNodes = Array.from(tempDiv.childNodes);
            const delay = ms => new Promise(res => setTimeout(res, ms));

            const processNode = async (sourceNode, targetElement) => {
                if (sourceNode.nodeType === Node.TEXT_NODE) {
                    for (const char of sourceNode.textContent) {
                        targetElement.appendChild(document.createTextNode(char));
                        mainContentArea.scrollTop = mainContentArea.scrollHeight;
                        await delay(25);
                    }
                } else if (sourceNode.nodeType === Node.ELEMENT_NODE) {
                    const newElement = sourceNode.cloneNode(false);
                    targetElement.appendChild(newElement);
                    for (const child of Array.from(sourceNode.childNodes)) {
                        await processNode(child, newElement);
                    }
                } else {
                    targetElement.appendChild(sourceNode.cloneNode(true));
                }
            };

            for (const node of sourceNodes) {
                await processNode(node, element);
            }
            if (callback) callback();
        }

        function startFakeStream(element) {
            stopAllStreams();
            const phrases = [
                'Đang kết nối với Cây Thế Giới...', 'Đang phân tích định luật nhân quả...', 'Đang lắng nghe tiếng vọng của vận mệnh...',
                'Nữ thần đang đáp lại...', 'Đang xây dựng các nhánh khả năng...', 'Đang tính toán các nếp gấp thực tại...', 'Quan sát quỹ đạo các vì sao...'
            ];
            let phraseIndex = Math.floor(Math.random() * phrases.length);
            let charIndex = 0;
            let isDeleting = false;
            let pauseCounter = 0;
            const pauseDuration = 15;

            const textNode = document.createTextNode('');
            const cursorSpan = document.createElement('span');
            cursorSpan.id = 'streaming-message';
            element.innerHTML = '';
            element.appendChild(textNode);
            element.appendChild(cursorSpan);

            const updateText = () => {
                if (pauseCounter > 0) {
                    pauseCounter--;
                    return;
                }

                const currentPhrase = phrases[phraseIndex];
                textNode.nodeValue = currentPhrase.substring(0, charIndex);

                if (!isDeleting && charIndex < currentPhrase.length) {
                    charIndex++;
                } else if (isDeleting && charIndex > 0) {
                    charIndex--;
                } else {
                    isDeleting = !isDeleting;
                    if (!isDeleting) {
                        phraseIndex = (phraseIndex + 1) % phrases.length;
                    }
                    pauseCounter = pauseDuration;
                }
            };

            fakeStreamInterval = setInterval(updateText, 100);
        }

