        function validateCustomBirthStructure(birth) {
            if (!birth.name) return 'Thiếu tên Xuất Thân.';
            if (!birth.description) return 'Thiếu mô tả Xuất Thân.';
            if (typeof birth.bonus !== 'object' || birth.bonus === null) return 'Dữ liệu điều chỉnh thuộc tính (bonus) bị thiếu hoặc sai định dạng.';
            return null;
        }

        function validateCustomRaceStructure(race) {
            if (!race.name && !race.tag) return 'Thiếu tên Chủng Tộc.';
            if (!race.description) return 'Thiếu mô tả Chủng Tộc.';
            if (typeof race.base_attributes !== 'object' || race.base_attributes === null) return 'Dữ liệu thuộc tính cơ bản (base_attributes) bị thiếu hoặc sai định dạng.';
            if (!Array.isArray(race.traits)) return 'Dữ liệu thiên phú Chủng Tộc (traits) sai định dạng, phải là một mảng.';
            if (race.traits.length > 1) return 'Chủng Tộc tùy chỉnh chỉ có thể có một thiên phú, vui lòng sửa lại trong trình chỉnh sửa.';
            return null;
        }

        function validateCustomTraitStructure(trait) {
            if (!trait.name) return 'Thiếu tên Thiên Phú.';
            if (!trait.rarity || !CREATION_CONFIG.TRAIT_RARITIES[trait.rarity]) return `Phẩm chất thiên phú (rarity) “${trait.rarity}” không hợp lệ.`;
            if (typeof trait.bonus !== 'object' || trait.bonus === null) return 'Dữ liệu điều chỉnh thuộc tính (bonus) bị thiếu hoặc sai định dạng.';
            return null;
        }

        function validateBondedCharStructure(char) {
            if (!char.name) return 'Thiếu tên Nhân Vật Gắn Kết.';
            if (!char.gender) return 'Thiếu thông tin giới tính.';
            if (!char.race) return 'Thiếu thông tin Chủng Tộc.';
            if (!char.career) return 'Thiếu thông tin Chức Nghiệp.';
            if (typeof char.attributes !== 'string') return 'Dữ liệu thuộc tính (attributes) bị thiếu hoặc không phải định dạng chuỗi.';
            try {
                const attrs = JSON.parse(char.attributes);
                if (typeof attrs !== 'object' || attrs === null) return 'Dữ liệu thuộc tính (attributes) sau khi phân tích JSON không phải là một đối tượng.';
            } catch (e) {
                return 'Dữ liệu thuộc tính (attributes) không thể được phân tích thành JSON hợp lệ.';
            }
            return null;
        }

        async function openCustomDataSelection(type) {
            const config = {
                birth: {
                    overlay: customBirthSelectionOverlay,
                    listEl: document.getElementById('custom-birth-selection-list'),
                    dbKey: CUSTOM_BIRTHS_KEY,
                    openEditor: openCustomBirthEditor,
                    validator: validateCustomBirthStructure,
                },
                race: {
                    overlay: customRaceSelectionOverlay,
                    listEl: document.getElementById('custom-race-selection-list'),
                    dbKey: CUSTOM_RACES_KEY,
                    openEditor: openCustomRaceEditor,
                    validator: validateCustomRaceStructure,
                },
                'class': {
                    overlay: customClassSelectionOverlay,
                    listEl: document.getElementById('custom-class-selection-list'),
                    dbKey: CUSTOM_CLASSES_KEY,
                    openEditor: openCustomClassEditor,
                    validator: validateCustomClassStructure,
                }
            };

            const typeConfig = config[type];
            if (!typeConfig) {
                console.error("Loại dữ liệu tùy chỉnh không xác định:", type);
                return;
            }

            const { overlay, listEl, dbKey, openEditor, validator } = typeConfig;
            const items = await dbGet(dbKey) || [];

            listEl.innerHTML = '';
            if (items.length === 0) {
                listEl.innerHTML = `<p style="text-align:center; opacity:0.7;">Danh sách trống, vui lòng tạo trước.</p>`;
            } else {
                items.forEach(item => {
                    const div = document.createElement('div');
                    div.className = 'custom-list-item';
                    div.innerHTML = `
                        <span class="item-name" data-id="${item.id}">${item.name || item.tag}</span>
                        <div class="item-actions">
                            <button data-id="${item.id}" data-action="edit" title="Chỉnh Sửa"><i class="fas fa-edit"></i></button>
                            <button data-id="${item.id}" data-action="delete" title="Xóa"><i class="fas fa-trash"></i></button>
                        </div>
                    `;
                    listEl.appendChild(div);
                });
            }

            if (listEl.eventListener) {
                listEl.removeEventListener('click', listEl.eventListener);
            }
            listEl.eventListener = async (e) => {
                const target = e.target;
                const button = target.closest('button');
                const itemName = target.closest('.item-name');

                if (button) {
                    e.stopPropagation();
                    const id = button.dataset.id;
                    const action = button.dataset.action;
                    if (action === 'edit') {
                        openEditor(id);
                    } else if (action === 'delete') {
                        if (await showCustomConfirm('Bạn có chắc muốn xóa mục tùy chỉnh này không?')) {
                            let data = await dbGet(dbKey) || [];
                            data = data.filter(item => item.id !== id);
                            await dbSet(dbKey, data);
                            await openCustomDataSelection(type);
                        }
                    }
                } else if (itemName) {
                    const id = itemName.dataset.id;
                    const item = items.find(i => i.id === id);
                    if (!item) return;

                    const validationError = validator(item);
                    if (validationError) {
                        await showCustomAlert(`Không thể chọn, định dạng dữ liệu không chính xác:\n\n${validationError}\n\nVui lòng nhấn nút chỉnh sửa để sửa lại.`);
                        return;
                    }

                    const tempState = JSON.parse(JSON.stringify(creationState));
                    if (type === 'class') {
                        tempState.selectedCareer = 'Tùy Chỉnh';
                        tempState.customCareer = item;
                    } else {
                        tempState[type === 'birth' ? 'selectedBirth' : 'selectedRace'] = 'Tùy Chỉnh';
                        tempState[type === 'birth' ? 'customBirth' : 'customRace'] = item;
                    }

                    if (type === 'race') {
                        const newBase = item.base_attributes || {};
                        Object.keys(CREATION_CONFIG.ATTRIBUTES).forEach(key => {
                            const isSpecial = key === 'Tín Ngưỡng' || key === 'Thân Hòa Vực Sâu';
                            tempState.attributes[key] = newBase[key] !== undefined ? newBase[key] : (isSpecial ? 0 : 8);
                        });
                    }

                    const tempPointsAfterSwitch = calculateRemainingPoints(tempState);

                    if (tempPointsAfterSwitch < 0) {
                        await showCustomAlert(`Không đủ Điểm Số Mệnh (cần ${-tempPointsAfterSwitch} điểm), không thể chọn mục tùy chỉnh này！`);
                        return;
                    }

                    if (type === 'class') {
                        creationState.selectedCareer = 'Tùy Chỉnh';
                        creationState.customCareer = item;
                    } else {
                        creationState[type === 'birth' ? 'selectedBirth' : 'selectedRace'] = 'Tùy Chỉnh';
                        creationState[type === 'birth' ? 'customBirth' : 'customRace'] = item;
                    }

                    if (type === 'race') {
                        const newBase = item.base_attributes || {};
                        Object.keys(CREATION_CONFIG.ATTRIBUTES).forEach(key => {
                            const isSpecial = key === 'Tín Ngưỡng' || key === 'Thân Hòa Vực Sâu';
                            creationState.attributes[key] = newBase[key] !== undefined ? newBase[key] : (isSpecial ? 0 : 8);
                        });
                    }

                    overlay.classList.remove('visible');
                    renderCreationStep();
                }
            };

            listEl.addEventListener('click', listEl.eventListener);

            overlay.classList.add('visible');
        }

        async function openCustomBirthEditor(id = null) {
            currentEditingCustomBirthId = id;
            const isEditing = id !== null;
            const births = await dbGet(CUSTOM_BIRTHS_KEY) || [];
            const birth = isEditing ? births.find(b => b.id === id) : {};

            document.getElementById('custom-birth-editor-title').textContent = isEditing ? 'Chỉnh Sửa Xuất Thân' : 'Tạo Xuất Thân Mới';
            document.getElementById('custom-birth-name').value = birth.name || '';
            document.getElementById('custom-birth-desc').value = birth.description || '';

            const attributesContainer = document.getElementById('custom-birth-attributes');
            const summaryEl = document.getElementById('custom-attr-points-summary');
            const customBonus = birth.bonus || {};

            const updateSummary = () => {
                const pointsUsed = Object.values(customBonus).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                summaryEl.innerHTML = `Tổng điều chỉnh thuộc tính: <span class="cost">${pointsUsed} / 10</span>`;
                return pointsUsed;
            };

            attributesContainer.innerHTML = Object.keys(CREATION_CONFIG.ATTRIBUTES).map(key => `
                <div class="attribute-item">
                    <div class="name-desc"><strong>${key}</strong></div>
                    <div class="attribute-controls">
                        <button class="attr-btn minus" data-attr="${key}">-</button>
                        <input type="number" class="value custom-bonus-input" data-attr-val="${key}" value="${customBonus[key] || 0}" min="-5" max="5">
                        <button class="attr-btn plus" data-attr="${key}">+</button>
                    </div>
                </div>
            `).join('');

            attributesContainer.querySelectorAll('.custom-bonus-input').forEach(input => {
                input.addEventListener('change', (e) => {
                    const attr = e.target.dataset.attrVal;
                    const oldValue = customBonus[attr] || 0;
                    let newValue = parseInt(e.target.value) || 0;
                    newValue = Math.max(-5, Math.min(5, newValue));

                    const currentTotal = Object.values(customBonus).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                    const newPointsUsed = currentTotal - oldValue + newValue;

                    if (newPointsUsed > 10) {
                        e.target.value = oldValue;
                        showCustomAlert('Tổng điều chỉnh thuộc tính không được vượt quá 10！');
                    } else {
                        customBonus[attr] = newValue;
                        e.target.value = newValue;
                    }
                    updateSummaryAndControls();
                });
            });

            attributesContainer.querySelectorAll('.attr-btn').forEach(btn => {
                btn.addEventListener('click', (e) => {
                    const attr = e.target.dataset.attr;
                    const input = attributesContainer.querySelector(`[data-attr-val="${attr}"]`);
                    let currentValue = parseInt(input.value) || 0;
                    const isPlus = e.target.classList.contains('plus');

                    const oldValue = customBonus[attr] || 0;
                    const pointsUsed = updateSummary();

                    if (isPlus) {
                        if (currentValue < 5) currentValue++;
                    } else {
                        if (currentValue > -5) currentValue--;
                    }

                    const newPointsUsed = pointsUsed - oldValue + currentValue;
                    if (newPointsUsed > 10) {
                        return;
                    }

                    input.value = currentValue;
                    customBonus[attr] = currentValue;
                    updateSummary();
                });
            });

            attributesContainer.querySelectorAll('.custom-bonus-input').forEach(input => {
                input.addEventListener('change', (e) => {
                    const attr = e.target.dataset.attrVal;
                    const oldValue = customBonus[attr] || 0;
                    let newValue = parseInt(e.target.value) || 0;
                    newValue = Math.max(-5, Math.min(5, newValue));

                    const pointsUsed = updateSummary();
                    const newPointsUsed = pointsUsed - oldValue + newValue;

                    if (newPointsUsed > 10) {
                        e.target.value = oldValue;
                        showCustomAlert('Tổng điều chỉnh thuộc tính không được vượt quá 10！');
                    } else {
                        customBonus[attr] = newValue;
                        e.target.value = newValue;
                    }
