            document.getElementById('custom-race-name').value = race.name || race.tag || '';
            document.getElementById('custom-race-desc').value = race.description || '';

            const attributesContainer = document.getElementById('custom-race-attributes');
            const summaryEl = document.getElementById('custom-race-attr-points-summary');

            const baseAttributes = {};
            Object.keys(CREATION_CONFIG.ATTRIBUTES).forEach(key => {
                const isSpecialAttr = key === 'Tín Ngưỡng' || key === 'Thân Hòa Vực Sâu';
                const defaultValue = isSpecialAttr ? 0 : 8;
                baseAttributes[key] = (race.base_attributes && race.base_attributes[key] !== undefined) ? race.base_attributes[key] : defaultValue;
            });

            const getAttrMin = (attrName) => (attrName === 'Tín Ngưỡng' || attrName === 'Thân Hòa Vực Sâu') ? 0 : 1;

            const updateUI = () => {
                const pointsUsed = Object.values(baseAttributes).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                summaryEl.innerHTML = `Tổng điểm thuộc tính cơ bản: <span class="cost">${pointsUsed} / 90</span>`;

                attributesContainer.querySelectorAll('.attribute-item').forEach(item => {
                    const attr = item.querySelector('.attr-btn').dataset.attr;
                    const currentValue = baseAttributes[attr] || 0;
                    const minValue = getAttrMin(attr);
                    const minusBtn = item.querySelector('.minus');
                    const plusBtn = item.querySelector('.plus');

                    minusBtn.disabled = currentValue <= minValue;
                    plusBtn.disabled = currentValue >= 15 || pointsUsed >= 90;
                });
                return pointsUsed;
            };

            attributesContainer.innerHTML = Object.keys(CREATION_CONFIG.ATTRIBUTES).map(key => {
                const minValue = getAttrMin(key);
                return `
                    <div class="attribute-item">
                        <div class="name-desc"><strong>${key}</strong></div>
                        <div class="attribute-controls">
                            <button class="attr-btn minus" data-attr="${key}">-</button>
                            <input type="number" class="value custom-bonus-input" data-attr-val="${key}" value="${baseAttributes[key]}" min="${minValue}" max="15">
                            <button class="attr-btn plus" data-attr="${key}">+</button>
                        </div>
                    </div>
                `;
            }).join('');

            attributesContainer.querySelectorAll('.custom-bonus-input').forEach(input => {
                input.addEventListener('change', (e) => {
                    const attr = e.target.dataset.attrVal;
                    const oldValue = baseAttributes[attr] || 0;
                    const minValue = getAttrMin(attr);
                    let newValue = parseInt(e.target.value) || 0;
                    newValue = Math.max(minValue, Math.min(15, newValue));

                    const pointsUsed = updateUI();
                    const newPointsUsed = pointsUsed - oldValue + newValue;

                    if (newPointsUsed > 90) {
                        e.target.value = oldValue;
                        showCustomAlert('Tổng điểm thuộc tính cơ bản không được vượt quá 90！');
                    } else {
                        baseAttributes[attr] = newValue;
                        e.target.value = newValue;
                    }
                    updateUI();
                });
