            attributesContainer.querySelectorAll('.attr-btn').forEach(btn => {
                btn.addEventListener('click', (e) => {
                    const attr = e.target.dataset.attr;
                    const input = attributesContainer.querySelector(`[data-attr-val="${attr}"]`);
                    let currentValue = parseInt(input.value) || 0;
                    const isPlus = e.target.classList.contains('plus');
                    const minValue = getAttrMin(attr);

                    const pointsUsed = updateUI();

                    if (isPlus) {
                        if (currentValue < 15 && pointsUsed < 90) currentValue++;
                    } else {
                        if (currentValue > minValue) currentValue--;
                    }

                    const newPointsUsed = pointsUsed - (parseInt(baseAttributes[attr]) || 0) + currentValue;
                    if (newPointsUsed > 90 && isPlus) {
                        return;
                    }

                    input.value = currentValue;
                    baseAttributes[attr] = currentValue;
                    updateUI();
                });
            });

            attributesContainer.querySelectorAll('.custom-bonus-input').forEach(input => {
                input.addEventListener('change', (e) => {
                    const attr = e.target.dataset.attrVal;
                    const oldValue = baseAttributes[attr] || 0;
