                    let newValue = parseInt(e.target.value) || 0;
                    newValue = Math.max(minValue, Math.min(15, newValue));

                    const pointsUsed = updateUI();
                    const newPointsUsed = pointsUsed - oldValue + newValue;

                    if (newPointsUsed > 90) {
                        e.target.value = oldValue;
                        showCustomAlert('Tổng điểm thuộc tính cơ bản không được vượt quá 90！');
                    } else {
                        baseAttributes[attr] = newValue;
                        e.target.value = newValue;
                    }
                    updateUI();
                });
            });

