        async function handleImportCustomData(dbKey, dataType, isAchievement = false) {
            genericImportInput.onchange = async (e) => {
                const file = e.target.files[0];
                if (!file) return;
                const reader = new FileReader();
                reader.onload = async (event) => {
                    try {
                        let importedData = JSON.parse(event.target.result);
                        if (!Array.isArray(importedData)) throw new Error('Định dạng tệp không chính xác, phải là một mảng JSON.');

                        let currentData;
                        if (isAchievement) {
                            const archive = await db.archives.get(currentArchiveName);
                            currentData = archive.data.state.achievements.custom || [];
                        } else {
                            currentData = await dbGet(dbKey) || [];
                        }

                        const defaultAttributes = Object.keys(CREATION_CONFIG.ATTRIBUTES).reduce((acc, key) => {
                            const isSpecial = key === 'Tín Ngưỡng' || key === 'Thân Hòa Vực Sâu';
                            acc[key] = isSpecial ? 0 : 8;
                            return acc;
                        }, {});
                        const defaultAttributesString = JSON.stringify(defaultAttributes);

                        const sanitizedImportedData = importedData.map(char => {
                            char.level = '5';
                            const attributes = JSON.parse(char.attributes || '{}');
                            const totalPoints = Object.values(attributes).reduce((sum, val) => sum + (parseInt(val) || 0), 0);
                            const pool = getValidPointPool(5);
                            if (totalPoints > pool.max) {
                                console.warn(`Cảnh báo nhập: Điểm thuộc tính của mẫu nhân vật "${char.name}" (${totalPoints}) đã vượt quá giới hạn cấp 5 (${pool.max}), thuộc tính đã được đặt lại về giá trị mặc định.`);
                                char.attributes = defaultAttributesString;
                            }
                            return char;
                        });

                        const currentIds = new Set(currentData.map(item => item.id));
                        sanitizedImportedData.forEach(item => {
                            if (!item.id) item.id = crypto.randomUUID();
                            if (!currentIds.has(item.id)) {
                                currentData.push(item);
                            }
                        });

                        if (isAchievement) {
                            const archive = await db.archives.get(currentArchiveName);
                            archive.data.state.achievements.custom = currentData;
                            await db.archives.put(archive);
                            await openCustomAchievementManager();
                        } else {
                            await dbSet(dbKey, currentData);
                            if (dbKey === CUSTOM_TRAITS_KEY) await renderCustomTraitManager();
                            else if (dbKey === CUSTOM_BONDED_CHARS_KEY) await renderBondedCharManager();
                            else await openCustomDataSelection(dataType.includes('Xuất Thân') ? 'birth' : 'race');
                        }
                        await showCustomAlert(`Dữ liệu ${dataType} đã được nhập thành công！Sẽ được xác thực chi tiết khi chọn sử dụng.`);

                    } catch (err) {
                        await showCustomAlert(`Nhập thất bại: ${err.message}`);
                    } finally {
                        genericImportInput.value = '';
                    }
                };
                reader.readAsText(file);
            };
            genericImportInput.click();
        }

        async function handleExportCustomData(dbKey, fileName, isAchievement = false) {
            let data;
            if (isAchievement) {
                const archive = await db.archives.get(currentArchiveName);
                data = archive?.data?.state?.achievements?.custom || [];
            } else {
                data = await dbGet(dbKey) || [];
            }

            if (data.length === 0) {
                await showCustomAlert('Không có dữ liệu để xuất.');
                return;
            }
            const dataStr = JSON.stringify(data, null, 2);
            const dataBlob = new Blob([dataStr], {type: "application/json"});
            const url = URL.createObjectURL(dataBlob);
            const a = document.createElement('a');
            a.href = url;
            a.download = fileName;
            document.body.appendChild(a);
            a.click();
            document.body.removeChild(a);
            URL.revokeObjectURL(url);
        }

