        function setupFabListeners() {
            let isDragging = false;
            let startX, startY, clientStartX, clientStartY;
            let currentX, currentY;
            let hasMoved = false;
            const moveThreshold = 15;

            const FAB_ACTIONS = {
                'storage': () => {
                    if (currentPlayerData.isExtreme) {
                        openWarehouseUI();
                    } else {
                        showCustomAlert('Chức năng kho chỉ khả dụng trong chế độ Cực Hạn.');
                    }
                },
                'attributes': openAttributeAllocator,
                'alchemy': openAlchemyInterface
            };

            const toggleMenu = () => {
                fabContainer.classList.toggle('open');
                if (fabContainer.classList.contains('open')) {
                    fabContainer.classList.remove('retracted-top', 'retracted-bottom', 'retracted-left', 'retracted-right');
                }
            };

            fabBall.addEventListener('click', (e) => {
                const clientX = e.clientX;
                const clientY = e.clientY;
                const lastReleaseX = parseFloat(fabBall.dataset.lastReleaseX) || 0;
                const lastReleaseY = parseFloat(fabBall.dataset.lastReleaseY) || 0;

                const moveDistance = Math.sqrt(Math.pow(clientX - lastReleaseX, 2) + Math.pow(clientY - lastReleaseY, 2));

                if (moveDistance < 10) {
                    toggleMenu();
                }
            });

            const dragStart = (e) => {
                e.preventDefault();
                hasMoved = false;
                isDragging = false;
                const clientX = e.touches ? e.touches[0].clientX : e.clientX;
                const clientY = e.touches ? e.touches[0].clientY : e.clientY;

                startX = clientX;
                startY = clientY;
                clientStartX = clientX;
                clientStartY = clientY;

                currentX = fabContainer.offsetLeft;
                currentY = fabContainer.offsetTop;

                document.body.addEventListener('mousemove', dragMove);
                document.body.addEventListener('touchmove', dragMove, { passive: false });
                document.body.addEventListener('mouseup', dragEnd, { once: true });
                document.body.addEventListener('touchend', dragEnd, { once: true });

                fabContainer.classList.remove('retracted-top', 'retracted-bottom', 'retracted-left', 'retracted-right');
            };

            const dragMove = (e) => {
                const clientX = e.touches ? e.touches[0].clientX : e.clientX;
                const clientY = e.touches ? e.touches[0].clientY : e.clientY;

                const deltaX = clientX - startX;
                const deltaY = clientY - startY;

                if (!hasMoved && Math.sqrt(deltaX * deltaX + deltaY * deltaY) > moveThreshold) {
                    hasMoved = true;
                    isDragging = true;
                    fabBall.style.cursor = 'grabbing';
                    document.body.style.userSelect = 'none';
                }

                if (isDragging) {
                    const chatViewRect = chatView.getBoundingClientRect();
                    let newLeft = currentX + deltaX;
                    let newTop = currentY + deltaY;

                    newLeft = Math.max(0, Math.min(newLeft, chatViewRect.width - fabContainer.offsetWidth));
                    newTop = Math.max(0, Math.min(newTop, chatViewRect.height - fabContainer.offsetHeight));

                    fabContainer.style.left = `${newLeft}px`;
                    fabContainer.style.top = `${newTop}px`;
                }
            };

            const dragEnd = (e) => {
                document.body.removeEventListener('mousemove', dragMove);
                document.body.removeEventListener('touchmove', dragMove);

                const clientX = e.changedTouches ? e.changedTouches[0].clientX : e.clientX;
                const clientY = e.changedTouches ? e.changedTouches[0].clientY : e.clientY;
                const totalMoveDistance = Math.sqrt(Math.pow(clientX - clientStartX, 2) + Math.pow(clientY - clientStartY, 2));

                if (totalMoveDistance < moveThreshold) {
                    isDragging = false;
                }

                if (isDragging) {
                    const chatViewRect = chatView.getBoundingClientRect();
                    const fabRect = fabContainer.getBoundingClientRect();
                    const fabSize = fabRect.width;
                    const threshold = fabSize * 0.5;

                    let currentLeft = fabRect.left - chatViewRect.left;
                    let currentTop = fabRect.top - chatViewRect.top;

                    if (currentLeft < threshold) fabContainer.classList.add('retracted-left');
                    else if (currentLeft > chatViewRect.width - fabSize - threshold) fabContainer.classList.add('retracted-right');
                    else if (currentTop < threshold) fabContainer.classList.add('retracted-top');
                    else if (currentTop > chatViewRect.height - fabSize - threshold) fabContainer.classList.add('retracted-bottom');
                } else {
                    fabBall.dataset.lastReleaseX = clientX;
                    fabBall.dataset.lastReleaseY = clientY;
                }

                isDragging = false;
                hasMoved = false;
                fabBall.style.cursor = 'grab';
                document.body.style.userSelect = '';
            };

            fabBall.addEventListener('mousedown', (e) => {
                if (e.button === 0) {
                    dragStart(e);
                }
            });
            fabBall.addEventListener('touchstart', dragStart, { passive: false });

            document.addEventListener('click', (e) => {
                if (!fabContainer.contains(e.target) && !fabShortcutMenu.contains(e.target)) {
                    fabContainer.classList.remove('open');
                    fabShortcutMenu.classList.add('hidden');
                }
            });

            const fabMenu = fabContainer.querySelector('#fab-menu');
            fabMenu.innerHTML = `
                <div id="fab-menu-ring"></div>
                <div class="fab-item fab-shortcut" data-shortcut-index="0" title="Cài Đặt Lối Tắt"><i class="fas fa-plus"></i></div>
                <div class="fab-item fab-shortcut" data-shortcut-index="1" title="Cài Đặt Lối Tắt"><i class="fas fa-plus"></i></div>
                <div class="fab-item fab-shortcut" data-shortcut-index="2" title="Cài Đặt Lối Tắt"><i class="fas fa-plus"></i></div>
                <div class="fab-item fab-shortcut" data-shortcut-index="3" title="Cài Đặt Lối Tắt"><i class="fas fa-plus"></i></div>
                <div class="fab-item fab-shortcut" data-shortcut-index="4" title="Cài Đặt Lối Tắt"><i class="fas fa-plus"></i></div>
                <div class="fab-item fab-shortcut" data-shortcut-index="5" title="Cài Đặt Lối Tắt"><i class="fas fa-plus"></i></div>
                <div class="fab-item fab-shortcut" data-shortcut-index="6" title="Cài Đặt Lối Tắt"><i class="fas fa-plus"></i></div>
                <div class="fab-item" data-action="attributes" title="Phân Phối Thuộc Tính"><i class="fas fa-fist-raised"></i></div>
                <div class="fab-item" data-action="storage" title="Kho"><i class="fas fa-archive"></i></div>
                <div class="fab-item" data-action="alchemy" title="Luyện Kim Thuật"><i class="fas fa-flask"></i></div>
            `;

            fabMenu.querySelectorAll('.fab-item[data-action]').forEach(item => {
                const action = item.dataset.action;
                if (action && FAB_ACTIONS[action]) {
                    item.addEventListener('click', () => {
                        FAB_ACTIONS[action]();
                        fabContainer.classList.remove('open');
                    });
                }
            });

            fabMenu.querySelectorAll('.fab-shortcut').forEach(item => {
                item.addEventListener('click', (e) => {
                    const shortcutIndex = parseInt(item.dataset.shortcutIndex);
                    const currentShortcut = fabShortcutConfig[shortcutIndex];
                    if (currentShortcut && SHORTCUT_ACTIONS[currentShortcut]) {
                        SHORTCUT_ACTIONS[currentShortcut].action();
                        fabContainer.classList.remove('open');
                    } else {
                        showShortcutMenu(e, shortcutIndex);
                    }
                });

                item.addEventListener('contextmenu', (e) => {
                    e.preventDefault();
                    const shortcutIndex = parseInt(item.dataset.shortcutIndex);
                    delete fabShortcutConfig[shortcutIndex];
                    saveFabShortcutConfig();
                    renderFabShortcuts();
                    fabContainer.classList.remove('open');
                    showCustomAlert('Lối tắt đã được xóa');
                });
            });

            function showShortcutMenu(e, index) {
                fabShortcutMenu.innerHTML = '';
                Object.entries(SHORTCUT_ACTIONS).forEach(([key, value]) => {
                    const button = document.createElement('button');
                    button.innerHTML = `<i class="fas ${value.icon} fa-fw"></i> ${value.title}`;
                    button.onclick = () => {
                        fabShortcutConfig[index] = key;
                        saveFabShortcutConfig();
                        renderFabShortcuts();
                        fabShortcutMenu.classList.add('hidden');
                        fabContainer.classList.remove('open');
                    };
                    fabShortcutMenu.appendChild(button);
                });

                fabShortcutMenu.classList.remove('hidden');
                positionMenu(fabShortcutMenu, e);
            }
        }

