        async function handleReincarnation() {
            await showCustomAlert("Hành trình của bạn kết thúc tại đây... nhưng những sợi dây của vận mệnh đã dẫn bạn đến một khởi đầu mới.");
            showLoading('Đang luân hồi...');

            const archive = await db.archives.get(currentArchiveName);
            if (!archive) { hideLoading(); return; }

            const lastAiLog = archive.data.logs.filter(log => log.type === 'ai').pop();
            const deathSceneText = lastAiLog ? getCleanTextFromLogContent(lastAiLog.content) : "Tan biến trong màn sương mù không rõ.";

            const firstLog = archive.data.logs[0];
            if (!firstLog || !firstLog.stateSnapshot) {
                hideLoading();
                await showCustomAlert("Lỗi: Không tìm thấy khoảnh khắc sáng thế, không thể luân hồi.");
                return;
            }

            try {
                const initialSnapshotObject = JSON.parse(firstLog.stateSnapshot);
                const initialTableState = initialSnapshotObject.currentState || initialSnapshotObject;

                const newDeathCount = (archive.data.state.deathCount || 0) + 1;
                archive.data.state.deathCount = newDeathCount;

                if(initialSnapshotObject.currentState) {
                    initialSnapshotObject.deathCount = newDeathCount;
                } else {
                     initialTableState.deathCount = newDeathCount;
                }

                const deathInfo = { count: newDeathCount, lastDeathScene: deathSceneText };

                const openingPrompt = buildOpeningPrompt(initialTableState, firstLog.customOpeningStyle || '', deathInfo);

                let openingMonologue = `
                    <div class="log-entry summary">
                        <h4>Vận Mệnh Lại Chuyển Động, Ký Ức Vang Vọng (Luân Hồi Lần Thứ ${newDeathCount})</h4>
                        Khi ý thức của bạn tụ lại từ cõi hư vô, một thế giới mới mở ra trước mắt. Mọi thứ đều quen thuộc đến lạ, lại mang theo một chút xa lạ.
                        <details>
                            <summary><strong>Tiếng Vọng Của Kiếp Trước</strong></summary>
                            <div style="background:rgba(255,0,0,0.1); border-left: 2px solid red; padding: 10px; margin-top: 5px; white-space: pre-wrap;">${deathSceneText}</div>
                        </details>
                    </div>`;

                firstLog.content = openingMonologue.trim();
                firstLog.stateSnapshot = JSON.stringify(initialSnapshotObject);
                firstLog.timestamp = new Date().toISOString();

                archive.data.logs = [firstLog];
                archive.data.state.currentState = initialTableState;
                await db.archives.put(archive);

                await loadState(archive.data.state, true);
                loadChatHistory(archive.data.logs);
                toggleExtremeModeUI(true);

                await sendMessage(openingPrompt, true, '[Lệnh Hệ Thống] Luân hồi chế độ Cực Hạn, tạo màn mở đầu mới', true);
            } catch (error) {
                await showCustomAlert(`Luân hồi thất bại: ${error.message}`);
            } finally {
                hideLoading();
            }
        }

