        function renderAchievementReqDetails(requirement = {}) {
            const type = document.getElementById('ca-editor-req-type').value;
            const container = document.getElementById('ca-editor-req-details');
            container.innerHTML = '';

            switch(type) {
                case 'playerData':
                    const mainCategorySelect = document.createElement('select');
                    mainCategorySelect.innerHTML = `
                        <option value="primary">Dữ Liệu Cốt Lõi</option>
                        <option value="detailedAttributes">Thuộc Tính Chi Tiết</option>
                    `;

                    const subCategorySelect = document.createElement('select');

                    const updateSubCategory = () => {
                        const mainCat = mainCategorySelect.value;
                        subCategorySelect.innerHTML = '';
                        let options = [];
                        if (mainCat === 'primary') {
                            options = ['level', 'money', 'deathCount'];
                        } else if (mainCat === 'detailedAttributes') {
                            options = Object.keys(CREATION_CONFIG.ATTRIBUTES);
                        }
                        options.forEach(opt => {
                            const optionEl = document.createElement('option');
                            optionEl.value = opt;
                            optionEl.textContent = opt;
                            subCategorySelect.appendChild(optionEl);
                        });
                        if (requirement.key) {
                            const parts = requirement.key.split('.');
                            if (mainCat === 'detailedAttributes' && parts.length > 1) {
                                subCategorySelect.value = parts[1];
                            } else if (mainCat === 'primary') {
                                subCategorySelect.value = parts[0];
                            }
                        }
                    };

                    mainCategorySelect.addEventListener('change', updateSubCategory);

                    if (requirement.key && requirement.key.includes('.')) {
                        mainCategorySelect.value = 'detailedAttributes';
                    } else {
                        mainCategorySelect.value = 'primary';
                    }

                    updateSubCategory();

                    const opSelect = document.createElement('select');
                    opSelect.innerHTML = `<option value=">=">>=</option><option value="<="><=</option><option value="==">==</option>`;
                    if (requirement.operator) opSelect.value = requirement.operator;

                    const valueInput = document.createElement('input');
                    valueInput.type = 'number';
                    valueInput.placeholder = 'Giá trị mục tiêu';
                    valueInput.value = requirement.value || '';

                    container.append(mainCategorySelect, subCategorySelect, opSelect, valueInput);
                    break;
                case 'aiResponse':
                    const keywordInput = document.createElement('input');
                    keywordInput.type = 'text';
                    keywordInput.placeholder = 'Từ khóa';
                    keywordInput.value = requirement.keyword || '';
                    container.appendChild(keywordInput);
                    break;
            }
        }

