        }

        async function saveCustomAchievement() {
            const name = document.getElementById('ca-editor-name').value.trim();
            if (!name) { await showCustomAlert('Tên thành tựu không được để trống！'); return; }

            const reqType = document.getElementById('ca-editor-req-type').value;
            const reqDetails = document.getElementById('ca-editor-req-details').children;
            let requirement = { type: reqType };
            switch(reqType) {
                case 'playerData':
                    const mainCat = reqDetails[0].value;
                    const subCat = reqDetails[1].value;
                    requirement.key = mainCat === 'detailedAttributes' ? `detailedAttributes.${subCat}` : subCat;
                    requirement.operator = reqDetails[2].value;
                    requirement.value = reqDetails[3].value;
                    break;
                case 'aiResponse':
                    requirement.keyword = reqDetails[0].value;
                    break;
            }

            const rewardType = document.getElementById('ca-editor-reward-type').value;
            const rewardDetails = document.getElementById('ca-editor-reward-details').children;
            let reward = { type: rewardType };
            let rewardCommand = '';

            if (rewardType !== 'none') {
                try {
                    reward.description = rewardDetails[0].value;
                    switch(rewardType) {
                        case 'item':
                            reward = { ...reward, id: rewardDetails[1].value, name: rewardDetails[2].value, itemType: rewardDetails[3].value, desc: rewardDetails[4].value, effect: rewardDetails[5].value, quantity: rewardDetails[6].value };
                            rewardCommand = `y_insert(${JSON.stringify({"0":reward.id, "1":reward.name, "2":reward.itemType, "3":reward.desc, "4":reward.effect, "5":reward.quantity})})`;
                            break;
                        case 'character':
                            reward = { ...reward, id: rewardDetails[1].value, nameGender: rewardDetails[2].value, raceCareer: rewardDetails[3].value };
                            rewardCommand = `y_insert(${JSON.stringify({"0":reward.id, "1":reward.nameGender, "2":reward.raceCareer})})`;
                            break;
                        case 'pet':
                            reward = { ...reward, id: rewardDetails[1].value, nameGender: rewardDetails[2].value, raceType: rewardDetails[3].value };
                            rewardCommand = `y_insert(${JSON.stringify({"0":reward.id, "1":reward.nameGender, "2":reward.raceType})})`;
                            break;
                        case 'task':
                            reward = { ...reward, id: rewardDetails[1].value, title: rewardDetails[2].value, desc: rewardDetails[3].value, reward: rewardDetails[4].value, punishment: rewardDetails[5].value, difficulty: rewardDetails[6].value };
                            rewardCommand = `y_insert(${JSON.stringify({"0":reward.id, "1":reward.title, "2":reward.desc, "3":reward.reward, "4":reward.punishment, "5":reward.difficulty})})`;
                            break;
                        case 'world_event':
                            reward = { ...reward, time: rewardDetails[1].value, location: rewardDetails[2].value, desc: rewardDetails[3].value };
                            rewardCommand = `y_event("${reward.time}", "${reward.location}", "${reward.desc}")`;
                            break;
                    }
                } catch(e) {
                    await showCustomAlert('Định dạng thông tin phần thưởng không chính xác, vui lòng kiểm tra lại.');
                    return;
                }
            }

            const achievementData = {
                id: currentEditingAchievementId || crypto.randomUUID(),
                name: name,
                description: document.getElementById('ca-editor-desc').value.trim(),
                completionText: document.getElementById('ca-editor-completion-text').value.trim(),
                quality: document.getElementById('ca-editor-quality').value,
                requirement: requirement,
                reward: rewardType !== 'none' ? { ...reward, command: rewardCommand } : null
            };

            const archive = await db.archives.get(currentArchiveName);
            const customAchievements = archive.data.state.achievements.custom || [];
            if (currentEditingAchievementId) {
                const index = customAchievements.findIndex(a => a.id === currentEditingAchievementId);
