        async function checkAchievements(aiResponse, stateToCheck) {
            if (!currentArchiveName) return { changed: false, rewardCommands: [] };

            let achievementsState = stateToCheck.achievements || { completed: [], custom: [] };

            const allAchievements = [...DEFAULT_ACHIEVEMENTS, ...(achievementsState.custom || [])];
            const uncompleted = allAchievements.filter(ach => !achievementsState.completed.includes(ach.id));

            if (uncompleted.length === 0) return { changed: false, rewardCommands: [] };

            let changed = false;
            let commandsToExecute = [];

            const evaluateRewardCommand = (commandTemplate) => {
                if (!commandTemplate.includes('${')) return commandTemplate;
                try {
                    return commandTemplate.replace(/\${([^}]+)}/g, (match, expression) => {
                        const func = new Function('currentPlayerData', 'currentState', `return ${expression}`);
                        return func(currentPlayerData, currentState);
                    });
                } catch (e) {
                    console.error(`Error evaluating expression in achievement command: "${commandTemplate}"`, e);
                    return '';
                }
            };

            for (const ach of uncompleted) {
                let isCompleted = false;
                const req = ach.requirement;
                if (!req) continue;

                try {
                    switch(req.type) {
                        case 'playerData':
                            const getNestedProp = (obj, path) => path.split('.').reduce((o, k) => (o && o[k] !== undefined) ? o[k] : undefined, obj);
                            const playerValue = getNestedProp(currentPlayerData, req.key);
                            const targetValue = parseFloat(req.value);
                            if (playerValue !== undefined && !isNaN(playerValue) && !isNaN(targetValue)) {
                                if (req.operator === '>=') isCompleted = parseFloat(playerValue) >= targetValue;
                                else if (req.operator === '<=') isCompleted = parseFloat(playerValue) <= targetValue;
                                else isCompleted = parseFloat(playerValue) == targetValue;
                            }
                            break;
                        case 'tableCount':
                            const table = stateToCheck[req.table] || {};
                            const count = Object.keys(table).length;
                            if (req.operator === '>=') isCompleted = count >= req.value;
                            else if (req.operator === '<=') isCompleted = count <= req.value;
                            else isCompleted = count == req.value;
                            break;
                        case 'tableFilterCount':
                            const tableToFilter = Object.values(stateToCheck[req.table] || {});
                            const filteredCount = tableToFilter.filter(t => { try { return eval(req.filter); } catch(e) { return false; } }).length;
                            if (req.operator === '>=') isCompleted = filteredCount >= req.value;
                            else if (req.operator === '<=') isCompleted = filteredCount <= req.value;
                            else isCompleted = filteredCount == req.value;
                            break;
                        case 'aiResponse':
                            if (aiResponse) {
                                let visibleText = aiResponse;

                                visibleText = visibleText.replace(/<y_actions>[\s\S]*?<\/y_actions>/g, '');

                                visibleText = visibleText.replace(/<(?:think|thinking|Think|Thinking|tableThink)>[\s\S]*?<\/(?:think|thinking|Think|Thinking|tableThink)>/gi, '');

                                visibleText = visibleText.replace(/<branches>[\s\S]*?<\/branches>/g, '');

                                visibleText = processTextWithRules(visibleText, PLACEMENT_MAP.AI_OUTPUT, 'regular');

                                const tempDiv = document.createElement('div');
                                tempDiv.innerHTML = visibleText;
                                const pureText = tempDiv.textContent || tempDiv.innerText || '';

                                if (req.keyword.split('|').some(k => pureText.includes(k))) {
                                    isCompleted = true;
                                }
                            }
                            break;
                        case 'variable':
                            const varValue = (stateToCheck['var'] || {})[req.key] || 0;
                            const targetVarValue = parseFloat(req.value);
                            if (req.operator === '>=') isCompleted = parseFloat(varValue) >= targetVarValue;
                            else if (req.operator === '<=') isCompleted = parseFloat(varValue) <= targetVarValue;
                            else isCompleted = parseFloat(varValue) == targetVarValue;
                            break;
                    }
                } catch(e) { console.error(`Phán định thành tựu [${ach.name}] thất bại:`, e); }

                if (isCompleted) {
                    achievementsState.completed.push(ach.id);
                    changed = true;
                    showDanmaku(`Đạt được thành tựu: ${ach.completionText || ach.name}`, 'achievement');
                    if (ach.reward && ach.reward.command) {
                        const evaluatedCommand = evaluateRewardCommand(ach.reward.command);
                        commandsToExecute.push(evaluatedCommand);
                    }
                    if (ach.id === 'level_25') {
                        const currentPoints = await dbGet(`ATTRIB_POINTS_${currentArchiveName}`) || 0;
                        await dbSet(`ATTRIB_POINTS_${currentArchiveName}`, currentPoints + 1);
                    }
                }
            }

            return { changed, achievementsState, rewardCommands: commandsToExecute };
        }

        async function checkTaskCompletion() {
            const tasksInProgress = Object.values(currentState['6'] || {}).filter(t => t['9'] === 'in-progress');
            if (tasksInProgress.length === 0) return false;

            let tasksCompletedThisTurn = [];

            for (const task of tasksInProgress) {
                if (task['10'] === 'ai_judged' || !task['11']) continue;

                let conditionsMet = false;
                try {
                    const requirements = JSON.parse(task['11']);
                    const reqArray = Array.isArray(requirements) ? requirements : [requirements];

                    const checkCondition = (req) => {
                        switch(req.type) {
                            case 'playerData':
                                const getNestedProp = (obj, path) => path.split('.').reduce((o, k) => (o && o[k] !== undefined) ? o[k] : undefined, obj);
                                const playerValue = getNestedProp(currentPlayerData, req.key);
                                const targetValue = parseFloat(req.value);
                                if (playerValue !== undefined && !isNaN(playerValue) && !isNaN(targetValue)) {
                                    if (req.operator === '>=') return parseFloat(playerValue) >= targetValue;
                                    if (req.operator === '<=') return parseFloat(playerValue) <= targetValue;
                                    return parseFloat(playerValue) == targetValue;
                                }
                                return false;
                            case 'tableCount':
                                const table = currentState[req.table] || {};
                                const count = Object.keys(table).length;
                                if (req.operator === '>=') return count >= req.value;
                                if (req.operator === '<=') return count <= req.value;
                                return count == req.value;
                            case 'tableFilterCount':
                                const tableToFilter = Object.values(currentState[req.table] || {});
                                const filteredCount = tableToFilter.filter(t => eval(req.filter)).length;
                                if (req.operator === '>=') return filteredCount >= req.value;
                                if (req.operator === '<=') return filteredCount <= req.value;
                                return filteredCount == req.value;
                            default: return false;
                        }
                    };
                    conditionsMet = reqArray.every(checkCondition);
                } catch (e) { continue; }

                if (conditionsMet) {
                    currentState['6'][task['0']]['9'] = 'completed';
                    tasksCompletedThisTurn.push(task);
                }
            }

            if (tasksCompletedThisTurn.length > 0) {
                for (const task of tasksCompletedThisTurn) {
                    showDanmaku(`Hoàn thành nhiệm vụ: ${task['1']}`, 'achievement');
                    addMessageToLog({ content: `[Hệ Thống] Mục tiêu nhiệm vụ đã đạt được: ${task['1']}，có thể đi nộp！` }, 'system');
                }
                await saveCurrentState();
                syncStateFromTables();
                return true;
            }
            return false;
        }

