        function calculateAlchemySuccessRate() {
            const baseRate = 20;
            let details = [`Tỷ Lệ Thành Công Cơ Bản: ${baseRate}%`];

            const materials = alchemyState.materials.filter(m => m);
            if(materials.length === 0) return { baseRate: 20, attrBonus: 0, synergyBonus: 0, volatility: 0, materialCountPenalty: 0, details: ["Không có nguyên liệu"] };

            const attrBonus = Math.floor((currentPlayerData.detailedAttributes['Trí Lực'] - 10) / 2) + Math.floor((currentPlayerData.detailedAttributes['May Mắn'] - 10) / 4);
            if (attrBonus !== 0) {
                details.push(`Bonus Thuộc Tính Người Chơi: +${attrBonus}%`);
            }

            let materialCountPenalty = 0;
            if (materials.length === 4) {
                materialCountPenalty = 10;
                details.push(`Phạt Số Lượng Nguyên Liệu: -${materialCountPenalty}% (4/5)`);
            } else if (materials.length === 3) {
                materialCountPenalty = 20;
                details.push(`Phạt Số Lượng Nguyên Liệu: -${materialCountPenalty}% (3/5)`);
            }

            const typeCounts = materials.reduce((acc, material) => {
                const itemData = inventoryItems.find(i => i.id === material.id);
                if (itemData) {
                    const type = itemData.type || 'Tạp Vật';
                    acc[type] = (acc[type] || 0) + 1;
                }
                return acc;
            }, {});

            let synergyBonus = 0;
            for (const type in typeCounts) {
                if (typeCounts[type] >= 2) {
                    const pairs = Math.floor(typeCounts[type] / 2);
                    synergyBonus += pairs * 5;
                }
            }

            let synergyDetail = `Bonus Hợp Lực Nguyên Liệu: +${synergyBonus}%`;
            if (Object.keys(typeCounts).length === 1 && typeCounts[Object.keys(typeCounts)[0]] === 5) {
                synergyBonus += 10;
                synergyDetail = `Hợp Lực Hoàn Hảo (Năm loại giống nhau): +${synergyBonus}%`;
            }

            if (synergyBonus > 0) {
                details.push(synergyDetail);
            }

            const totalValue = materials.reduce((sum, material) => {
                const itemData = inventoryItems.find(i => i.id === material.id);
                return sum + (itemData?.value || 0);
            }, 0);

            let volatility = 0;
            const volatilityThreshold = 800;
            if (totalValue > volatilityThreshold) {
                const ratio = totalValue / volatilityThreshold;
                const rawPenalty = 80 * (1 - (1 / (Math.pow(ratio, 0.7) + 0.2)));
                volatility = Math.floor(Math.min(80, rawPenalty));

                details.push(`Phạt Biến Động Giá Trị Cao: -${volatility}%`);
            }

            return { baseRate, attrBonus, synergyBonus, volatility, materialCountPenalty, details };
        }

